/* characters q23 (68 mục) — R2.6 bồi tiểu sử Cổ Đạo */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q23"]=window.__LIBQ["tien-nghich"]["q23"]||{};window.__LIBQ["tien-nghich"]["q23"]["characters"]={"updatedAt":"2026-07-17","count":68,"chars":[{"id":"vuong-lam","name":"Vương Lâm","tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1956","tieuDe":"Thăm Chu Như chuyển thế, giải phóng người điên","text":"Lơ lửng trên bầu trời Sơn Nhạc Châu quan sát Chu Như chuyển thế sống cùng gia đình thợ săn, nhận ra Tiểu Bạch cũng chuyển thế thành chó lớn. Nghe Chu Như nói không muốn làm tiên nhân, ánh mắt phức tạp rồi rời đi. Đêm đó vào mộng Tiểu Bạch cho nó ăn đan dược, giao phó rằng nếu Chu Như muốn truy tìm giấc mộng thì Tiểu Bạch có thể mở ký ức cho nàng. Sau đó tới Tổ Thành Tiên Tộc, xuống Địa Cung, một phất tay phá hủy toàn bộ phong ấn cấm chế quanh ngọn núi phong ấn người điên. Dùng thần thức đánh thức người điên, sau nửa canh giờ biết người điên chọn ở lại, tôn trọng quyết định rồi rời đi.","anchor":"Ngươi nếu thật sự đã quyết định như vậy thì ta sẽ tôn trọng"},{"mucCt":"ky","text":"Rời người điên sau khi thức tỉnh đối phương, tôn trọng lựa chọn của bạn, dự đoán ba trăm năm sau mới gặp lại. Mê mang về Thái Cổ Thần Cảnh, Thiên Vận Tử, việc làm Uyển Nhi sống lại. Nhớ tới Chu Như — người đã chọn không thức tỉnh ký ức — quyết định không lấy ý chí bản thân áp đặt lên cố nhân luân hồi. Bay tới Thiên Lạp châu, đứng trên trời cao quan sát lão tướng Ti Nam đối đầu Nam Vương. Nhận ra Ti Nam chính là Tư Đồ Nam luân hồi — kiếp này không trở thành vương gia mà thành đại soái nắm năm mươi vạn quân. Mỉm cười vui vẻ, chưa quyết định có thức tỉnh Tư Đồ Nam hay không.","anchor":"Không trở thành vương gia mà lại trở thành đại soái... Không biết sau khi hắn mở ký ức kiếp trước ra sẽ nghĩ thế nào...","bridge":true,"khoang":"@c1957"},{"chuong":"@c1958","importance":"normal","mucCt":"ky","tieuDe":"Gặp lại Tư Đồ Nam chuyển thế","text":"Đêm khuya đột nhập soái trướng quân doanh năm mươi vạn quân Võ Hiên quốc, gặp lại cố nhân — lão tướng đại soái chính là Tư Đồ Nam chuyển thế. Suốt đêm uống rượu kể hết kinh lịch Tiên Cương: Thiên Ngưu Châu, Lục Ma Châu, Tổ thành, cổ tộc, tìm được tàn hồn Lý Mộ Uyển mà rơi nước mắt, giết Đạo cổ Hoàng tôn trả ẩn tình sư tôn. Khổ sở thú nhận không tìm được Lý Thiến Mai dù đã tìm rất lâu. Tiết lộ Lý Thiến Mai, Tư Đồ Nam, Thanh Thủy đều chuyển thế lên Tiên Cương đại lục, hắn để lại ấn ký trên người họ làm phương thức duy nhất tìm kiếm. Mở ký ức kiếp trước cho lão tướng theo yêu cầu. Hẹn Tư Đồ Nam khi nào làm xong Nam Vương thì tìm hắn, hai người lại say một trận, rồi hóa cầu vồng biến mất trong thiên địa.","anchor":"Đây là cảm giác không nói lên lời khi cố nhân gặp lại"},{"mucCt":"ky","text":"Đứng trên bầu trời suy ngẫm bản chất luân hồi, nhớ lại Chu Như không nỡ mất cha mẹ kiếp này, Tư Đồ Nam không muốn phụ quán binh, nhận ra luân hồi như tấm gương có chính mình bên trong, lĩnh ngộ dần hướng cảnh giới viên mãn. Tìm tới động phủ hoang vắng bắc châu tiên tộc gặp Đồng tử đầu to, điểm mi tâm giải khai ký ức kiếp trước, dùng tín thuật ngưng tụ lực lượng thiên địa thành tiểu kiếm cắm vào vách và đan dược bỏ vào hồ lô để lại. Dùng tinh quang điểm mi tâm Hồng Sam Tử khôi phục trí nhớ kiếp trước. Tìm đến Nam Ni châu gặp Thân Báo mấy canh giờ rồi rời đi. Đã gặp hầu hết cố nhân trong động phủ giới, đều lưu lại vật bảo vệ tính mạng và đồng Nguyên với động phủ giới, thuộc Thất Đạo Tông.","anchor":"Đám cố nhân trong động phủ giới trong Thời gian này Vương Lâm hầu như đã gặp hết","bridge":true,"khoang":"@c1959"},{"mucCt":"ky","text":"Gặp Thanh Hồng dưới mưa, nghe nàng nhắc lại câu nói của Mặc Trí từ ký ức kiếp trước của kiếp trước khiến tâm thần chấn động mãnh liệt, buông dù rơi dưới mưa. Ngửa mặt cười ha hả, hai hàng nước mắt chảy, tuyên bố tuyệt đối không chọn cách quên dù đang ở trong luân hồi. Nhớ lại lời thân ảnh gào thét ở tổ miếu hoàng thành Thủy Cổ, thì thào lặp lại lời tuyên chiến với thiên địa khiến toàn bộ Đại Lục Tiên Cương nổi cuồng phong. Sau đó quan sát Thanh Lâm đã luân hồi thành phàm nhân thợ rèn ở Lâm Hóa Châu, ngưỡng mộ sự hạnh phúc giản dị của hắn, rồi rời đi khẳng định lựa chọn của mình cũng chính xác.","anchor":"Nhưng cho dù thật sự ta đang ở trong luân hồi này, thì ta cùng sẽ không chọn cách quên đi, tuyệt đối không, vĩnh viễn không!","bridge":true,"khoang":"@c1960"},{"chuong":"@c1961","importance":"normal","mucCt":"ky","tieuDe":"Từ biệt cố nhân, bước vào động phủ giới","text":"Quan sát Chu Dật và Thanh Sương từ xa, thấy Chu Dật hạnh phúc viên mãn, uống bầu rượu từ chỗ Tư Đồ Nam mừng cho họ. Tới Tổ thành nhìn Hải Tử từ xa rồi rời đi. Trở lại Thiên Ngưu Châu, dùng hai chỉ phá phong ấn tiên tổ trên hồn Thiên Ngưu, giải phóng linh hồn nó ngưng hóa Nguyên thần bay đi. Gặp lại Thanh Thủy trước đại môn Thất Đạo Tông, ôm nhau mừng rỡ, cùng uống rượu kể chuyện. Khi nhắc Hồng Điệp, Thanh Thủy run lên cười khổ thề tìm cách cứu Hàm Yên. Sau khi Thanh Thủy rời đi, đẩy đại môn động phủ giới bước vào, cường quang lóe lên, biến mất. Trong tất cả cố nhân chỉ có Thập Tam muốn đi theo.","anchor":"Vương Lâm đẩy đại môn của động phủ giới, ngay khi đại môn mở ra. một đạo cường quang lóe lên"},{"chuong":"@c1962","importance":"major","mucCt":"ky","tieuDe":"Trở về giới nội, phát hiện Tiên giới bị vây","text":"Từ cánh cửa ánh sáng bước ra tại La Thiên trong tinh không giới nội, nhận ra đã về nhà. Thần thức tản ra bốn phương, phát hiện Tiên giới đang bị Xích Hồn giáo vây khốn, trận pháp cấm chế bị huyết quang ăn mòn. Nụ cười biến mất, sát khí ngập trời bộc phát hoàn toàn — lần đầu tiên kể từ khi trở thành cường giả đệ nhất Tiên Cương đại lục.","anchor":"Đây là lần đâu tiên sau khi hắn trở thành cường giả đệ nhất của Tiên Cương đại lục bộc phát hoàn toàn sát khí!"},{"chuong":"@c1963","importance":"major","mucCt":"ky","tieuDe":"Trở về Tiên giới, tái ngộ Mộc Băng Mi, ước định Mộng Đạo","text":"Bước một bước từ La Thiên Tinh Vực vào bên trong Tiên giới mà không tu sĩ nào phát hiện, đánh giá Xích Hồn Tử dù đỉnh phong cũng chỉ như con kiến. Triệu hồi Hứa Lập Quốc, Lưu Kim Bưu, Thập Tam ra tại Tiên giới, bảo họ tùy ý. Tái ngộ Mộc Băng Mi trên ngọn núi, gọi nàng bằng tên thật Liễu Mi. Tuyên bố đã tìm được phương pháp làm Uyển Nhi sống lại, đề nghị thi triển Mộng Đạo thuật để mình cùng Mộc Băng Mi và Vương Bình vượt qua một đời luân hồi trăm năm trong mộng, chấm dứt nghiệt duyên. Gật đầu nhận làm trượng phu, lần đầu tiên hai người chính thức ôm nhau. Sau một ngày, mang Mộc Băng Mi rời ngọn núi đi về phía xa.","anchor":"Sống với ta một đời Mộng Đạo nhập phàm sống trăm năm luân hồi xong liền chấm thức hết thảy thôi"},{"chuong":"@c1966","importance":"normal","mucCt":"ky","tieuDe":"Diệt Xích Hồn Tử, để lại truyền thừa Tiên giới, hành trình một năm về quê","text":"Triển khai Đại Thiên Tôn Chi Dương (ba màu trắng-đen-vàng kim ngưng tụ thành mặt trời khổng lồ, hiện khuôn mặt Tiên Hoàng bên trong), uy áp nửa bước Đạp Thiên Cảnh hủy diệt hoàn toàn Xích Hồn Tử — thân thể tan nát, nguyên thần diệt vong, tâm thần bị phá hủy từ trong ra ngoài. Bố trí trận pháp Tiên giới cường hãn (trừ Cổ Tổ và Tiên Tổ sống lại, Cổ Đạo cũng không phá nổi), để lại đạo thống, thần thông, đan dược lớn như núi và cảm ngộ hư bổn nguyên cho Tiên giới. Mang Mộc Băng Mi, Thập Tam, Hứa Lập Quốc rời Tiên giới. Về Chu Tước Tinh ngồi trước pho tượng của mình một ngày. Vào Yêu Linh Chỉ Địa phục hồi động phủ tiên đế Thanh Lâm, tìm bức tranh phong ấn trong vực sâu, đưa nữ tử thần bí ra giải phong ấn rồi đưa nàng chìm vào luân hồi. Đi khắp tứ đại tinh vực giới nội rồi ra giới ngoại — đến vùng đất Điên Lạc gặp lão Chu Tước và cố nhân, giải phong ấn vùng đất này, mang đi mũi kim la bàn (vật trọng yếu nhất). Gặp lại Tán Linh thượng nhân cùng bằng hữu. Thăm Thác Sâm đang hóa thân trẻ con ngủ say trong trung tâm tinh cầu, để lại thần niệm. Xác nhận Thiên Vận Tử và Thất Thải đã biến mất dấu vết. Sau một năm trở lại Chu Tước Tinh — quê hương.","anchor":"Sau một năm. hắn trở lại Chu Tước Tinh, về tới quê hương của hắn."},{"chuong":"@c1967","importance":"major","mucCt":"ky","tieuDe":"Hoàn thành một đời luân hồi phàm nhân cùng Liễu Mi","text":"Trong mộng cảnh luân hồi, Vương Lâm sống trọn một kiếp phàm nhân ở sơn thôn Triệu Quốc. Hắn sinh ra là người câm điếc, con nhà thợ mộc, thành thân với Liễu Mi — bạn thanh mai trúc mã. Hắn chọn nghề mộc tổ truyền, khắc bốn bức tượng gỗ cho thê tử qua bốn giai đoạn cuộc đời. Hai người sinh con trai Vương Bình, nuôi con trưởng thành đỗ đạt, rồi trở về sơn thôn sống tuổi già. Cả đời câm lặng, tới phút Liễu Mi lâm chung hắn mới nói lời đầu tiên từ sau thành thân. Hai vợ chồng mỉm cười ra đi cùng nhau. Tỉnh lại trong động phủ do Thập Tam thủ hộ, bên cạnh Mộc Băng Mi, giữa hai người có hạt châu u quang. Hắn bảo Mộc Băng Mi nhắm mắt rồi mở ra, nói tất cả sẽ bắt đầu lại từ đầu.","anchor":"Kết thúc rồi, nhắm mắt lại, khi lại mở ra, tất cả sẽ bắt đầu lại từ đầu"},{"mucCt":"ky","text":"Rời động phủ giới, dùng thần thức gửi ngọc giản cho Tây Tử Phượng ở La Thiên Tinh Vực và cho Thác Sâm đang ngủ say ở giới ngoại tinh hải. Gửi viên đan dược đỏ sẫm cho lão già bức tượng đá (đệ tử Thất Thải Tiên Tôn) giúp áp chế sức mạnh hóa thạch. Bố trí lực lượng vô hình bảo hộ toàn bộ động phủ giới. Xuất hiện tại Thất Đạo Tông đã sụp đổ trên Thiên Ngưu Châu sau ba trăm năm, vung tay áo biến nơi đổ nát thành tông môn rộng lớn trang nghiêm, tuyên bố đây là nhà cho người động phủ giới. Phát gần hai mươi đạo hào quang triệu hồi người chuyển thế (Thanh Thủy, Hồng Sam Tử, Thanh Sương, Chu Như, Hồng Điệp, Chu Dật…). Bố trí đại trận bảo hộ bên ngoài Thất Đạo Tông sánh ngang tiên giới đại trận. Nhớ về người điên đã thành tiên hoàng, Kế Đô đã thành Thủy Cổ hoàng tôn, Lý Thiến Mai đã khôi phục ký ức nhưng không muốn gặp mình. Giữ lời hứa với Cổ Đạo, xuyên bức tường nước tới khu vực cổ tộc, khoanh chân ngồi chờ ba tháng để Thái Cổ Thần Cảnh mở ra.","anchor":"Nơi này sẽ là nhà của tất cả những người từ động phủ giới đi ra","bridge":true,"khoang":"@c1969"},{"mucCt":"ky","text":"Khoanh chân ngồi bên cơn lốc nước biển chờ Thái Cổ Thần Cảnh mở, suy tư về kế hoạch điên cuồng từ Thủy Cổ Tổ Miếu. Ba Đại Thiên Tôn Cổ tộc (Tống Thiên, Huyền La, Cực Cổ Đại Thiên Tôn) tới gặp, Tống Thiên và Cực Cổ cung kính gọi Vương tôn. Khi Huyền La muốn vái chào, Vương Lâm chủ động đứng dậy vái trước gọi sư tôn, khiến Tống Thiên và Cực Cổ chấn động vì chưa từng thấy đệ tử thành cường giả vẫn giữ tình sư đồ. Ba Đại Thiên Tôn tiên tộc (Cửu Đế, Võ Phong, Đạo Nhất) cũng tới cung kính gọi Vương tôn. Nói chuyện thân mật với Võ Phong sau mấy trăm năm không gặp. Cảm nhận được dị biến nghiêm trọng của Thái Cổ Thần Cảnh, tiếng ầm vang tăng vọt, lực lượng bên trong gầm thét muốn lao ra, thần sắc sáu Đại Thiên Tôn đồng thời biến đổi.","anchor":"Vương Lâm tham kiến sư tôn.","bridge":true,"khoang":"@c1970"},{"chuong":"@c1972","importance":"major","mucCt":"ky","tieuDe":"Trao ngọc giản cho Huyền La, bước vào Thái Cổ Thần Cảnh","text":"Trước khi Huyền La rời đi, Vương Lâm trao ngọc giản cho sư tôn để bảo vệ việc chuyển thế, hẹn nếu bình an trở ra sẽ tự mình bảo vệ. Đối thoại với Cổ Đạo, nói mục đích vào Thái Cổ Thần Cảnh là vì một đáp án. Sau khi đại môn mở ra đóng băng toàn bộ Tiên Cương đại lục, Vương Lâm bước vào Thái Cổ Thần Cảnh sau Cổ Đạo.","anchor":"Vì một đáp án!"},{"chuong":"@c1973","importance":"major","mucCt":"ky","tieuDe":"Tiến vào La Bàn Định Giới — kiếp trước Đạp Thiên","text":"Bước vào Thái Cổ Thần Cảnh, bay lên không trung phát hiện mặt đất hình la bàn khổng lồ thiếu một nửa. Tái ngộ Thiên Vận Tử trên đỉnh núi tuyết bảy màu, bị hắn tiết lộ kiếp trước là tu sĩ Cảnh giới Đạp Thiên — người mạnh nhất thiên địa, từng cướp La Bàn Định Giới để cứu thê tử Lý Mộ Uyển nhưng thất bại, sau đó tự sáng tạo Mộng Đạo Thuật tản chân ngã trọng hóa luân hồi. Nhìn cảnh kiếp trước trong vòng xoáy đen, ký ức dần hồi phục. Ý thức hoàn toàn bình tĩnh không bị vặn vẹo — khác hẳn mọi lần trước, khiến Thiên Vận Tử chấn động. Nói câu phủ nhận danh tính người bảo vệ của Thiên Vận Tử và chỉ ra còn thiếu một người.","anchor":"cho dù kiếp trước ngươi là cao thủ Đạp Thiên, nhưng ở trong La Bàn Định Giới này"},{"mucCt":"ky","text":"Vương Lâm đối diện Thiên Vận Tử, kể lại chuỗi nghi hoặc: lần thứ hai nhìn thấy thân ảnh ôm thi thể trên ngọn núi tuyết bảy màu trong tổ miếu Thủy cổ, tiếng nói lặp lại thiếu một trong Thiên Nghịch Châu, cảnh hư ảo Bạch Phàm phát điên trong động phủ giới, âm thanh vạn cổ không môn giống tiếng thiếu một. Hắn lấy ra đầu lâu Cát Cùng làm bằng chứng, trên đó lưu thần niệm của sát lục phân thân cùng ký hiệu ấn kỳ tỏa u quang và khí tức sát lục. Hắn tuyên bố Thiên Vận Tử chính là khí linh của La Bàn Định Giới, không phải người bảo vệ. Hắn tiết lộ kế hoạch: dùng Lưu Nguyệt thuật nghịch chuyển năm tháng đưa sát lục phân thân về vô số ngàn năm trước, cho phân thân ý thức tự chủ triển khai hồi mộng đạo riêng, tạo ra cái gọi là kiếp trước. Hắn khẳng định Tiên Cương đại lục không phải giấc mộng, mình sinh tại Chu Tước Tinh, không phải chuyển thế. Thần thức trên đầu lâu Cát Cùng cho biết phân thân trong quá khứ đã nghịch chuyển thiên địa mượn được la bàn, đặt trên Tiên Cương đại lục, nhiều lần tiến vào đều tiêu tán rất nhanh, lần cuối tiến vào Thái Cổ Thần Cảnh hoàn thành ý chí lưu lại: khiến la bàn phân ra phóng ra khí linh tức Thiên Vận Tử. Hắn luận luân hồi là vòng tròn vốn tồn tại, hiểu thấu thì tùy ý nắm giữ, không hiểu thì là kiếp trước chuyển thế. Hắn tuyên bố toàn cục là hắn bày mưu ngược lại Thiên Vận Tử.","anchor":"Ngươi ở đây bày mưu với ta, lại không biết vào thời điểm cuối cùng toàn là ta bày mưu với ngươi.","bridge":true,"khoang":"@c1974"},{"chuong":"@c1975","importance":"major","mucCt":"ky","tieuDe":"Diệt Thiên Vận Tử, hồi sinh Lý Mộ Uyển","text":"Vung tay diệt sương đen Thiên Vận Tử, bóp nát hạc đen hóa thân cuối cùng của hắn, xác nhận đã đạt Cảnh Giới Đạp Thiên. Thu bổn nguyên một giới (khí chín màu) từ tàn dư Thiên Vận Tử. Nhìn đạo khí xám không mang khí tức Thiên Vận Tử bay vào Đạp Thiên Kiều nhưng không bất ngờ. Lấy quan tài gỗ chứa Lý Mộ Uyển, đặt bổn nguyên một giới lên mi tâm nàng. Rơi nước mắt hồi tưởng hành trình tình cảm mấy ngàn năm. Cuối cùng Lý Mộ Uyển mở mắt tỉnh lại.","anchor":"Khi ta nắm được luân hồi. thì ta đã đạp thiên rồi."},{"chuong":"@c1976","importance":"major","mucCt":"ky","tieuDe":"Thu La Bàn Định Giới, dung hợp phân thân, kết cục","text":"Thu toàn bộ Thái Cổ Thần Cảnh thành La Bàn Định Giới rồi thu tiếp thành Thiên Nghịch châu. Mở dòng xoáy đưa Cổ Đạo trở về Tiên Cương đại lục. Bước vào đào viên đánh nốt ván cờ dang dở với Thiên Vận Tử áo xám, đặt Thiên Nghịch châu làm quân trắng cuối cùng, bàn cờ hiện khuôn mặt nửa đen nửa trắng — hai người bảo vệ. Được xác nhận là người thứ hai đạt Đạp Thiên Cảnh trong Nghịch Trần Giới. Quay về Tiên Cương đợi sát lục phân thân — phân thân xóa linh trí hóa hắc khí dung nhập trở lại thân, Vương Lâm ngưng tụ sát lục chân thân, hiểu hắn đã trải vô số luân hồi nên chọn hợp nhất. Quyết định cùng Lý Mộ Uyển tìm nơi sống bình thường, tuyên bố tu hành tại tâm, ôm nàng hóa cầu vồng bay về hoàng hôn.","anchor":"Tu hành tại tâm. Tìm được chân ngã rồi thì nơi nào cũng giống nhau."}],"nhanMach":[{"ten":"Thân Báo","tag":"dong-minh","quanHe":"Cố nhân chuyển thế trong động phủ giới, thuộc Thất Đạo Tông","ghiChu":"Vương Lâm tìm gặp ở Nam Ni châu @c1959"},{"ten":"Hồng Sam Tử","tag":"dong-minh","quanHe":"Cố nhân chuyển thế trong động phủ giới, thuộc Thất Đạo Tông","ghiChu":"Vương Lâm điểm mi tâm giải khai ký ức kiếp trước @c1959"},{"ten":"Thanh Hồng","tag":"dong-minh","quanHe":"Nghi là cố nhân chuyển thế trong động phủ giới","ghiChu":"Cuối chương tiếng gọi nhu hòa từ sau lưng nàng, gợi ý Vương Lâm tới @c1959"},{"ten":"Đạo Nhất","tag":"doi-thu","quanHe":"Đại Thiên Tôn Tiên Cương bị Vương Lâm khuất phục, cung kính gọi Vương Tôn","ghiChu":"@c1965"},{"ten":"La Minh","tag":"khac","quanHe":"Thị vệ thân tín của Tiên Hoàng, được Xích Hồn Tử nhắc tới khi cầu sống","ghiChu":"@c1966"},{"ten":"Thất Thải","tag":"khac","quanHe":"Nhân vật thần bí, bí mật cuối cùng của động phủ giới mà Vương Lâm chưa giải đáp","ghiChu":"@c1966"},{"ten":"Đông Mai","tag":"khac","quanHe":"Nữ tử có thể là Lý Thiến Mai chuyển thế, buồn bã khi nghe về Vương Lâm","ghiChu":"Tống Trí thầm nghĩ Đông Mai là Lý Thiến Mai chuyển thế"},{"ten":"Thiên Vận Tử áo xám","tag":"dong-minh","quanHe":"Cùng là người bảo vệ, đánh ván cờ tàn cuộc trong đào viên","ghiChu":"Người thứ nhất đạt Đạp Thiên Cảnh, Vương Lâm là người thứ hai"},{"ten":"Tư Đồ Nam","tag":"ban-be","quanHe":"Tri kỷ cố nhân, tìm được kiếp chuyển thế trên Tiên Cương","ghiChu":"Gặp lại tại soái trướng Võ Hiên quốc, mở ký ức kiếp trước cho hắn","nguon":"@c1958"},{"ten":"Tán Linh thượng nhân","tag":"ban-be","quanHe":"Bằng hữu cũ","ghiChu":"Gặp lại tại giới ngoại, cảm động."},{"ten":"Mặc Trí","tag":"ban-be","quanHe":"Cố giao, từng gặp ở miếu đêm mưa","ghiChu":"Năm thứ hai trăm tới sơn cốc thăm, khuyên Vương Lâm bỏ cuộc, uống rượu suốt đêm. Nhắn lời sư tôn hỏi về la bàn định giới."},{"ten":"Hồn Thiên Ngưu","tag":"an-nhan","quanHe":"Cố nhân, từng mang ơn áo giáp hồn biến thành","ghiChu":"Giải phong ấn tiên tổ trả ơn, hồn bay đi tự do @c1961"},{"ten":"Mộc Băng Mi","tag":"the-thiep","quanHe":"Nghiệt duyên, lần đầu chính thức ôm nhau, ước định cùng nhập Mộng Đạo luân hồi trăm năm","ghiChu":"@c1963"},{"ten":"Thác Sâm","tag":"ban-be","quanHe":"Cố nhân thân thiết","ghiChu":"Gặp lại Thác Sâm dạng trẻ con đang tu luyện thần thông bí ẩn tại giới ngoại, để lại thần niệm (@c1966)"},{"ten":"Tống Trí","tag":"khac","quanHe":"Tộc nhân từng được Vương Lâm tiễn về năm trăm năm trước","ghiChu":"Tống Trí qua đời tại Hắc Thạch Thành sau năm trăm năm."}],"tuViMoc":[{"chuong":"@c1964","canhGioi":"Nửa bước Đạp Thiên","text":"Được xác nhận đã bước nửa bước vào cảnh giới Đạp Thiên, có thể so sánh với Tiên Tổ và Cổ Tổ.","importance":"major"},{"chuong":"@c1966","canhGioi":"Nửa bước Đạp Thiên Cảnh","text":"Tu vi đạt nửa bước Đạp Thiên Cảnh khi triển khai Đại Thiên Tôn Chi Dương diệt Xích Hồn Tử, uy áp đủ đánh tan cả một tinh vực.","importance":"major"},{"chuong":"@c1973","canhGioi":"Đạp Thiên (kiếp trước)","text":"Thiên Vận Tử tiết lộ kiếp trước Vương Lâm là tu sĩ cảnh giới Đạp Thiên — người mạnh nhất trong thiên địa, đã cướp La Bàn Định Giới từ tay người bảo vệ.","importance":"major"},{"chuong":"@c1976","canhGioi":"Đạp Thiên Cảnh","text":"Được Thiên Vận Tử áo xám xác nhận là người thứ hai trong Nghịch Trần Giới đạt tới Đạp Thiên Cảnh, bước thứ tư đạp thiên là đỉnh phong Nghịch Trần Giới.","importance":"major"}],"tuiDo":{},"diem":[{"text":"Phàm nhân tư chất kém, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh, chính thức bước vào con đường tu tiên","chuong":"@c0023"},{"text":"Đoạt xá thân Mã Lương sau khi tự nổ thân thể xuyên Vực Ngoại, tái sinh từ tuyệt cảnh","chuong":"@c0103"},{"text":"Nhận truyền thừa Cổ Thần Đồ Ti, trọng tổ thân thể Cổ Thần, nền tảng cho toàn bộ con đường thể tu sau này","chuong":"@c0176"},{"text":"Dung hợp bổn tôn và phân thân thành một, đạt tam tinh Cổ Thần, xác lập hình thái chiến đấu hoàn chỉnh","chuong":"@c0365"},{"text":"Chính thức thành Đại Thiên Tôn, Đại Thiên Tôn Chi Dương ba màu thực chất hóa trọn vẹn, mười mặt trời hiện trên Tiên Cương","chuong":"@c1939"},{"text":"Diệt Thiên Vận Tử, hồi sinh Lý Mộ Uyển, thu La Bàn Định Giới, đạt cảnh giới Đạp Thiên — hoàn tất hành trình nghịch thiên","chuong":"@c1976"}]},"nguon":["@c1956","@c1957","@c1958","@c1959","@c1960","@c1961","@c1962","@c1963","@c1964","@c1965","@c1966","@c1967","@c1968","@c1969","@c1970","@c1971","@c1972","@c1973","@c1974","@c1975","@c1976"],"canhGioiCaoNhat":"Nửa bước Đạp Thiên Cảnh","trangThai":"song","cn":"王林","gioiTinh":"nam","vaiTro":"Nhân vật chính — phàm nhân nghịch thiên, Đại Thiên Tôn tam cổ cửu tinh đệ nhất cường giả Tiên Cương","tinhCach":"Kiên nghị bất khuất, nhiều lần từ tuyệt cảnh tán công vươn lên đột phá; Thâm trầm mưu trí, giỏi ẩn nhẫn bố cục và phản kích trong thế yếu; Quyết đoán tàn nhẫn với kẻ thù nhưng nặng tình với cố nhân; Không chịu khuất phục trước hoàng quyền và trật tự áp đặt","blurb":"Vương Lâm xuất thân là thiếu niên phàm nhân tư chất kém ở Thạch Thôn, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh, ý chí khổ tu và vô số lần sinh tử — từ đoạt xá thân Mã Lương, truyền thừa Cổ Thần Đồ Ti, dung hợp bổn tôn với phân thân, vượt mười bảy tầng Thiên Tôn Niết — mà từng bước vươn tới đỉnh cao tu đạo. Sau khi được sắc phong Dược Thiên Tôn, đạt Không Kiếp hậu kỳ với thân thể tam cổ cửu tinh và ngưng hình dáng ban đầu của Đại Thiên Tôn Chi Dương, hắn đối diện trực tiếp áp lực hoàng quyền Đạo Cổ mà vẫn không quỳ gối, vượt Tam Tổn Kiếp tại Tổ Miếu Thủy Cổ, chính thức thành Đại Thiên Tôn, dung "},{"id":"chu-nhu","name":"Chu Như","tabs":{"kinhLich":[{"importance":"major","mucCt":"ky","chuong":"@c1956","tieuDe":"Chuyển thế từ chối tu tiên","text":"Chuyển thế thành thiếu nữ hơn mười tuổi tại sơn thôn Sơn Nhạc Châu, sống giản dị cùng cha mẹ (cha là thợ săn). Kể với mẹ rằng đêm qua mơ thành tiên nhân nhưng tuyên bố không muốn làm tiên nhân vì cảm thấy cả đời làm tiên nhân không vui sướng, muốn ở cùng cha mẹ cả đời. Đêm đó mơ thấy đời trước tên Chu Như, có thúc thúc chí thân hỏi có muốn rời đi không, nàng chọn ở lại.","anchor":"Con không thèm làm tiên nhân. Con luôn cảm thấy hình như trong mộng cả đời mình làm tiên nhân không vui sướng"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Nguyên Anh Lý Mộ Uyển đầu thai vào bào thai sơn thôn Hạnh Hoa Thôn, chuyển sinh thành Chu Như với tư chất bách mạch đều thông","chuong":"@c0314"},{"text":"Hồn phách bị Lý Mộ Uyển chấn ra khỏi nhục thân, được Vương Lâm triệu hồi sống sót, từ đó tồn tại với thân phận độc lập","chuong":"@c0381"},{"text":"Ký ức phong ấn được giải phóng tại đỉnh Chu Tước Sơn khi mở túi trữ vật Vương Lâm lưu lại","chuong":"@c0663"},{"text":"Tái ngộ Vương Lâm tại Côn Hư cảnh sau thời gian dài xa cách, đau lòng nhìn tóc bạc trắng của hắn","chuong":"@c1053"},{"text":"Được Vương Lâm thu hồi vận mệnh trong mặt trời thứ chín, thoát khỏi sự chi phối của thiên mệnh","chuong":"@c1540"},{"text":"Chuyển thế đầu thai thành thiếu nữ hơn mười tuổi tại sơn thôn Sơn Nhạc Châu, từ chối tu tiên, sống giản dị cùng cha mẹ","chuong":"@c1956"}]},"nguon":["@c1956"],"vaiTro":"Chuyển sinh phàm nhân của Nguyên Anh Lý Mộ Uyển — nghĩa nữ được Vương Lâm bảo hộ suốt nhiều kiếp","tinhCach":"Quyến luyến sâu sắc, nhiều lần bất chấp tìm kiếm Vương Lâm và không nỡ rời xa; hồn nhiên bộc trực, hay hờn dỗi giận lẫy; dã tính phóng khoáng, gắn bó với hổ Tiểu Bạch như bạn đồng hành; chí tu luyện kiên định, lấy việc tìm lại thúc thúc làm mục đích","blurb":"Chu Như là thân xác phàm nhân do Nguyên Anh Lý Mộ Uyển chuyển sinh tại Hạnh Hoa Thôn, mang tư chất tuyệt hảo bách mạch đều thông, từ nhỏ được Vương Lâm âm thầm bảo hộ rồi nuôi dưỡng trong Tiên Ngọc Bảo Tháp. Sau khi hồn phách được tách khỏi Nguyên Anh Lý Mộ Uyển và ký ức bị xóa, nàng đoàn tụ phụ mẫu rồi tự mình tu luyện đến cảnh Anh Biến, suốt đời lấy việc tìm lại thúc thúc Vương Lâm làm tâm nguyện duy nhất. Trải qua nhiều lần tái ngộ và chia ly, Chu Như cuối cùng được thu hồi vận mệnh trong mặt trời thứ chín, ở bên Vương Lâm như cô con gái trước khi quyết định chuyển thế đầu thai, tái sinh th"},{"id":"tieu-bach","name":"Tiểu Bạch","tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1956","tieuDe":"Chuyển thế thành chó, được giao giữ ký ức Chu Như","text":"Chuyển thế thành con chó lớn màu đen hình dáng giống mãnh hổ, đã thành tinh có tu vi không tầm thường, sống cùng gia đình Chu Như tại sơn thôn. Nhận ra Vương Lâm trên bầu trời, lộ vẻ sợ hãi. Đêm đó mơ thấy mình là mãnh hổ, rồi Vương Lâm xuất hiện cho ăn đan dược, vỗ đầu rồi giao phó: nếu Chu Như muốn truy tìm giấc mộng thì nó có thể mở ký ức cho nàng.","anchor":"Sau này Chu Như muốn truy tìm giấc mộng của mình thì người có thể mở được ký ức của mình"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Bị Thiết Nham bắt, cúi đầu chấp nhận làm thú cưỡi cho Chu Như khi nàng mới mười tuổi","chuong":"@c0334"},{"text":"Có linh trí và độc thoại nội tâm, tự xưng hổ gia; tại Chu Tước hưởng nhiều hổ cái","chuong":"@c0567"},{"text":"Theo sát Chu Như bay tới chỗ Vương Lâm trong Côn Hư cảnh, vẫn kinh sợ hắn từ năm xưa","chuong":"@c1052"},{"text":"Bị Đạo Phi gọi mở đường khi xông vào hoàng cung","chuong":"@c1873"},{"text":"Chuyển thế thành con chó lớn màu đen hình dáng tựa mãnh hổ, đã thành tinh có tu vi, được giao giữ ký ức Chu Như","chuong":"@c1956"}]},"nguon":["@c1956","@c1965"],"vaiTro":"Thú cưỡi của Chu Như — lão hổ hắc văn đạo hạnh trăm năm","tinhCach":"kiêu ngạo, tự tôn (tự xưng hổ gia, chỉ chấp nhận cúi đầu trước kẻ mạnh); lười nhác; trung thành bất đắc dĩ nhưng bền bỉ","blurb":"Tiểu Bạch là lão hổ hắc văn tu vi Trúc Cơ kỳ, đạo hạnh hơn trăm năm, bị Thiết Nham bắt về làm thú cưỡi cho Chu Như từ thuở nàng mười tuổi. Dù bản tính kiêu ngạo và tự xưng hổ gia, nó vẫn theo sát Chu Như suốt hành trình — từ Chu Tước Sơn đến Côn Hư cảnh, kể cả khi đối diện Vương Lâm, kẻ khiến nó kinh sợ từ năm xưa. Về sau chuyển thế thành con chó lớn màu đen hình dáng tựa mãnh hổ, được giao giữ ký ức Chu Như."},{"id":"a-ngoc","name":"Người điên","aliases":["A Ngốc","Tiên Hoàng"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1956","tieuDe":"Tỉnh dậy, chọn ở lại làm Tiên Hoàng","text":"Nằm ngủ say trong ngọn núi tại Địa Cung dưới Tổ Thành, được Vương Lâm phá phong ấn và dùng thần thức đánh thức. Sau khi tỉnh, tự bạch mình là hậu duệ Tiên Tổ Liên Đạo Chân, từ chối rời đi cùng Vương Lâm, chọn gánh trách nhiệm bảo vệ truyền thừa Tiên Tộc. Mặc hoàng bào đội vương miện, thần sắc uy nghiêm không còn điên rồ. Hẹn nếu không chịu đựng được nữa sẽ đi tìm Vương Lâm.","anchor":"Ta đã mơ hồ cả đời. Điên rồ cả đời. Nhưng ta đúng là hậu duệ của Tiên Tổ Liên Đạo Chân đã chết"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Được Ngô Vũ xác nhận là thi khôi cũ của mình; mang nửa tinh khí Nguyên Anh trung kỳ tiềm ẩn","chuong":"@c0079"},{"text":"Thử sức với Vương Lâm: kéo phù vàng, dùng quyền pháp ẩn lực đạo cổ quái khiến Vương Lâm lùi ba thước; dẫn Vương Lâm đến chỗ Ngô Vũ","chuong":"@c0079"},{"text":"Cùng Vương Lâm vào truyền tống trận Thi Âm tông, linh tính dồi dào khiến tám đệ tử gác trận kinh ngạc","chuong":"@c0080"},{"text":"Bị Dạ Tự Tại nhận làm lô đỉnh (thi khôi giả đan); La Sát lên kế hoạch nâng lên Kết Đan kỳ","chuong":"@c0081"},{"text":"Tỉnh dậy sau phong ấn tại Địa Cung dưới Tổ Thành, được Vương Lâm đánh thức và chọn ở lại làm Tiên Hoàng","chuong":"@c1956"}]},"canhGioiCaoNhat":"Đại Thiên Tôn","trangThai":"song","nguon":["@c1956","@c1975"],"vaiTro":"Thi khôi cũ của Ngô Vũ — quái nhân da lam đồng hành Vương Lâm","tinhCach":"Trí tuệ như trẻ thơ, chỉ thốt từng chữ đơn lẻ; bản năng chiến đấu cực mạnh với quyền pháp cổ quái; nhe răng dọa người nhưng thân thiết nương tựa người quen","blurb":"Quái nhân da lam khắc đầy ký hiệu cổ quái, mang chín tấm phù vàng — mỗi tấm kéo xuống tăng gấp đôi thực lực và trị thương tức thì. Thực chất là thi khôi cũ của Ngô Vũ, người từng định đoạt xá nhưng thất bại vì lực lượng hủy diệt trong cơ thể hắn; Ngô Vũ để lại nửa tinh khí Nguyên Anh trung kỳ khiến hắn tiềm ẩn thực lực khổng lồ. Sau khi theo Vương Lâm vào Thi Âm tông, hắn bị Dạ Tự Tại nhận làm lô đỉnh và trở thành đối tượng trong kế hoạch nâng lên Kết Đan kỳ của La Sát; về sau nằm ngủ phong ấn trong ngọn núi tại Địa Cung dưới Tổ Thành cho đến khi được Vương Lâm đánh thức và chọn ở lại làm Tiên"},{"id":"tu-do-nam","name":"Tư Đồ Nam","aliases":["Ti Nam"],"trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Kiếp luân hồi trở thành lão tướng Ti Nam — đại soái biên cương Võ Hiên quốc tại Thiên Lạp châu, nắm gần năm mươi vạn đại quân, bách chiến thường thắng. Không phải hoàng thất nhưng không thể thiếu, bị đố kỵ nhưng oai phong vượt cả hoàng tộc. Kiên quyết không dùng quân sĩ nghênh đón Nam Vương xa hoa, tự mình đi đón với sát khí đầy người khiến thị vệ Nam Vương run rẩy, Nam Vương phải cười gượng không dám vào quân doanh. Vương Lâm từ trên trời xác nhận đây là thân phận luân hồi của Tư Đồ Nam.","anchor":"Lão tướng Ti Nam tới nghênh tiếp Nam Vương.","bridge":true,"khoang":"@c1957"},{"mucCt":"ky","text":"Kiếp luân hồi này là lão tướng đại soái Võ Hiên quốc, thống lĩnh năm mươi vạn quân. Vương Lâm đột nhập soái trướng, suốt đêm uống rượu kể chuyện cũ. Dần cảm nhận sự quen thuộc từ linh hồn, nhận ra mình chính là Tư Đồ Nam chuyển thế, khóc cười lẫn lộn. Giằng xé vì năm mươi vạn quân sĩ truyền đời đi theo mình. Uống hết ba bầu rượu, kiên định yêu cầu Vương Lâm mở ký ức kiếp trước. Tuyên bố chưa đi ngay — muốn hoàn thành tâm nguyện kiếp này: trở thành Nam Vương rồi mới đi tìm Vương Lâm. Sau khi Vương Lâm rời đi, lập tức hạ lệnh chỉnh binh, quyết bắt kẻ đang xưng Nam Vương và tự mình làm Nam Vương.","anchor":"Ta là Tư Đồ Nam?","bridge":true,"khoang":"@c1958"}],"nhanMach":[{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Tri kỷ kiếp trước, người mở ký ức kiếp trước cho hắn","ghiChu":"Vương Lâm đột nhập soái trướng gặp lại, kể hết kinh lịch, mở ký ức. Hẹn sau khi làm Nam Vương sẽ tìm Vương Lâm."}],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Tiết lộ thân phận cường giả lục cấp Chu Tước Quốc, bị truy sát thân hủy, tinh hoa Nguyên Anh ẩn vào Thiên Nghịch Châu theo sát Vương Lâm","chuong":"@c0047"},{"text":"Đoạt xá thành công thân đồng tử áo đỏ trong khối viêm băng, nuốt tứ tổ Tiên Di Tộc, bản lãnh đạt Vấn Đỉnh kỳ","chuong":"@c0411"},{"text":"Được Thanh Lâm trợ giúp phá Không Môn, chính thức trở thành tu sĩ bước thứ ba, tham chiến bảo vệ Chu Tước Tinh","chuong":"@c1520"},{"text":"Được xác nhận là phách thứ hai màu xanh của Thất Thải Tiên Tôn, phách ẩn chứa toàn bộ tu vi Không Kiếp","chuong":"@c1650"},{"text":"Được Vương Lâm gửi gắm trọng trách: nếu Vương Lâm chết, bố cáo thiên hạ sự thật và viết thành ngọc giản lưu truyền","chuong":"@c1588"},{"text":"Được Vương Lâm cứu thoát khỏi Đan Hải, chia tay huynh đệ trước biến cố lớn","chuong":"@c1752"}]},"nguon":["@c1957","@c1958"],"canhGioiCaoNhat":"Phàm nhân","vaiTro":"Huynh trưởng Vương Lâm — cường giả Chu Tước, phách thứ hai của Thất Thải Tiên Tôn","tinhCach":"Kiêu ngạo ngang tàng, hành sự bá đạo không kiêng nể; tàn nhẫn quyết đoán nhưng trọng nghĩa tình với huynh đệ; nóng nảy bốc đồng, dễ kích động vì người thân; phong lưu phóng khoáng, thích tự do không chịu ràng buộc","blurb":"Tư Đồ Nam vốn là cường giả lục cấp đệ nhất của Chu Tước Quốc, bị kẻ địch từ thất cấp tu chân quốc truy sát đến thân hủy, chỉ còn tinh hoa Nguyên Anh ẩn trong Thiên Nghịch Châu, từ đó theo sát Vương Lâm hàng trăm năm, vừa chỉ điểm tu luyện vừa nhiều lần xả thân bảo vệ. Sau khi đoạt xá thành công và phục hồi thực lực, ông trải qua Vấn Đỉnh, Tịnh Niết rồi được Thanh Lâm trợ giúp phá Không Môn bước vào bước thứ ba, cùng Vương Lâm chinh chiến tinh không trong cuộc đại chiến giới nội giới ngoại. Về sau được xác nhận chính là phách thứ hai màu xanh của Thất Thải Tiên Tôn, ẩn chứa toàn bộ tu vi Không "},{"id":"nam-vuong-vo-hien","name":"Nam Vương","gioiTinh":"nam","theLuc":[{"ten":"Võ Hiên quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Vương gia của Võ Hiên quốc, phàm nhân trung niên hưởng thụ xa hoa, tửu sắc quá độ. Phụng chỉ tới biên cương khao quân nhưng bản tính kiêu ngạo, hay nhắm vào đại soái Ti Nam.","vaiTro":"Vương gia Võ Hiên quốc, kẻ xa hoa đối lập với khí phách Ti Nam","tinhCach":["Kiêu ngạo, xa hoa; tửu sắc quá độ; hay bày trận thế nhằm vào đại soái nhưng sợ sát khí thật sự"],"tabs":{"diem":[{"text":"Phàm nhân hoàng tộc hưởng thụ cực xa hoa, xe ngựa mười trượng với thể thiếp thành đàn, đoàn xe kéo dài cả dặm","chuong":"@c1957"}],"kinhLich":[{"mucCt":"vua","text":"Phụng chỉ tới biên cương Võ Hiên quốc khao thưởng quân sĩ với đoàn xe xa hoa dâm mị. Trước sát khí của lão tướng Ti Nam, đổ mồ hôi lạnh, cười gượng, không dám tiến vào quân doanh.","anchor":"Bổn vương sẽ ở bên ngoài thôi, không cận tiến vào đâu.","bridge":true,"khoang":"@c1957"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Đồ Nam","tag":"doi-thu","quanHe":"Đại soái biên cương Ti Nam — đối tượng Nam Vương hay nhắm vào nhưng phải kiêng nể sát khí"}],"tuiDo":{}},"nguon":["@c1957"]},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","tabs":{"kinhLich":[{"chuong":"@c1964","importance":"normal","mucCt":"vua","tieuDe":"Được nhắc: cố ý tránh mặt Vương Lâm sau chuyển thế","text":"Sau chuyển thế, ấn ký biến mất, hẳn đã khôi phục ký ức nhưng cố ý không tản ra khí tức, không muốn cho Vương Lâm tìm thấy. Đang ở đâu đó trên Đại Lục Tiên Cương.","anchor":"Nhưng ta có một cảm giác là nàng đang ở một nơi nào đó trên Đại Lục Tiên Cương, nàng biết sự tồn tại của ta, biết là ta đang tìm kiếm"},{"chuong":"@c1973","importance":"normal","mucCt":"vua","tieuDe":"Cảnh kiếp trước hồi sinh thất bại hiện lên","text":"Trong vòng xoáy đen do Thiên Vận Tử triệu ra, hiện cảnh kiếp trước Vương Lâm ôm thi thể nàng gào thét thề phá thiên địa đắm vào luân hồi để cứu. Xác nhận nàng từng bị hồi sinh bất thành.","anchor":"sau khi hồi sinh Lý Mộ Uyển thất bại"},{"chuong":"@c1974","importance":"bridge","mucCt":"gon","text":"Được tiết lộ rằng toàn bộ kế hoạch nghịch chuyển năm tháng của Vương Lâm và la bàn mà phân thân sát lục mượn được trong quá khứ đều nhằm mục đích cứu nàng sống lại.","anchor":"thấy được phương pháp thức tỉnh Uyển Nhi đúng như ta yêu cầu năm đó!"},{"chuong":"@c1975","importance":"major","mucCt":"ky","tieuDe":"Được hồi sinh, mở mắt tỉnh lại","text":"Nằm trong quan tài gỗ, được Vương Lâm đặt bổn nguyên một giới lên mi tâm. Sau thời gian chờ đợi, run rẩy lông mi rồi mở mắt ra, giơ tay chạm mặt Vương Lâm. Trong mắt ẩn chứa ôn nhu giống mấy ngàn năm trước và sự thương tiếc.","anchor":"Toàn thân Vương Lâm chấn động, hắn cúi đầu xuống nhìn thấy Lý Mộ Uyển run"},{"chuong":"@c1976","importance":"major","mucCt":"ky","tieuDe":"Tỉnh dậy, cùng Vương Lâm rời đi sống bình thường","text":"Đã tỉnh dậy, đứng cùng Vương Lâm trên ngọn núi tuyết bảy màu. Nắm tay hắn suốt hành trình qua Đạp Thiên Kiều, đào viên, ván cờ với Thiên Vận Tử áo xám. Hỏi Vương Lâm về ý nghĩa ván cờ khi bay đi. Cùng hắn hóa cầu vồng rời khỏi Tiên Cương, bay về phía hoàng hôn.","anchor":"Lý Mộ Uyển cũng nắm tay Vương Lâm."}],"nhanMach":[],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Dùng Bách Thú Linh Lô và Ma Huyết đằng luyện thành công linh đan trong lúc động phủ bị mười tu sĩ Kết Đan kỳ công phá","chuong":"@c0127"},{"text":"Chia tay Vương Lâm sau bốn năm đồng hành tại Tu Ma Hải, để lại hơn 18.000 ngọc giản đan phương và bản mệnh tinh huyết kèm thần thức hộ thể","chuong":"@c0137"},{"text":"Ba lần Kết Anh thất bại, thọ nguyên cạn kiệt, thân xác hóa xương khô, kim đan nứt vỡ; nguyên anh đầu thai thành bé gái Chu Như qua bức tranh Sinh Tử Luân Hồi","chuong":"@c0313"},{"text":"Sau chín mươi năm trong thân Chu Như, thức tỉnh rồi tự đẩy nguyên anh ra, từ bỏ cơ hội tái sinh để bảo toàn sinh mệnh Chu Như","chuong":"@c0381"},{"text":"Tàn hồn được Vương Lâm tách khỏi thân Tống Trí suốt gần hai năm, hồn phách hoàn chỉnh trở lại","chuong":"@c1929"},{"text":"Được hồi sinh nhờ Vương Lâm nghịch chuyển năm tháng, mở mắt tỉnh lại và cùng hắn rời đi sống bình thường","chuong":"@c1975"}]},"nguon":["@c1958","@c1968","@c1973","@c1974","@c1975","@c1976","@c1964"],"trangThai":"song","gioiTinh":"nu","aliases":["Uyển Nhi"],"cn":"李慕婉","vaiTro":"Nhân vật nữ chính — thê tử Vương Lâm, tu sĩ tài hoa luyện đan và trận pháp","tinhCach":"Tài hoa xuất chúng về luyện đan và trận pháp, sáng tạo linh hoạt trong chiến đấu; nặng tình sâu sắc với Vương Lâm, kiên trinh suốt trăm năm ly biệt; kiên cường chịu đựng trước thọ nguyên cạn kiệt và ba lần Kết Anh thất bại; giàu lòng trắc ẩn, tự từ bỏ cơ hội tái sinh để bảo toàn sinh mệnh Chu Như","blurb":"Lý Mộ Uyển là tu sĩ Kết Đan hậu kỳ, nổi bật với thiên phú luyện đan và trận pháp, từng bị Song Tu Môn truy sát vì Thiên Ly đan rồi được Vương Lâm cứu giúp, cùng hắn trải qua bốn năm đồng hành tại Tu Ma Hải trước khi chia tay. Hơn trăm năm sau, ba lần Kết Anh thất bại khiến thọ nguyên cạn kiệt, thân xác hóa xương khô; nguyên anh nhờ bức tranh Sinh Tử Luân Hồi đầu thai thành bé gái Chu Như, nhưng nàng tự đẩy nguyên anh ra để bảo toàn sinh mệnh Chu Như, rồi được Vương Lâm gìn giữ nguyên anh suốt gần bảy trăm năm. Tàn hồn nàng sau đó được phát hiện dung nhập trong thân Tống Trí, trải qua gần hai n"},{"id":"ly-thien-mai","name":"Lý Thiến Mai","tabs":{"kinhLich":[{"chuong":"@c1964","importance":"normal","mucCt":"vua","tieuDe":"Cố ý ẩn mình, không muốn gặp Vương Lâm","text":"Vương Lâm tiết lộ: ấn ký của nàng đã biến mất, hẳn đã khôi phục ký ức nhưng cố ý không tản ra dù chỉ một tia khí tức, không muốn gặp. Vương Lâm cảm giác nàng đang ở đâu đó trên Đại Lục Tiên Cương.","anchor":"ta có một cảm giác là nàng đang ở một nơi nào đó trên Đại Lục Tiên Cương"},{"importance":"bridge","mucCt":"gon","chuong":"@c1969","tieuDe":"Vương Lâm nhớ về nàng","text":"Vương Lâm đoán nàng đã khôi phục ký ức như Thanh Thủy nhưng không muốn gặp mình, lặng lẽ chúc phúc cho hắn.","anchor":"Lặng lẽ chúc phúc cho ta sao"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Luận đạo cùng Vương Lâm tại Bồng Lai, đặt ba câu hỏi về thiên, đạo, ý — khởi đầu mối tri kỷ xuyên suốt","chuong":"@c1096"},{"text":"Bất chấp tông lệnh và cảnh cáo đào ngũ, rời chiến trường Yêu Tông sau trăm năm chém giết mãnh thú để tìm Vương Lâm","chuong":"@c1163"},{"text":"Bị sư tôn Phá Thiên Tông vây khốn, phá trận pháp rời tông, bị đoạn tuyệt sư đồ vĩnh viễn","chuong":"@c1200"},{"text":"Suốt mười năm hy sinh máu tươi, tinh huyết chăm sóc tượng đá Vương Lâm tại đại lục hoang dã đến kiệt quệ mất trí nhớ","chuong":"@c1214"},{"text":"Nguyện chuyển thế đầu thai chờ Vương Lâm trong luân hồi, là người cuối cùng rời đi với nụ cười","chuong":"@c1697"},{"text":"Sau khi đầu thai, cố ý ẩn mình không tản ấn ký, lặng lẽ chúc phúc Vương Lâm từ xa","chuong":"@c1969"}]},"nguon":["@c1958","@c1964","@c1969"],"gioiTinh":"nu","trangThai":"song","vaiTro":"Nữ tu sĩ Phá Thiên Tông — thiên chi kiêu nữ Vân Hải tinh vực, tri kỷ của Vương Lâm","tinhCach":"ham hỏi đạo, trọng bản tâm; nặng tình và giữ hẹn; kiên định trước sư mệnh, tông lệnh; sẵn sàng hy sinh vì người mình chọn","blurb":"Lý Thiến Mai, bí danh Lý Oánh Chi, là thiên chi kiêu nữ Vân Hải tinh vực xuất thân Phá Thiên Tông, năm tuổi nhập đạo, hơn 1200 năm tu luyện đạt Toái Niết hậu kỳ. Nàng kết giao với Vương Lâm qua luận đạo tại Bồng Lai, trải trăm năm chém giết mãnh thú tại chiến trường Yêu Tông rồi bất chấp tông lệnh vượt tinh vực tìm hắn, bị đoạn tuyệt sư đồ và hy sinh máu tươi, tinh huyết chăm sóc tượng đá Vương Lâm suốt mười năm đến kiệt quệ mất trí nhớ. Sau khi dần khôi phục ký ức và được Vương Lâm tiếp nhận, nàng quyết định chuyển thế đầu thai, nguyện chờ hắn trong luân hồi; tính đến chương gần nhất, Vương L"},{"id":"thanh-thuy","name":"Thanh Thủy","tabs":{"kinhLich":[{"chuong":"@c1961","importance":"major","mucCt":"ky","tieuDe":"Tự khôi phục ký ức, thề cứu Hàm Yên","text":"Ấn ký trên thân tự tiêu tan, khôi phục ký ức kiếp trước. Rời tông môn hiện tại tìm đến Thất Đạo Tông nhìn đại môn động phủ giới. Gặp lại Vương Lâm, hai huynh đệ ôm nhau mừng rỡ, cùng uống rượu kể chuyện. Khi nghe nhắc Hồng Điệp thì run lên cười khổ, tuyên bố chọn không quên, quyết tâm tìm cách làm Hàm Yên sống lại dù gian nan cả đời hay luân hồi liên tục. Rời đi khi ánh ban mai chiếu xuống, không quay lại động phủ giới.","anchor":"Nhưng lựa chọn của ta là không quên!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1969","tieuDe":"Nhận hào quang triệu hồi","text":"Đang hành tẩu trong sa mạc khu vực tiên tộc, nhận hào quang dung nhập vào thân thể, lộ nụ cười.","anchor":"Thân thể hắn chấn động, một lát sau hắn mở mắt ra. trên mặt lộ ra một nụ cười"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Thái tử Thanh Thủy Quốc, sau khi cố quốc bị diệt vong đã thức tỉnh Cực Cảnh, bảy ngày đẫm máu tàn sát kẻ thù rồi mang sát nghiệp cùng cực, tự phong ấn bản thân","chuong":"@c1462"},{"text":"Truyền thừa cho Vương Lâm hai tiên thuật đại tiên đế Hoán Vũ và Tát Đậu Thành Binh, công khai nhận Vương Lâm là sư đệ trước Lôi Tiên Điện","chuong":"@c0816"},{"text":"Dùng sát lục bổn nguyên ngưng tụ hắc kiếm phá Không Môn, đột phá Không Niết Sơ Kỳ — bước thứ ba tu hành","chuong":"@c1467"},{"text":"Hóa thân thành Vương Lâm bế quan trấn thủ đài chiến Vân Hải, bị Hư Thần Thiên Tôn trọng thương gần chết vì thay mặt sư đệ","chuong":"@c1516"},{"text":"Được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn; cùng con gái Hồng Điệp bước vào chuyển thế đầu thai, nhờ Vương Lâm chiếu cố nữ nhi","chuong":"@c1696"},{"text":"Sau chuyển thế, ấn ký tự tiêu tan, khôi phục ký ức kiếp trước, rời tông môn tìm đến Thất Đạo Tông và thề cứu thê tử Hàm Yên","chuong":"@c1961"}]},"nguon":["@c1958","@c1961","@c1969"],"trangThai":"song","cn":"青水","gioiTinh":"nam","vaiTro":"Phách thứ nhất Thất Thải Tiên Tôn — sư huynh đồng mạch Bạch Phàm của Vương Lâm, Tiên Quân mang sát nghiệp viễn cổ","tinhCach":"trọng nghĩa đồng môn, nhiều lần xả thân bảo hộ Vương Lâm không tính được mất; sát phạt quyết liệt, mang sát nghiệp cùng cực từ viễn cổ; thận trọng đa nghi, không dễ tin người nhưng giữ chữ tín; nặng tình thân, nguyện cùng con gái chuyển thế đầu thai","blurb":"Thanh Thủy vốn là thái tử Thanh Thủy Quốc trong thượng cổ tu chân giới; sau khi cố quốc bị diệt vong, trong tuyệt vọng bị truy sát đã thức tỉnh Cực Cảnh, quay về tàn sát kẻ thù rồi mang sát nghiệp cùng cực, tự phong ấn bản thân. Là sư huynh đồng mạch Bạch Phàm của Vương Lâm, ông nhiều lần hiện thân bảo hộ, truyền thừa tiên thuật Hoán Vũ và Tát Đậu Thành Binh, về sau dùng sát lục bổn nguyên phá Không Môn bước vào Không Niết Sơ Kỳ. Được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn; cuối cùng ông cùng con gái Hồng Điệp bước vào chuyển thế, tự khôi phục ký ức kiếp trước và thề cứu thê tử Hàm "},{"id":"dong-tu-dau-to","name":"Đồng tử đầu to","tabs":{"kinhLich":[{"importance":"major","mucCt":"vua","chuong":"@c1959","tieuDe":"Khôi phục ký ức kiếp trước nhờ Vương Lâm","text":"Chuyển thế thành tu sĩ đầu cực to thân gầy nhỏ, ẩn trong động phủ hoang vắng bắc châu tiên tộc, tưởng Vương Lâm là kẻ thù Mã Đào nên phun lục quang (con rết luyện trong nguyên thần) tấn công rồi bỏ chạy. Bị Vương Lâm điểm mi tâm giải khai ký ức kiếp trước, nhớ ra chủ nhân, rơi nước mắt khi thấy kiếm và đan dược Vương Lâm để lại.","anchor":"Hắn thấy được cây kiếm khiến hắn kinh hãi thấy hồ lô tràn ngập đan dược nồng đậm lực lượng thiên địa, nước mắt rơi xuống"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Dẫn quân La Thiên xâm phạm Chu Tước Tinh, bị Vương Lâm đánh bại rồi phong ấn nguyên thần thu phục","chuong":"@c0838"},{"text":"Mang quá khứ bị gia tộc đuổi đi trong đêm mưa, mẫu thân phiền chán đánh đập, tạo nên tính cách cô độc trầm mặc","chuong":"@c0856"},{"text":"Định tự bạo nguyên thần khi bị sáu phân thân Khuy Niết sơ kỳ của Vu Phi dồn ép đến tuyệt vọng","chuong":"@c0853"},{"text":"Nhục thân cũ sụp đổ tại Yêu Linh chi địa, được trợ giúp ngưng tụ thân thể mới tại Chu Tước Thánh Tông","chuong":"@c1016"},{"text":"Được Vương Lâm trả hồn huyết và giải phong ấn, hoàn toàn tự do nhưng vẫn chọn ở lại","chuong":"@c1621"},{"text":"Chuyển thế thành tu sĩ đầu cực to, được Vương Lâm tìm tới khôi phục ký ức kiếp trước","chuong":"@c1959"}]},"nguon":["@c1959"],"vaiTro":"Thiên Cương tiên La Thiên — thuộc hạ trung thành của Vương Lâm","tinhCach":"ngoài mặt cười ngây ngô nhưng nội tâm thận trọng, quan sát tinh tế; trung thành tuyệt đối với Vương Lâm, sẵn sàng tự bạo nguyên thần khi nguy cấp; cô độc trầm mặc do quá khứ bị gia tộc ruồng bỏ; am hiểu cấm chế và phá trận","blurb":"Đồng tử đầu to là tu sĩ Khuy Niết thuộc La Thiên Bắc Vực, một trong số ít Thiên Cương tiên có thể khắc tên lên Phong Tiên thạch. Từ kẻ dẫn quân xâm phạm Chu Tước Tinh, hắn bị Vương Lâm đánh bại và phong ấn nguyên thần thu phục, về sau nhiều lần hộ pháp, trợ chiến và theo hầu qua vô số tử địa. Dù nhục thân cũ sụp đổ rồi được tái tạo, dù được trả hồn huyết và giải phong ấn hoàn toàn tự do, hắn vẫn chọn ở lại bên Vương Lâm, và sau khi chuyển thế vẫn được Vương Lâm tìm tới khôi phục ký ức kiếp trước."},{"id":"hong-sam-tu","name":"Hồng Sam Tử","gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (chuyển thế thành đồng tử)","trangThai":"song","blurb":"Hồng Sam Tử, biệt hiệu Huyết Sam Đồng Tử, là cường giả Không Huyền Trung Kỳ trú tại tầng thứ nhất Vân Hải tinh vực, một trong những người được chủ nhân Phong Giới ủy thác ước định hợp nhất Tứ Đại Tiên Giới. Khi Phong Giới Đại Trận hiện hình và chiến tranh giới nội–giới ngoại bùng nổ, Hồng Sam Tử dẫn mấy vạn tu sĩ Vân Hải tiếp viện, một mình đối đầu nhiều cao thủ bước thứ ba, phá sát giới mấy vạn năm để chiến đấu, đóng vai trò then chốt trong nhiều trận quyết chiến bảo vệ giới nội. Sau đại chiến thứ hai bị phong ấn tại Thất Thải Giới, được Vương Lâm giải cứu, tiếp tục tham chiến trong các trận ","vaiTro":"Cường giả Vân Hải tinh vực — người được ủy thác ước định hợp nhất Tứ Đại Tiên Giới","tinhCach":"Dũng mãnh không sợ chết, sẵn sàng xả thân vì đại cục; quyết đoán trên chiến trường, không lùi dù đối mặt cường địch áp đảo; trọng nghĩa khí, giữ sát giới mấy vạn năm nhưng phá giới khi cần; trung thành tận tụy, hết lòng phò tá Vương Lâm trong mọi trận quyết chiến","aliases":[],"tabs":{"diem":[{"text":"Được chủ nhân Phong Giới nhắc tên, lệnh Huyền Bỉnh đi tìm để thông báo ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Dẫn mấy vạn tu sĩ Vân Hải từ tinh không bất ngờ xuất hiện tiếp viện giới nội trong đại chiến","chuong":"@c1425"},{"text":"Lộ danh hiệu Huyết Sam Đồng Tử, phá sát giới mấy vạn năm, một mình đối đầu nhiều cao thủ bước thứ ba giới ngoại","chuong":"@c1427"},{"text":"Bị phong ấn tại Thất Thải Giới trong đại chiến thứ hai, sau đó được Vương Lâm giải cứu khỏi đạo quả giam cầm","chuong":"@c1469"},{"text":"Chọn chuyển thế đầu thai, sau đó được Vương Lâm dùng tinh quang điểm mi tâm khôi phục ký ức kiếp trước","chuong":"@c1959"}],"kinhLich":[{"importance":"major","mucCt":"vua","chuong":"@c1959","tieuDe":"Khôi phục ký ức kiếp trước","text":"Chuyển thế thành đồng tử mặc hồng bào, đi cùng hơn mười tu sĩ ở bắc châu. Bị Vương Lâm dùng tinh quang điểm mi tâm, trí nhớ kiếp trước dần hồi phục, sau mấy canh giờ nhớ ra mình là Hồng Sam Tử, kích động nhìn trời cười.","anchor":"Đồng tử mặc hồng ý kia nhìn lên bầu trời, trên mặt từ từ lộ nụ cười"},{"importance":"bridge","mucCt":"gon","chuong":"@c1969","tieuDe":"Nhận hào quang triệu hồi khi truy kích","text":"Đang truy kích một lão già trong khu vực tiên tộc, nhận hào quang dung nhập vào mi tâm, nhìn thoáng về Thiên Ngưu Châu rồi tăng tốc truy kích.","anchor":"sắc mặt âm trầm có một vẻ nhu hòa, nhưng tốc độ truy kích lại càng nhanh hơn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Chủ nhân kiếp trước, người giải khai ký ức","ghiChu":"@c1959"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1959","@c1969"]},{"id":"than-bao","name":"Thân Báo","gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tông chủ một tiểu tông phái ở Nam Ni châu, Đông châu. Là cố nhân chuyển thế trong động phủ giới của Vương Lâm, thuộc Thất Đạo Tông. Đang lo âu trước chiến tranh tiên cổ sắp tới.","vaiTro":"Cố nhân chuyển thế của Vương Lâm, tông chủ tiểu tông phái, thành viên Thất Đạo Tông","tinhCach":"Lo âu trước thời cuộc; kiên định sau khi gặp lại Vương Lâm","aliases":[],"tabs":{"diem":[{"text":"Cố nhân chuyển thế trong động phủ giới, tông chủ tiểu tông phái ở Nam Ni châu","chuong":"@c1959"},{"text":"Sau khi Vương Lâm gặp, ánh mắt từ mê mang hóa kiên định","chuong":"@c1959"}],"kinhLich":[{"mucCt":"vua","text":"Là tông chủ tiểu tông phái ở Nam Ni châu, đang lo âu vì chiến tranh sắp tới và nội bộ chia rẽ ý kiến phụ thuộc tông lớn. Vương Lâm tìm tới gặp mấy canh giờ rồi rời đi, sau đó ánh mắt từ mê mang hóa kiên định.","anchor":"sau đó mấy canh giờ liền rời đi","bridge":true,"khoang":"@c1959"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Chủ nhân kiếp trước, người tìm gặp giúp đỡ","ghiChu":"@c1959"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1959"]},{"id":"thanh-hong","name":"Thanh Hồng","gioiTinh":"nu","theLuc":[{"ten":"Nhật Nguyệt tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Niết đỉnh phong (toàn năng bước thứ ba)","trangThai":"song","blurb":"Nữ tử thiên tài ngàn năm khó tìm của Nhật Nguyệt tông, đệ nhất tông Thiên Phương châu, Đông châu. Tu vi Không Niết đỉnh phong, được đại trưởng lão thu làm đồ đệ, gọi là thánh nữ. Luôn cảm thấy mình không thuộc thiên địa này — nghi là cố nhân chuyển thế trong động phủ giới.","vaiTro":"Thánh nữ Nhật Nguyệt tông, nghi là cố nhân chuyển thế của Vương Lâm","tinhCach":"Dung mạo tuyệt mỹ, tính cách lạnh lùng; thích màu đỏ và bướm; thường đắm chìm trong mộng, cảm thấy mình không thuộc thiên địa này","aliases":["Hồng Điệp","Hồng Diệp"],"tabs":{"diem":[{"text":"Thiên tài ngàn năm khó tìm của Nhật Nguyệt tông, gần ngàn năm đạt Không Niết đỉnh phong, chỉ kém một bước Không Linh","chuong":"@c1959"},{"text":"Luôn cảm thấy mình không thuộc thiên địa này, giống những người chuyển thế khác, thường đắm chìm trong mộng","chuong":"@c1959"},{"text":"Thích màu đỏ (mọi người biết) và thích bướm (không ai biết), mặc y phục đỏ như con bướm đỏ trong gió mưa","chuong":"@c1959"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1959","tieuDe":"Thánh nữ Nhật Nguyệt tông lộ diện","text":"Là nữ tử thiên tài ngàn năm khó tìm của Nhật Nguyệt tông (đệ nhất tông Thiên Phương châu, Cửu tông thập tam môn Đông châu). Trong gần ngàn năm đạt toàn năng bước thứ ba Không Niết đỉnh phong, chỉ kém một bước Không Linh. Được đại trưởng lão tu vi Kim Tôn (thực lực Thiên Tôn) tự tay thu làm đồ đệ, cách mấy năm xuất quan chỉ điểm, thậm chí đưa vào chỗ bế quan cùng tu. Được gọi là thánh nữ, dung mạo tuyệt mỹ nhưng tính cách lạnh lùng, gần ngàn năm chưa tìm đạo lữ. Thích màu đỏ và bướm, luôn cảm thấy mình không thuộc thiên địa này, thường đắm chìm trong mộng — giống những người chuyển thế khác. Khi ra khỏi bế quan trong mưa bão, nhìn con bướm tuyệt đẹp bay tới, nghe tiếng gọi nhu hòa từ sau lưng.","anchor":"Nàng vẫn luôn cảm thấy mình không thuộc về thiên địa này"},{"importance":"normal","mucCt":"ky","chuong":"@c1960","tieuDe":"Chọn quên kiếp trước, đưa đáp án luân hồi","text":"Gặp Vương Lâm dưới mưa, tiết lộ khi đạt bước thứ ba đã gặp Vương Lâm trong mộng. Nhớ ra kiếp trước mình tên Hồng Điệp, và cả kiếp trước của kiếp trước. Đưa ra đáp án cho câu hỏi Vương Lâm từng hỏi: chọn quên đi kiếp trước, chỉ giữ kiếp này, vì cố chấp luân hồi là đau đớn và mê man. Nhắc lại câu nói của người khác từ ký ức kiếp trước của kiếp trước. Nhìn Vương Lâm rời đi, đứng đến khi mưa tạnh, thả con bướm bay xa, mang vẻ suy sụp cô độc quay vào động phủ.","anchor":"Quên đi kiếp trước, chỉ có kiếp này, nếu vẫn cố chấp, liên tục luân hồi là một sự đau đớn"}],"tuViMoc":[{"chuong":"@c1959","canhGioi":"Không Niết đỉnh phong (toàn năng bước thứ ba)","text":"Trong gần ngàn năm tu luyện đạt toàn năng bước thứ ba Không Niết đỉnh phong, chỉ kém một bước Không Linh","importance":"major"}],"nhanMach":[{"ten":"Đại trưởng lão Nhật Nguyệt tông","tag":"su-mon","quanHe":"Sư phụ, tu vi Kim Tôn thực lực Thiên Tôn, tự tay thu nàng làm đồ đệ","ghiChu":"@c1959"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1959","@c1960","@c1968"]},{"id":"dai-truong-lao-nhat-nguyet-tong","name":"Đại trưởng lão Nhật Nguyệt tông","gioiTinh":"khong-ro","theLuc":[{"ten":"Nhật Nguyệt tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Kim Tôn (thực lực Thiên Tôn, chưa xông Thiên Tôn Niết)","trangThai":"song","blurb":"Đại trưởng lão Nhật Nguyệt tông, tu vi Kim Tôn nhưng nghe nói có thực lực Thiên Tôn mà chưa xông Thiên Tôn Niết. Tự tay thu Thanh Hồng làm đồ đệ, cách mấy năm xuất quan chỉ điểm.","vaiTro":"Đại trưởng lão Nhật Nguyệt tông, sư phụ Thanh Hồng","tinhCach":"Hầu như hàng năm bế quan, thỉnh thoảng xuất quan chỉ điểm đồ đệ","aliases":[],"tabs":{"diem":[{"text":"Tu vi Kim Tôn, nghe nói có thực lực Thiên Tôn nhưng chưa xông Thiên Tôn Niết","chuong":"@c1959"},{"text":"Tự tay thu Thanh Hồng làm đồ đệ, thậm chí đưa vào chỗ bế quan cùng tu","chuong":"@c1959"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1959","tieuDe":"","text":"Được nhắc tới là đại trưởng lão Nhật Nguyệt tông, sư phụ Thanh Hồng, tu vi Kim Tôn thực lực Thiên Tôn.","anchor":"là đệ nhất tông của Thiên Phương châu, cũng là một trong Cửu tông thập tam môn của Đông châu"}],"tuViMoc":[{"chuong":"@c1959","canhGioi":"Kim Tôn (thực lực Thiên Tôn)","text":"Tu vi Kim Tôn, nghe nói có thực lực Thiên Tôn nhưng chưa xông Thiên Tôn Niết","importance":"major"}],"nhanMach":[{"ten":"Thanh Hồng","tag":"su-mon","quanHe":"Đồ đệ, thánh nữ Nhật Nguyệt tông","ghiChu":"@c1959"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1959"]},{"id":"mac-tri","name":"Mặc Trí","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1960","tieuDe":"","text":"Được Thanh Hồng gián tiếp nhắc tới qua câu nói từ ký ức kiếp trước của kiếp trước, Vương Lâm nhớ lại hình ảnh Mặc Trí trong miếu đêm mưa ở Chu Tước Tinh với ánh mắt đau đớn thương xót mà nay mới thấu hiểu.","anchor":"Mưa này sinh từ trời, chết ở đất, quá trình ở giữa chính là nhân sinh"},{"chuong":"@c1973","importance":"normal","mucCt":"gon","tieuDe":"Được xác nhận là đệ tử Thiên Vận Tử","text":"Thiên Vận Tử tự xưng Mặc Trí là đệ tử của hắn, nhằm chứng minh danh tính người bảo vệ La Bàn Định Giới.","anchor":"Ta có một đệ tử, ngươi hẳn là nhận ra hắn. tên của hắn chính là Mặc Trí"}],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Thiên Vận Tử tự nhận Mặc Trí là đệ tử mình (@c1973)"},{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Cố giao, từng gặp ở miếu đêm mưa","ghiChu":"Tới sơn cốc thăm, khuyên bỏ cuộc nhưng bị từ chối, uống rượu suốt đêm"}],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Gặp Vương Lâm trong miếu hoang, nhận ra ý cảnh tỏa hồn của Vương Lâm và giảng đạo lý sinh tử","chuong":"@c0259"},{"text":"Sở hữu ý cảnh Vong Cảnh (quên lãng) cùng thần thông Súc Địa thành thốn, tu vi rất cao","chuong":"@c0259"},{"text":"Đại diện Xuất Vân Quốc dâng lễ vật chúc mừng tân Chu Tước Thánh Hoàng","chuong":"@c1023"},{"text":"Gặp lại Vương Lâm sau gần ngàn năm, cùng uống rượu luận đạo rồi mang ngọc giản về truyền tới Tu Chân Liên Minh","chuong":"@c1026"},{"text":"Được xác nhận là đệ tử của Thiên Vận Tử","chuong":"@c1973"}]},"nguon":["@c1960","@c1968","@c1973"],"trangThai":"song","gioiTinh":"nam","vaiTro":"Đệ tử Thiên Vận Tử, tu sĩ Xuất Vân Tông — người giảng đạo sinh tử cho Vương Lâm","tinhCach":"Điềm tĩnh, siêu thoát; thấu triệt lẽ sinh tử qua luận đạo; trọng tình, cảm khái với cố nhân","blurb":"Mặc Trí là đệ tử của Thiên Vận Tử, tu sĩ thuộc Xuất Vân Tông (Xuất Vân Quốc, Tu Chân Liên Minh), sở hữu ý cảnh Vong Cảnh cùng thần thông Súc Địa thành thốn và khả năng nhận diện ý cảnh người khác, cho thấy tu vi rất cao dù cảnh giới cụ thể chưa được nêu rõ. Ông gặp Vương Lâm lần đầu trong cổ miếu dưới mưa đêm trên Chu Tước Tinh, nhận ra Vương Lâm mang ý cảnh tỏa hồn và giảng cho Vương Lâm đạo lý sinh tử. Gần ngàn năm sau, ông được sư tôn phái đi chúc mừng tân Thánh Hoàng Chu Tước, gặp lại Vương Lâm cùng uống rượu luận đạo, rồi mang ngọc giản truyền tin tới ba thế lực còn lại của Tu Chân Liên M"},{"id":"thanh-lam","name":"Thanh Lâm","aliases":["Tiên Đế"],"tabs":{"kinhLich":[{"importance":"major","mucCt":"ky","chuong":"@c1960","tieuDe":"Luân hồi thành phàm nhân thợ rèn, chọn quên","text":"Đã luân hồi thành phàm nhân, là đại hán hơn ba mươi tuổi chủ lò rèn ở thành trì Lâm Hóa Châu, Đông Châu. Có vợ hiền đẹp và con gái tám tuổi tên Sương. Sống đơn giản hạnh phúc, rèn sắt cần mẫn. Trong giấc mộng thấy mình là tiên đế rung trời chuyển đất, cùng con gái tên Sương, nhưng tỉnh mộng luôn chọn quên đi, ôm lấy gia đình thực tại. Vương Lâm quan sát từ bầu trời, nhận ra hắn chính là Tiên Đế Thanh Lâm trong động phủ giới năm xưa.","anchor":"Tiên đế năm đó trong động phủ giới, hiện giờ đã trở thành phàm nhân, nhưng hắn lại có được hạnh phúc"},{"chuong":"@c1966","importance":"bridge","mucCt":"gon","text":"Động phủ tại Yêu Linh Chỉ Địa được Vương Lâm phục hồi, bên trong tìm thấy bức tranh phong ấn nữ tử thần bí.","anchor":"trong động phủ của tiên đế Thanh Lâm"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Được xác nhận là Tiên Đế, cường giả đệ nhất Tiên giới và phụ thân Thanh Sương qua ngọc giản","chuong":"@c0595"},{"text":"Thức tỉnh trong trận pháp hồi sinh, khai sinh Tân Vũ Giới, ôn hòa an ủi đệ tử sau tang thương","chuong":"@c1050"},{"text":"Hiện thân từ thức hải, đánh tan Cổ Ma Tháp Già và truyền thụ Quy tắc thân thể cho Vương Lâm","chuong":"@c1047"},{"text":"Thi triển viễn cổ tiên thuật gọi ánh sáng viễn cổ, lãnh đạo giới nội đánh trận giết tu sĩ giới ngoại","chuong":"@c1453"},{"text":"Được xác nhận là phách thứ ba (cam) của Thất Thải Tiên Tôn, phách chứa chính khí và lương tri","chuong":"@c1650"},{"text":"Luân hồi thành phàm nhân thợ rèn ở thành trì Lâm Hóa Châu, có vợ, chọn quên đi quá khứ","chuong":"@c1960"}]},"nguon":["@c1960","@c1966"],"vaiTro":"Tiên Đế — phách thứ ba (cam) của Thất Thải Tiên Tôn, cường giả đệ nhất Tiên giới","tinhCach":"Mưu tính sâu xa, bố cục vượt thời gian; lạnh lùng quyết đoán với kẻ địch; che chở đệ tử và giới nội, trọng ân nghĩa; mang vẻ tang thương sau biến cố, ôn hòa với người thân cận","blurb":"Thanh Lâm là Tiên Đế, được công nhận là cường giả đệ nhất Tiên giới, phụ thân Thanh Sương, phu quân Hoa Phi, ân sư của Vương Nguy và Hồ Quyên, đồng thời là phách thứ ba chứa chính khí và lương tri của Thất Thải Tiên Tôn. Sau khi thân thể bị Cổ Ma Tháp Già chiếm cứ, ông nhờ trận pháp hồi sinh mà thức tỉnh, truyền Quy tắc thân thể cho Vương Lâm và khai sinh Tân Vũ Giới, rồi bế quan chữa thương hàng trăm năm tại Vũ Tiên Giới, nhiều lần ra tay bảo vệ giới nội và tham chiến đại chiến giới ngoại. Cuối cùng ông luân hồi thành phàm nhân thợ rèn tại thành trì Lâm Hóa Châu, chọn cách quên đi quá khứ."},{"id":"chu-dat","name":"Chu Dật","cn":"朱逸","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1961","importance":"normal","mucCt":"vua","tieuDe":"Viên mãn hạnh phúc bên Thanh Sương","text":"Được Vương Lâm quan sát từ xa, vẻ mặt hạnh phúc tươi cười, đã đạt viên mãn sau nhiều năm khổ luyện. Vương Lâm mỉm cười uống rượu mừng cho hắn.","anchor":"khi nhìn thấy vẻ hạnh phúc và tươi cười trên mặt của Chu Dật, Vương Lâm cùng mỉm cười"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Thiêu đốt Nguyên Thần đột phá Vấn Đỉnh kỳ ngay trước lúc chết, giao phó Vũ Chi Tiên Kiếm và di nguyện cho Vương Lâm","chuong":"@c0293"},{"text":"Nguyên Thần nhập kiếm, hóa thành Kiếm Tiêu Chi Hồn trong Vũ Chi Tiên Kiếm","chuong":"@c0294"},{"text":"Bị phong ấn trăm năm trong Luyện Tiên Hóa Ma đại trận, linh thể hao tổn chỉ còn sót lại, vẫn cứu Vương Lâm","chuong":"@c0594"},{"text":"Hóa kiếm quang đánh thẳng Hư Không Tử, dẫn phát thương thế cũ của đối phương, linh thể hao tổn nghiêm trọng","chuong":"@c0991"},{"text":"Nhìn Thanh Sương phủ nhận và quên lãng mình, vẫn ngồi bên cạnh không rời mắt — bi kịch si tình ngàn năm","chuong":"@c1046"},{"text":"Cuối cùng đạt viên mãn hạnh phúc bên Thanh Sương sau nhiều năm khổ luyện và chờ đợi","chuong":"@c1961"}]},"nguon":["@c1961"],"vaiTro":"Phụ — si tình kiếm tu, Kiếm Tiêu Chi Hồn của Vũ Chi Tiên Kiếm, ân nhân bảo hộ Vương Lâm","tinhCach":"Si tình bền bỉ, ngàn năm không đổi dù người xưa đã quên lãng; trọng nghĩa xả thân, sẵn sàng thiêu đốt Nguyên Thần vì người; kiên nghị chịu phong ấn trăm năm không oán hận; trầm mặc bi ai trước bi kịch tình duyên không trọn nhưng vẫn thủ hộ lặng lẽ","blurb":"Chu Dật vốn là đệ tử tư chất xuất sắc của Ngũ Hành Tông xuất thân Chu Tước tinh, về sau trở thành đại trưởng lão Thi Âm Tông, cả đời mang theo nữ thi tiên nhân Đình Nhi và ôm mối si tình ngàn năm với Thanh Sương. Vì cứu Đình Nhi, y thiêu đốt Nguyên Thần đột phá Vấn Đỉnh kỳ ngay trước lúc thân thể cháy tàn, giao phó Vũ Chi Tiên Kiếm cùng di nguyện cho Vương Lâm rồi Nguyên Thần nhập kiếm hóa thành Kiếm Tiêu Chi Hồn. Từ đó, Chu Dật dĩ thân phận kiếm linh nhiều lần trợ chiến bảo hộ Vương Lâm qua vô số kiếp nạn, chịu phong ấn trăm năm không oán, đánh thương Hư Không Tử để hộ chủ, lặng lẽ theo sau T"},{"id":"thanh-suong","name":"Thanh Sương","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1961","importance":"bridge","mucCt":"gon","text":"Ở bên Chu Dật khi Vương Lâm nhìn từ xa, hai người hạnh phúc bên nhau.","anchor":"Chu Dật và Thanh Sương"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Từng bày kế áp chế đối thủ khi động phủ mở ra và là người duy nhất có thể tiến vào động phủ thứ năm — cấm địa bế quan tuyệt mật của Thanh Lâm","chuong":"@c0952"},{"text":"Thân thể bị Cổ Ma Tháp Già chi phối và tranh đoạt sau khi đứng dậy trong tầng chín của tiên tháp","chuong":"@c0996"},{"text":"Hồn phách tụ lại trong thức hải Thanh Lâm, dung nhập thể Vương Lâm và thức tỉnh tại Tân Vũ Giới, hóa băng sơn","chuong":"@c1046"},{"text":"Được Vương Lâm thu hồi vận mệnh trong mặt trời thứ chín","chuong":"@c1540"},{"text":"Thần sắc lạnh lùng bước theo Thanh Lâm vào con đường chuyển thế, quay đầu nhìn Chu Dật trước khi biến mất","chuong":"@c1696"},{"text":"Không chọn tu tiên, chuyển thế nhiều lần như phàm nhân, cuối cùng ở bên Chu Dật hạnh phúc","chuong":"@c1961"}]},"nguon":["@c1961"],"vaiTro":"Tiên quân Vũ Tiên Giới — con gái Tiên Đế Thanh Lâm","tinhCach":"mưu lược, từng bày kế áp chế đối thủ và bố trí cấm địa bế quan tuyệt mật; nặng tình nhưng ẩn nhẫn, nén đau đớn trước Chu Dật; lạnh lùng, ít để lộ cảm xúc","blurb":"Thanh Sương là Tiên quân của Vũ Tiên Giới, con gái Tiên Đế Thanh Lâm — vị Tiên Đế chí tôn từng bước vào bước tu đạo thứ ba. Di thể nàng được Chu Dật gửi gắm cho Vương Lâm mang theo với hy vọng phục sinh, trải qua nhiều biến cố bị Cổ Ma Tháp Già chi phối trước khi hồn phách tụ lại trong thức hải Thanh Lâm, dung nhập thể Vương Lâm và thức tỉnh tại Tân Vũ Giới. Sau khi được thu hồi vận mệnh trong mặt trời thứ chín, nàng trở lại tiên giới với ký ức chưa hoàn toàn phục hồi, rồi bước theo Thanh Lâm vào con đường chuyển thế, không chọn tu tiên mà sống như phàm nhân qua nhiều kiếp, cuối cùng ở bên Chu"},{"id":"thap-tam","name":"Thập Tam","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1961","importance":"normal","mucCt":"gon","tieuDe":"Theo sư tôn vào động phủ giới","text":"Là người duy nhất trong tất cả cố nhân muốn đi theo Vương Lâm trở lại động phủ giới, vì ở bên cạnh sư tôn là thỏa mãn lớn nhất.","anchor":"chỉ có Thập Tam là muốn đi theo Vương Lâm trở lại động phủ giới"},{"chuong":"@c1963","importance":"normal","mucCt":"gon","tieuDe":"Được triệu ra tại Tiên giới, cung kính theo sư tôn","text":"Được Vương Lâm triệu ra tại Tiên giới, chỉ hơi hoảng hốt rồi khôi phục bình tĩnh, cung kính vái sư tôn và đứng bên cạnh.","anchor":"chỉ cần có thể đi theo sư tôn thì tất cả đều không có ý nghĩa gì đặc thù"},{"chuong":"@c1964","importance":"normal","mucCt":"vua","tieuDe":"Thi triển Cực Hỏa Đạo giết đệ tử Xích Hồn Tử","text":"Theo lệnh Vương Lâm, thi triển Cực Hỏa Đạo (Bát Cực Đạo), liệt hỏa bao phủ bầu trời, tiêu diệt toàn bộ con rối huyết ảnh và chém đầu thanh niên hồng bào. Tu vi đã đại tiến nhờ Vương Lâm dốc lòng truyền thụ thần thông và dùng sức mạnh thiên địa.","anchor":"Thập Tam lạnh lùng từ trong biên lửa đi ra. tay phải hắn cầm theo cái đầu người mang vẻ tuyệt vọng"},{"chuong":"@c1966","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm mang theo rời Tiên giới cùng Mộc Băng Mi và Hứa Lập Quốc.","anchor":"Vương Lâm mang theo Mộc Băng Mi và đám người Thập Tam"},{"chuong":"@c1967","importance":"bridge","mucCt":"gon","text":"Thủ hộ bên ngoài động phủ nơi Vương Lâm và Mộc Băng Mi đang ngồi trong mộng cảnh luân hồi.","anchor":"Bên trong động phủ mà Thập Tam đang thủ hộ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Chỉ tu luyện Luyện Hồn Yêu Thuật ba tháng đã đạt giai đoạn ba, chế thành hồn phiên bảy thước đầu tiên","chuong":"@c0505"},{"text":"Bị phế tu vi vẫn không cam lòng, mỗi đêm chịu đau luyện thể theo pháp Cự Ma Tộc, tự phát gần đạt yêu lực nhị tinh","chuong":"@c0508"},{"text":"Nhận truyền thừa Cự Linh Cửu Tu, kích động quỳ đập đầu tôn Vương Lâm làm Lão tổ, thề cả đời trung thành","chuong":"@c0530"},{"text":"Ngồi dưới tượng đá Vương Lâm suốt hơn hai nghìn ngày đêm không nhúc nhích, canh giữ động khẩu cho sư tôn","chuong":"@c1018"},{"text":"Là người sớm nhất rời Vũ Giới, mang theo pho tượng Vương Lâm dựa cảm ứng mơ hồ khổ tìm sư tôn khắp nơi","chuong":"@c1440"},{"text":"Chuyển thế thành cô nhi Vương Thạch, được Vương Lâm khôi phục ký ức, tiếp tục theo sư tôn vào Tiên giới thi triển Cực Hỏa Đạo","chuong":"@c1955"}]},"nguon":["@c1961","@c1963","@c1964","@c1966","@c1967","@c1968"],"cn":"十三","vaiTro":"Đại đệ tử của Vương Lâm — thiên tài Luyện Hồn Yêu Thuật kiêm thủ lĩnh bộ lạc Luyện Hồn","tinhCach":"Trầm ổn kiên nghị, càng trải biến cố càng vững chí; bất khuất không cam lòng, phế tu vi vẫn tự luyện thể mỗi đêm; trung thành tận tụy tuyệt đối, nguyện theo sư tôn dù chuyển thế đầu thai; cảnh giác điềm tĩnh trong hiểm cảnh","blurb":"Kính Thập Tam là đại đệ tử của Vương Lâm, trời sinh ngộ tính với Luyện Hồn Yêu Thuật — chỉ ba tháng đã đạt giai đoạn ba. Sau khi bị phế tu vi, gã không cam lòng mà tự phát luyện thể theo pháp Cự Ma Tộc, quỳ bái Vương Lâm làm Lão tổ, nhận truyền thừa Cự Linh Cửu Tu rồi trưởng thành thành thủ lĩnh thần thông kinh người của bộ lạc Luyện Hồn, thân thể được rèn bằng máu Cự Ma Tộc và máu vương tộc Cổ Thần đến gần cảnh giới Tiên vệ Ngân Thi. Gã là người sớm nhất rời Vũ Giới mang theo pho tượng Vương Lâm khổ tìm sư tôn, cuối cùng nguyện theo sư phụ chuyển thế đầu thai, chuyển thế thành Vương Thạch rồi"},{"id":"moc-bang-mi","name":"Mộc Băng Mi","cn":"木冰眉","aliases":["Mộc Ngung","Liễu Mi","Côn Hư thánh nữ"],"gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Được gọi là Thánh nữ điện hạ trong Tiên giới, đứng trên đỉnh núi cao, dung mạo tuyệt luân. Cầm thanh kiếm do bổn nguyên Vương Lâm biến thành (còn tồn tại khí tức Đạo cổ), nhớ lại lời hẹn năm xưa, nước mắt rơi lên thân kiếm. Bị Xích Hồn Tử tuyển chọn làm đạo lữ cho đệ tử, toan bị dạy dỗ trước khi đưa.","anchor":"Nếu ta còn ở thế gian thì sẽ đón chàng","bridge":true,"khoang":"@c1962"},{"chuong":"@c1963","importance":"major","mucCt":"ky","tieuDe":"Tái ngộ Vương Lâm, đồng ý ước định Mộng Đạo trăm năm","text":"Đứng trên ngọn núi cầm kiếm lộ vẻ quyết đoán như đã hạ quyết tâm điều gì, định rời đi thì phát hiện Vương Lâm. Khi nghe gọi tên Liễu Mi, tái nhợt, thanh kiếm rơi, nước mắt rơi lã chã, nói không muốn nghe. Sau khi Vương Lâm giải thích sẽ dùng Mộng Đạo thuật tạo một đời luân hồi trăm năm cho cả ba người, trầm mặc hồi lâu rồi gật đầu đồng ý. Hỏi hiện tại chàng là trượng phu của ta đúng không, rồi cười trong nước mắt ôm lấy Vương Lâm — lần đầu tiên hai người chính thức ôm nhau.","anchor":"Đây có thể nói là lần đầu tiên bọn họ chính thức ôm nhau, lần đâu tiên bỏ qua tất cả những tâm tư phức tạp trong tim"},{"chuong":"@c1964","importance":"bridge","mucCt":"gon","text":"Ở Tiên giới, lạnh lùng nhìn thanh niên hồng bào (đệ tử Xích Hồn Tử) như nhìn người chết khi hắn tuyên bố sẽ dạy dỗ nàng.","anchor":"Mộc Băng Mi đẹp tuyệt trần, nữ tử này hiện giờ đang lạnh lùng nhìn mình"},{"chuong":"@c1966","importance":"normal","mucCt":"gon","tieuDe":"Rời Tiên giới cùng Vương Lâm","text":"Được Vương Lâm mang theo rời Tiên giới.","anchor":"Vương Lâm mang theo Mộc Băng Mi và đám người Thập Tam"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"the-thiep","quanHe":"Trượng phu, lần đầu chính thức ôm nhau, ước định Mộng Đạo luân hồi trăm năm","ghiChu":"@c1963"}],"tuiDo":{},"diem":[{"text":"Tuyên bố mọi thần thông và nguyên lực thiên địa trong Côn Hư Tinh vực đều nằm trong tay nàng, thể hiện quyền uy tuyệt đối","chuong":"@c1011"},{"text":"Bị Thác Sâm đánh tan thân, nguyên thần trọng thương, dùng bí thuật Côn Hư thoát ra lưu lạc tới Vân Hải tinh vực","chuong":"@c1147"},{"text":"Xác nhận danh tính Liễu Mi — mẹ Vương Bình — và đạo tâm viên mãn, từ biệt Vương Lâm dưới ánh trăng","chuong":"@c1196"},{"text":"Được Vương Lâm phong làm tông chủ Thần Tông, chỉ huy bày binh bố trận tạo phòng tuyến giới nội trong đại chiến giới ngoại","chuong":"@c1440"},{"text":"Được hé lộ chính là phách thứ sáu (phách sinh từ tình) của Thất Thải Tiên Tôn","chuong":"@c1651"},{"text":"Tái ngộ Vương Lâm tại Tiên giới, đồng ý ước định Mộng Đạo trăm năm, cùng hắn rời Tiên giới","chuong":"@c1963"}]},"nguon":["@c1961","@c1962","@c1963","@c1964","@c1966","@c1968"],"vaiTro":"Côn Hư Thánh Nữ — mẹ Vương Bình, tông chủ Thần Tông, phách thứ sáu của Thất Thải Tiên Tôn","tinhCach":"Lạnh lùng quyền uy nhưng nặng tình với con và Vương Lâm, âm thầm chịu đựng chia ly giấu nỗi đau sau vẻ ngoài băng lãnh; bất khuất trước cường địch, không chịu khuất phục dù trọng thương hay bị giam cầm; kiên định trong đại chiến, sẵn sàng xông trận dù tuyệt vọng","blurb":"Mộc Băng Mi là Côn Hư Thánh Nữ, mẹ của Vương Bình, từng nắm quyền điều khiển toàn bộ thần thông và nguyên lực thiên địa trong Côn Hư Tinh vực. Sau khi Côn Hư cảnh bị Thác Sâm hủy diệt, nàng trọng thương lưu lạc tới Vân Hải tinh vực lấy thân phận Liễu Mi tái ngộ Vương Lâm, rồi về Thần Tông chịu giam cầm nhiều năm trước khi được Vương Lâm phong làm tông chủ, chỉ huy phòng tuyến giới nội trong đại chiến giới ngoại. Về sau nàng được hé lộ chính là phách thứ sáu — phách sinh từ tình — của Thất Thải Tiên Tôn, và trong Tiên giới đã tái ngộ Vương Lâm, đồng ý ước định Mộng Đạo trăm năm, là một trong số"},{"id":"lam-mong-dao-ton","name":"Lam Mộng Đạo Tôn","cn":"蓝梦道尊","aliases":["Lam Mộng"],"gioiTinh":"nam","trangThai":"song","vaiTro":"Thái Cổ Ngũ Tôn — lãnh đạo Lam Ti Tộc, người sinh ra trong giới nội","tinhCach":"Thâm trầm u buồn, nặng tình cảm gia đình; điềm tĩnh thận trọng, coi trọng nhân quả; trọng nghĩa khí, sẵn sàng xả thân hộ người thân; phức tạp nội tâm, hay hối hận và trầm mặc","blurb":"Lam Mộng Đạo Tôn là một trong Thái Cổ Ngũ Tôn, tu vi Không Huyền đại viên mãn, lãnh đạo Lam Ti Tộc tại Lam Sơn và được tiết lộ là người sinh ra trong giới nội. Ông từng chiêu mộ Vương Lâm kế thừa đạo thống không thành nhưng vẫn truyền thần thông, nhiều lần can thiệp hộ Vương Lâm trong các biến cố lớn, từ cuộc đối đầu Thiên Nghịch đến đại chiến Chưởng Tôn. Dù từng vì ước định với Chưởng Tôn mà xuất thủ chặn Vương Lâm, về sau ông dứt khoát tuyên bố đứng về phía Vương Lâm, một mình đánh bại ba đạo tôn, và trở thành người mạnh nhất tọa trấn tân Tiên Giới cho đến khi bị Xích Hồn Giáo đánh trọng thư","tabs":{"diem":[{"text":"Lộ diện lần đầu, tự xưng danh tính là chủ nhân bàn tay khổng lồ tấn công Thất Thải giới","chuong":"@c1156"},{"text":"Chiêu mộ Vương Lâm kế thừa đạo thống thất bại, truyền ba thức thần thông gồm Phiên Thiên, Quang Ảnh Thuẫn và Dung biến đạo thuật","chuong":"@c1243"},{"text":"Xuất thủ chặn Vương Lâm theo ước định với Chưởng Tôn, ân đoạn nghĩa tuyệt","chuong":"@c1492"},{"text":"Tuyên bố đứng về phía Vương Lâm, tiết lộ bản thân là người sinh ra trong giới nội, kể bí mật ngũ phi","chuong":"@c1582"},{"text":"Một mình đánh bại Diệu Âm Đạo Tôn, Cửu Thiên và Đại Hoang Thượng Nhân trong ba ngày, tự xưng Thái Cổ Ngũ Tôn","chuong":"@c1583"},{"text":"Dùng tu vi cả đời phong ấn Chưởng Tôn ba nhịp thở, nói kết thúc nhân quả với Vương Lâm","chuong":"@c1679"}],"kinhLich":[{"chuong":"@c1961","importance":"normal","mucCt":"vua","tieuDe":"Trọng thương vì Xích Hồn Giáo","text":"Là người mạnh nhất tân Tiên giới, năm xưa tọa trấn bảo vệ bình an. Hiện đã bị Xích Hồn Giáo đánh trọng thương.","anchor":"Lam Mộng Đạo Tôn trọng thương"},{"mucCt":"vua","text":"Ngồi bên cạnh Nam Vân Tử, sắc mặt tái nhợt đang thổ nạp chữa thương sau khi bị Xích Hồn Tử đánh trọng thương. Khinh thường Vương Lâm, gọi hắn là con kiến hôi trước mặt sư tôn Xích Hồn Tử.","anchor":"nếu không thì trước mặt sư tôn hắn chỉ là một con kiến hôi mà thôi","bridge":true,"khoang":"@c1962"},{"chuong":"@c1964","importance":"normal","mucCt":"vua","tieuDe":"Được Vương Lâm chữa thương, hỏi thăm Lý Thiến Mai","text":"Thương thế nặng, sắc mặt tái nhợt, được Vương Lâm dùng sức mạnh thiên địa chữa lành. Hỏi thăm con gái Lý Thiến Mai, nghe Vương Lâm nói chưa tìm được thì phẫn nộ thất vọng, cười ha hả đầy cay đắng.","anchor":"Nó vì ngươi mà đi tới Đại Lục Tiên Cương, ngươi lại không tìm được"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Người sáng tạo tân Tiên giới mà Lam Mộng tọa trấn bảo vệ"},{"ten":"Xích Hồn Tử","tag":"su-mon","quanHe":"Sư tôn"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người sáng tạo tân Tiên giới","ghiChu":"Tọa trấn lãnh địa Vương Lâm tạo ra"}],"tuiDo":{}},"theLuc":[{"ten":"Tân Tiên giới","trangThai":"gan-bo"}],"nguon":["@c1961","@c1962","@c1964","@c1965"]},{"id":"nam-van-tu","name":"Nam Vân Tử","gioiTinh":"nam","trangThai":"song","vaiTro":"Tu sĩ Thi Âm Tông (Liên Minh Tinh Vực) — người giữ ước định hợp nhất Tứ Đại Tiên Giới, tinh thông trận pháp","blurb":"Nam Vân Tử là tu sĩ thuộc Thi Âm Tông của Liên Minh Tinh Vực, một trong ba người ở ba tinh vực được chủ nhân Phong Giới giao ước định hợp nhất Tứ Đại Tiên Giới Phong Vũ Lôi Điện. Trong đại chiến giới nội – giới ngoại, ông vừa xung trận bảo vệ Vân Hải, vừa đảm nhận sửa chữa Phong Giới Đại Trận và ngưng tụ hư ảnh trận pháp khổng lồ tấn công kẻ địch; sau khi bị Chưởng Tôn đánh trọng thương bế quan rồi phục hồi, ông cầm đầu lực lượng chưa đầy tám ngàn tu sĩ giới nội quyết tử chiến tại Chu Tước Tinh, dốc toàn lực trợ giúp Vương Lâm mở Không Môn, và tiếp tục theo sát Vương Lâm xuất chinh. Về sau ông","tabs":{"diem":[{"text":"Được chủ nhân Phong Giới chọn làm một trong ba người giữ ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Xung trận bảo vệ Vân Hải, đồng thời đảm nhận sửa chữa Phong Giới Đại Trận trong đại chiến giới nội – giới ngoại","chuong":"@c1427"},{"text":"Ngưng tụ hư ảnh trận pháp khổng lồ phối hợp tấn công kẻ địch, thể hiện trình độ trận pháp cao thâm","chuong":"@c1438"},{"text":"Cầm đầu chưa đầy tám ngàn tu sĩ giới nội quyết tử chiến bên ngoài Chu Tước Tinh, trợ giúp Vương Lâm mở Không Môn","chuong":"@c1520"},{"text":"Chọn ở lại tân Tiên Giới trấn giữ, thân thể bị đánh tan vỡ chỉ còn nguyên thần","chuong":"@c1961"},{"text":"Được Vương Lâm dùng sức mạnh thiên địa ngưng tụ thân thể mới từ nguyên thần","chuong":"@c1964"}],"kinhLich":[{"chuong":"@c1961","importance":"normal","mucCt":"vua","tieuDe":"Thân thể tan vỡ, chỉ còn nguyên thần","text":"Ở lại tân Tiên giới không rời đi. Hiện thân thể đã bị đánh tan vỡ, chỉ còn lại nguyên thần.","anchor":"Nam Vân Tử thân thể tan vỡ, chỉ còn lại có nguyên thần"},{"mucCt":"ky","text":"Chỉ còn Nguyên thần tồn tại sau khi thân thể bị đánh tan, đối mặt hư ảnh đệ tử Xích Hồn Tử trên bầu trời Tiên giới. Tuyên bố tu sĩ Tiên giới không sợ chiến đấu, dẫn dắt tất cả tu sĩ trên mặt đất ngẩng đầu cùng hô vang, luồng sóng âm cuốn lên không trung hòa tan huyết quang tạm thời. Khẳng định Vương Lâm nhất định sẽ trở về.","anchor":"Tu sĩ chúng ta, sao không dám đánh một trận!","bridge":true,"khoang":"@c1962"},{"chuong":"@c1964","importance":"normal","mucCt":"vua","tieuDe":"Được Vương Lâm ngưng tụ thân thể từ Nguyên thần","text":"Đang ở trạng thái Nguyên thần, được Vương Lâm dùng sức mạnh thiên địa ngưng tụ thành thân thể cho nhập vào. Không chút lo lắng trước Xích Hồn Tử vì cảm nhận được sự hùng mạnh của Vương Lâm.","anchor":"hắn có thể cảm nhận được sự hùng mạnh của Vương Lâm"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Người sáng tạo Tiên giới, được Nam Vân Tử tin tưởng tuyệt đối"},{"ten":"Xích Hồn Tử","tag":"doi-thu","quanHe":"Kẻ thù vây khốn Tiên giới, đánh tan thân thể Nam Vân Tử"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người sáng tạo tân Tiên giới","ghiChu":""}],"tuiDo":{}},"theLuc":[{"ten":"Tân Tiên giới","trangThai":"gan-bo"}],"nguon":["@c1961","@c1962","@c1964","@c1965"],"canhGioiCaoNhat":"Bước thứ ba (chỉ còn Nguyên thần)","tinhCach":"Trọng nghĩa khí, cả đời ít nói nhưng quyết báo đáp ân tình Phong Tôn; kiên định không lùi bước trước kẻ địch mạnh; tinh thông trận pháp, hành sự cẩn trọng; có tầm nhìn đại cục, biết nắm thời cơ chỉ huy chiến trường","cn":"南云子"},{"id":"thanh-nien-hong-bao","name":"Thanh niên hồng bào","gioiTinh":"nam","trangThai":"tu-vong","vaiTro":"Đệ tử Xích Hồn Giáo, uy hiếp tân Tiên giới","tinhCach":"Ngạo mạn, hung hãn, coi thường truyền thuyết Vương Lâm","blurb":"Đệ tử Xích Hồn Giáo được phái tới tân Tiên giới ra tối hậu thư ép quy thuận trong năm ngày, đồng thời ép Mộc Băng Mi làm đạo lữ cho bốn thiếu gia, đe dọa phá hủy Chu Tước Tinh và pho tượng Vương Lâm.","tabs":{"diem":[{"text":"Ra tối hậu thư ép tân Tiên giới quy thuận Xích Hồn Giáo, đe dọa phá Chu Tước Tinh và pho tượng Vương Lâm","chuong":"@c1961"},{"text":"Nhận ra Vương Lâm chính là lão tổ pho tượng trên Chu Tước Tinh, run rẩy từ linh hồn","chuong":"@c1964"},{"text":"Nhận ra hình dáng Vương Lâm giống y pho tượng lão tổ trên Chu Tước Tinh, run rẩy từ linh hồn.","chuong":"@c1964"},{"text":"Từ nhỏ thấy pho tượng Vương Lâm trên Chu Tước Tinh, nhận ra lão tổ khi đối mặt thật thì run rẩy từ linh hồn","chuong":"@c1964"},{"text":"Từ nhỏ nhìn pho tượng Vương Lâm trên Chu Tước Tinh, khi nhận ra bản nhân thì run rẩy từ linh hồn.","chuong":"@c1964"}],"kinhLich":[{"chuong":"@c1961","importance":"normal","mucCt":"vua","tieuDe":"Ra tối hậu thư ép tân Tiên giới quy thuận","text":"Đệ tử Xích Hồn Giáo, ra tối hậu thư năm ngày ép tu sĩ tân Tiên giới quy thuận (đã qua ba ngày). Ép Mộc Băng Mi làm đạo lữ cho bốn thiếu gia, đe dọa phá Chu Tước Tinh và pho tượng Vương Lâm.","anchor":"ta sẽ phá hủy Chu Tước Tinh, phá nát pho tượng của cái người mà ngươi gọi là Lâm gì đó!"},{"chuong":"@c1964","importance":"normal","mucCt":"vua","tieuDe":"Xông vào Tiên giới, bị Thập Tam giết","text":"Xông vào Tiên giới qua lỗ thủng trận pháp, ngạo mạn tuyên bố sẽ dạy dỗ Mộc Băng Mi. Nhận ra Vương Lâm giống pho tượng lão tổ trên Chu Tước Tinh, linh hồn run rẩy. Bị Thập Tam thi triển Cực Hỏa Đạo chém đầu.","anchor":"Hình dáng của đối phương cùng với pho tượng mà từ nhỏ hắn đã nhìn thấy ở trên Chu Tước Tinh giống nhau y hệt"}],"tuViMoc":[],"nhanMach":[{"ten":"Mộc Băng Mi","tag":"doi-thu","quanHe":"Ép Mộc Băng Mi làm đạo lữ cho bốn thiếu gia"},{"ten":"Xích Hồn Tử","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Đệ tử Xích Hồn Tử"},{"ten":"Thập Tam","tag":"doi-thu","quanHe":"Người giết hắn","ghiChu":"Bị Thập Tam chém đầu"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Lão tổ Chu Tước Tinh","ghiChu":"Nhận ra pho tượng lão tổ trên Chu Tước Tinh"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Lão tổ đối phương","ghiChu":"Run sợ khi nhận ra Vương Lâm"}],"tuiDo":{}},"theLuc":[{"ten":"Xích Hồn Giáo","trangThai":"gan-bo"}],"nguon":["@c1961","@c1964"],"canhGioiCaoNhat":"Không rõ","aliases":["Đệ tử hồng bào Xích Hồn Tử"]},{"id":"hai-tu","name":"Hải Tử","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1961","importance":"bridge","mucCt":"gon","text":"Ở Tổ thành, Vương Lâm tới nhìn từ xa rồi lặng lẽ rời đi.","anchor":"ở nơi đó hẳn nhìn thấy Hải Tử"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Được Cửu Đế gọi ra tay cứu Đạo Nhất, mượn lực lượng Điệu Vong tộc can thiệp chiến cục","chuong":"@c1896"},{"text":"Dùng Liên Đạo Phi trấn áp linh hồn bảy mươi hai châu, giải thích cơ chế cấm cung cần đầu tiên tổ","chuong":"@c1897"},{"text":"Trợ giúp Cửu Đế hóa giải Trớ Thuật bằng thần thông Điệu Vong tộc sau khi trở về Đế Sơn","chuong":"@c1898"},{"text":"Tính toán ra thời hạn Thái Cổ Thần Cảnh mở hoàn toàn, thừa nhận không thể suy tính toàn bộ","chuong":"@c1928"},{"text":"Thi triển thuật bói toán trên Đế Sơn — bắt quyết tạo người tí hon, cắn lưỡi phun máu tươi","chuong":"@c1936"},{"text":"Lộ thần sắc phức tạp ẩn chứa tia minh ngộ khi Vương Lâm thành Đại Thiên Tôn","chuong":"@c1940"}]},"nguon":["@c1961"],"vaiTro":"Truyền nhân Điệu Vong tộc — trợ thủ bói toán và tính toán bên cạnh Cửu Đế","tinhCach":"Lạnh tĩnh, giỏi tính toán mưu lược; trung thành với Cửu Đế; hành sự có nguyên tắc, tuân thủ thỏa thuận","blurb":"Hài Tử (còn gọi Hải Tử) là thành viên Điệu Vong tộc, thường trực bên cạnh Cửu Đế trên Đế Sơn với vai trò vừa chiến đấu vừa thi triển thuật bói toán suy tính đại sự. Nàng từng mượn sức mạnh tộc mình cứu viện Đạo Nhất, dùng Liên Đạo Phi trấn áp linh hồn, trợ giúp Cửu Đế hóa giải Trớ Thuật, và phối hợp tính toán thời hạn Thái Cổ Thần Cảnh mở ra. Khi Vương Lâm thành Đại Thiên Tôn, Hài Tử trên đỉnh Đế Sơn lộ thần sắc phức tạp ẩn chứa tia minh ngộ, còn tại Tổ thành nàng được Vương Lâm lặng lẽ nhìn từ xa rồi rời đi."},{"id":"ham-yen","name":"Hàm Yên","gioiTinh":"nu","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1961","importance":"bridge","mucCt":"gon","text":"Được Thanh Thủy nhắc tới, đã chết rất lâu, linh hồn cũng không còn, Thanh Thủy thề tìm cách làm nàng sống lại.","anchor":"Nơi này có lẽ sẽ có phương pháp để ta làm cho Hàm Yên sống lại"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh Thủy","tag":"the-thiep","quanHe":"Người Thanh Thủy yêu, thề sẽ tìm cách cứu sống"}],"tuiDo":{}},"nguon":["@c1961"]},{"id":"hon-thien-nguu","name":"Hồn Thiên Ngưu","gioiTinh":"khac","trangThai":"song","vaiTro":"Linh hồn Thiên Ngưu bị phong ấn, được Vương Lâm giải thoát","blurb":"Linh hồn của Thiên Ngưu bị tiên tổ phong ấn từ lâu, thân thể đã hóa thành mặt đất của Thiên Ngưu Châu. Tại chương 1961, Vương Lâm dùng hai chỉ phá phong ấn, Hồn Thiên Ngưu ngưng hóa Nguyên thần và bay đi tự do như lưu tinh.","tabs":{"diem":[{"text":"Bị tiên tổ phong ấn nhiều năm, thân thể hóa thành mặt đất Thiên Ngưu Châu","chuong":"@c1961"},{"text":"Được Vương Lâm dùng hai chỉ phá phong ấn, ngưng hóa Nguyên thần bay đi tự do","chuong":"@c1961"}],"kinhLich":[{"chuong":"@c1961","importance":"major","mucCt":"gon","tieuDe":"Được Vương Lâm giải phong ấn, tự do bay đi","text":"Bị tiên tổ phong ấn nhiều năm, thân thể đã hóa thành mặt đất Thiên Ngưu Châu. Được Vương Lâm dùng hai chỉ phá phong ấn, ngưng hóa Nguyên thần, quy lạy cảm tạ rồi bay đi như lưu tinh.","anchor":"Đa tạ. Ta đồng ý."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Người giải phong ấn, giải phóng linh hồn"}],"tuiDo":{}},"nguon":["@c1961"]},{"id":"xich-hon-tu","name":"Xích Hồn Tử","cn":"赤魂子","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Xích Hồn Giáo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Xích Hồn Tử là linh hồn cực mạnh bị Đạo cổ Diệp Mịch phong ấn trong Hắc Tháp qua vô số năm. Được Vương Lâm dùng máu Đạo Cổ giải phóng trong sinh tử kiếp Chướng Tôn, hắn nuốt Tiên Phi rồi phá tan phong ấn Tĩnh Trung Lao Nguyệt mà thoát đi. Sau khi khôi phục tu vi đỉnh phong, hắn vây khốn Tiên giới và phá vỡ trận pháp bảo hộ, nhưng cuối cùng tâm thần sụp đổ và bị chính Vương Lâm hủy diệt hoàn toàn.","vaiTro":"Linh hồn cực mạnh bị phong ấn trong Hắc Tháp — cựu thù của Diệp Mịch, kẻ thù cuối cùng bị Vương Lâm hủy diệt","tinhCach":"Điên cuồng, mất kiểm soát sau vô số năm bị giam cầm; thù hận Diệp Mịch cực sâu; kiêu ngạo bất tuân; tâm thần bất ổn, không chấp nhận được thực tại","tabs":{"diem":[{"text":"Được Vương Lâm dùng máu Đạo Cổ giải phong ấn từ Hắc Tháp, gào thét điên cuồng hiện huyết ảnh và nuốt Tiên Phi","chuong":"@c1491"},{"text":"Cười điên cuồng phá tan phong ấn Tĩnh Trung Lao Nguyệt, thiên địa chấn động, tuyên bố ân oán triệt tiêu rồi thoát đi tự do","chuong":"@c1492"},{"text":"Lộ thân thế là hồn phách bị Diệp Mịch phong ấn năm xưa, khôi phục tu vi đỉnh phong và vây khốn Tiên giới","chuong":"@c1962"},{"text":"Phá vỡ trận pháp bảo hộ Tiên giới sau mấy ngày ăn mòn, mở lỗ thủng khổng lồ","chuong":"@c1964"},{"text":"Tâm thần sụp đổ hoàn toàn, viện dẫn quan hệ bạn cũ với La Minh nhưng bị Vương Lâm hủy diệt","chuong":"@c1966"}],"kinhLich":[{"chuong":"@c1962","importance":"normal","mucCt":"ky","tieuDe":"Lộ thân thế, vây khốn Tiên giới","text":"Chính là hồn phách bị Diệp Mịch phong ấn mà Vương Lâm thả ra trong sinh tử kiếp Chướng Tôn năm xưa. Sau khi khôi phục tu vi và có thân thể mới, sáng lập Xích Hồn giáo. Dùng hơn vạn con rối huyết sắc phóng huyết quang ăn mòn trận pháp cấm chế Tiên giới, đã tổn hại hơn phân nửa, còn hai ngày nữa sẽ phá xong. Đánh trọng thương Lam Mộng Đạo Tôn, đánh tan thân thể Nam Vân Tử. Toan tính hút máu huyết toàn bộ tu sĩ Tiên giới đạt Kim Tôn, về Tiên Cương đại lục nương nhờ Đạo Nhất Đại Thiên Tôn.","anchor":"Năm đó Vương Lâm trong sinh tử kiếp của Chướng Tôn thả một hồn phách bị Diệp Mịch phong ấn ra"},{"chuong":"@c1963","importance":"normal","mucCt":"gon","tieuDe":"Khôi phục đỉnh phong, bị Vương Lâm coi như kiến","text":"Tu vi đã khôi phục hoàn toàn đạt đỉnh phong, đang ở bên ngoài Tiên giới với sắc mặt kiêu ngạo, nhưng trong mắt Vương Lâm hiện tại chỉ yếu ớt như con kiến.","anchor":"đối phương dù yếu nhưng đối với Vương Lâm cũng mãnh tới kinh người. Nhưng lúc này tu vi của đổi phương khôi phục hoàn toàn, đạt tới đỉnh phong thì trong mắt Vương Lâm lại yếu ớt như một con kiến hôi"},{"chuong":"@c1964","importance":"normal","mucCt":"ky","tieuDe":"Phá trận pháp Tiên giới, đối mặt Hải Long","text":"Sau mấy ngày ăn mòn, phá vỡ trận pháp bảo hộ Tiên giới mở lỗ thủng khổng lồ. Đệ tử hồng bào xông vào bị Thập Tam giết. Xích Hồn Tử đích thân xông tới tấn công Vương Lâm, tự tin với tu vi Không Kiếp, coi Vương Lâm là con kiến. Nhưng khi thấy Kim Tôn Hải Long khôi phục bản thể vạn trượng lao tới thì kinh hãi sững sờ.","anchor":"Xích Hồn Tử cảm thấy như mình đang nằm mơ"},{"chuong":"@c1966","importance":"major","mucCt":"ky","tieuDe":"Tâm thần sụp đổ, bị Vương Lâm hủy diệt hoàn toàn","text":"Không chấp nhận sự thật, liên tục gào rằng tất cả là giả, viện dẫn mối quan hệ bạn bè cũ với La Minh (thị vệ Tiên Hoàng) cầu sống. Bị uy áp Đại Thiên Tôn Chi Dương bao trùm, nổi điên khi nhận ra mình đã dám có ý đồ với người luyện hóa hồn phách Tiên Hoàng, dám thu hậu nhân Đại Thiên Tôn làm đệ tử rồi khiến phản kháng — thân thể tan nát, nguyên thần diệt vong, tâm thần bị hủy diệt từ trong ra ngoài.","anchor":"Hắn không thể tiếp nhận sự tật này. Hắn không dám nghĩ là mình lại dám có ý đồ với một người có thể luyện hóa cả hồn phách Tiên Hoàng"}],"tuViMoc":[],"nhanMach":[{"ten":"Diệp Mịch","tag":"doi-thu","quanHe":"Người phong ấn hồn phách Xích Hồn Tử năm xưa, Xích Hồn Tử căm hận sâu sắc"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người thả hồn phách Xích Hồn Tử ra, cũng là kẻ hắn e ngại và muốn dùng Đại Thiên Tôn đối phó"},{"ten":"Đạo Nhất Đại Thiên Tôn","tag":"dong-minh","quanHe":"Đại Thiên Tôn tiên tộc mà Xích Hồn Tử toan tính nương nhờ sau khi đạt Thiên Tôn"},{"ten":"Đệ tử Xích Hồn Tử","tag":"su-mon","quanHe":"Đệ tử thân truyền, hậu nhân đời rất xa của Vương Lâm"},{"ten":"Nam Vân Tử","tag":"doi-thu","quanHe":"Tu sĩ Tiên giới bị Xích Hồn Tử đánh tan thân thể"},{"ten":"Lam Mộng Đạo Tôn","tag":"doi-thu","quanHe":"Tu sĩ Tiên giới bị Xích Hồn Tử đánh trọng thương"},{"ten":"Mộc Băng Mi","tag":"khac","quanHe":"Bị Xích Hồn Tử tuyển chọn làm đạo lữ cho đệ tử, toan dạy dỗ trước khi đưa"},{"ten":"Tuần Sơn Thanh","tag":"su-mon","quanHe":"Tự xưng là sư thúc, nói là Thiên Tôn dưới trướng Đạo Nhất, nhưng Đạo Nhất phủ nhận","ghiChu":"@c1965"},{"ten":"La Minh","tag":"ban-be","quanHe":"Hảo hữu cũ, thị vệ thân tín Tiên Hoàng, từng được Xích Hồn Tử cứu mạng","ghiChu":"@c1966"},{"ten":"Tiên Hoàng","tag":"khac","quanHe":"Chủ nhân của La Minh, Xích Hồn Tử từng dám có ý đồ với Đại Thiên Tôn liên quan tới hắn","ghiChu":"@c1966"}],"tuiDo":{}},"nguon":["@c1962","@c1963","@c1964","@c1965","@c1966"]},{"id":"de-tu-xich-hon-tu","name":"Đệ tử Xích Hồn Tử","cn":"","aliases":["thanh niên họ Vương"],"gioiTinh":"nam","theLuc":[{"ten":"Xích Hồn Giáo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Hậu nhân đời rất xa của Vương Lâm, được Xích Hồn Tử thu nhận làm đệ tử. Tư chất bất phàm, tàn nhẫn, cung kính phục vụ sư tôn.","vaiTro":"Đệ tử thân truyền của Xích Hồn Tử, hậu nhân Vương Lâm","tinhCach":"Cung kính với sư tôn; tàn nhẫn; háo sắc","tabs":{"diem":[{"text":"Là hậu nhân đời rất xa của Vương Lâm nhưng theo Xích Hồn Tử, coi hồng nhan tổ tiên (Mộc Băng Mi) là vật hưởng thụ.","chuong":"@c1962"}],"kinhLich":[{"mucCt":"vua","text":"Hư ảnh đối đầu Nam Vân Tử trên bầu trời Tiên giới, khinh thường, đòi sư tôn ban Nguyên thần Nam Vân Tử. Sẵn sàng nhận Mộc Băng Mi làm đạo lữ theo sắp đặt của sư tôn.","anchor":"Nghe nói kẻ này là hậu nhân đời rất xa của Vương Lâm","bridge":true,"khoang":"@c1962"}],"tuViMoc":[],"nhanMach":[{"ten":"Xích Hồn Tử","tag":"su-mon","quanHe":"Sư tôn, người thu nhận và truyền dạy"},{"ten":"Vương Lâm","tag":"ho-hang","quanHe":"Tổ tiên đời rất xa"},{"ten":"Mộc Băng Mi","tag":"khac","quanHe":"Được sư tôn tuyển chọn làm đạo lữ cho hắn"},{"ten":"Nam Vân Tử","tag":"doi-thu","quanHe":"Đòi sư tôn ban Nguyên thần của Nam Vân Tử"}],"tuiDo":{}},"nguon":["@c1962","@c1964"]},{"id":"diep-mich","name":"Diệp Mịch","cn":"叶灭","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1962","importance":"bridge","mucCt":"gon","text":"Được Xích Hồn Tử nhắc tới: đã chết, nhưng truyền thừa vẫn tồn tại, Xích Hồn Tử muốn đệ tử đạt được truyền thừa của Diệp Mịch.","anchor":"Diệp Mịch đã chết, nhưng nếu ngươi có thể đạt được truyền thừa của Diệp Mịch"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Trong vùng đất cổ mộ từng hóa thân thể khổng lồ chém giết, khí tức biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu, nhưng bị bắn rơi mắt trái khiến truyền thừa không hoàn chỉnh","chuong":"@c1481"},{"text":"Khí tức Đạo Cổ bùng phát từ chín quan tài trên tấm bia đá khổng lồ, biến đổi giữa ba dạng Cổ Thần – Cổ Ma – Cổ Yêu","chuong":"@c1576"},{"text":"Nguyên thần ẩn trong huyết ngưng tụ thành thực chất, mưu đoạt xá Vương Lâm nhưng thất bại và tiêu tán vĩnh viễn","chuong":"@c1672"},{"text":"Trái tim khổng lồ trăm trượng ở tầng cuối cổ mộ — di thể cuối cùng mang thần niệm thê lương oán hận — được truyền thừa cho Vương Lâm","chuong":"@c1680"},{"text":"Truyền thừa vẫn thiếu phần mắt trái chưa tìm được, khiến ký ức Vương Lâm nhận từ Diệp Mịch chưa trọn vẹn","chuong":"@c1729"},{"text":"Được Vương Lâm dùng làm mốc suy xét hệ thống lực lượng Cổ Tộc, thực lực được xem là tương đương Thiên Tôn","chuong":"@c1903"}]},"nguon":["@c1962"],"vaiTro":"Đạo Cổ — chủ nhân cổ mộ truyền thừa, nguồn gốc sức mạnh thể chất mà Vương Lâm thừa kế","tinhCach":"kiên ngạnh bất khuất, dù thất bại vẫn lưu lại truyền thừa cho hậu nhân; mưu tính thâm viễn, ẩn giấu nguyên thần trong huyết mưu đoạt xá người thừa kế; oán niệm dai dẳng, thần niệm thê lương tồn tại đến tận di thể cuối cùng","blurb":"Diệp Mịch, được gọi là Đạo Cổ, là chủ nhân vùng đất cổ mộ và nguồn gốc toàn bộ truyền thừa thể chất mà Vương Lâm tiếp nhận. Năm xưa từng hóa thân thể khổng lồ chém giết trong cổ mộ, khí tức biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu, nhưng bị bắn rơi mắt trái khiến truyền thừa không hoàn chỉnh; di thể gồm đầu lâu, hai cánh tay, trái tim cùng lầu các địa phủ chứa ba thần hồn lần lượt được Vương Lâm dung hợp. Nguyên thần ẩn trong huyết từng mưu đoạt xá Vương Lâm nhưng thất bại và tiêu tán vĩnh viễn; trái tim khổng lồ trăm trượng ở tầng sâu nhất cổ mộ mang thần niệm oán hận trở thành di sản truyền th"},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","cn":"许立国","aliases":[],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1963","importance":"normal","mucCt":"gon","tieuDe":"Được triệu ra Tiên giới, đắc ý vì từng qua Tiên Cương","text":"Được Vương Lâm triệu ra tại Tiên giới cùng Lưu Kim Bưu và Thập Tam, thần sắc đắc ý vì vừa đi qua Tiên Cương đại lục trở về.","anchor":"Mơ hồ Vương Lâm thấy thần sắc của hai người này có vẻ rất tự đắc"},{"chuong":"@c1964","importance":"bridge","mucCt":"gon","text":"Ở đằng xa cùng Lưu Kim Bưu lôi kéo một vài tu sĩ Tiên giới nói chuyện, khi Xích Hồn Tử xông tới thì ngẩng đầu nhìn với vẻ khinh miệt.","anchor":"Hứa Lập Quốc và Lưu Kim Bưu kia khi ngẩng đầu trong mắt lộ ra một vẻ khinh miệt"},{"chuong":"@c1966","importance":"bridge","mucCt":"gon","text":"Cùng rời Tiên giới với Vương Lâm.","anchor":"Hứa Lập Quốc rời đi"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc, ép nguyên thần thành ma đầu Trúc Cơ hậu kỳ đỉnh giả đan","chuong":"@c0112"},{"text":"Cản đòn bảo vệ thân thể Vương Lâm trước người khổng lồ băng tuyết, chiến đấu tới kiệt sức","chuong":"@c0338"},{"text":"Phản chủ chém đứt cánh tay trái Cự Ma lão tổ rồi tự nguyện quay về theo Vương Lâm","chuong":"@c0373"},{"text":"Được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ, trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm","chuong":"@c0596"},{"text":"Bị giam trong lốc xoáy lửa ba năm liên tục kháng cự, thực lực tăng mạnh","chuong":"@c1018"},{"text":"Khôi phục ký ức tiền kiếp trước lúc rời Tổ Thành, nhận lại Vương Lâm làm chủ nhân","chuong":"@c1881"}]},"nguon":["@c1963","@c1964","@c1966","@c1968"],"vaiTro":"Ma đầu bị Vương Lâm khống chế — kiếm linh đời thứ nhất của Vũ tiên kiếm","tinhCach":"Kiêu ngạo, hay lải nhải đòi đảo chủ tớ nhưng luôn bị trấn áp khuất phục; si mê nữ sắc tới mức mất tự chủ; nhát gan tính toán phản bội song cuối cùng vẫn quay về theo chủ; thực dụng giỏi nịnh nọt để tự bảo toàn","blurb":"Hứa Lập Quốc vốn là tu sĩ Nguyên Anh kỳ của Thiên Cương Tông, bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc rồi ép nguyên thần thành ma đầu. Trải qua hàng loạt biến cố, hắn lần lượt làm tay sai giám sát, kiếm hồn trong tiên kiếm, được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ mà trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm. Về sau hắn được đưa tới Tiên Cương, trải qua đầu thai chuyển thế mất rồi khôi phục ký ức, tiếp tục nhận Vương Lâm làm chủ và đi theo tới Tiên giới."},{"id":"luu-kim-buu","name":"Lưu Kim Bưu","cn":"刘金宝","aliases":[],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1963","importance":"normal","mucCt":"gon","tieuDe":"Được triệu ra Tiên giới cùng Hứa Lập Quốc","text":"Được Vương Lâm triệu ra tại Tiên giới cùng Hứa Lập Quốc và Thập Tam, thần sắc đắc ý giống Hứa Lập Quốc vì từng đi qua Tiên Cương đại lục.","anchor":"giống như vẻ mặt cực kỳ đắc ý của người từ địa phương lớn trở lại địa phương nhỏ vậy"},{"chuong":"@c1964","importance":"normal","mucCt":"vua","tieuDe":"Hải Long trên vai khôi phục bản thể chặn Xích Hồn Tử","text":"Ở Tiên giới cùng Hứa Lập Quốc lôi kéo tu sĩ nói chuyện. Khi Xích Hồn Tử xông tới, con rắn nhỏ trên vai rít gào kinh thiên, khôi phục bản thể thành Hải Long vạn trượng lao thẳng tới Xích Hồn Tử.","anchor":"Con rắn nhỏ kia nhanh chóng bay lên"}],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"dong-hanh","quanHe":"Đồng hành","ghiChu":"Cùng nhau ở Tiên giới"},{"ten":"Hải Long","tag":"khac","quanHe":"Hải Long ở trên vai hắn","ghiChu":"Mang Hải Long dạng rắn nhỏ"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Cùng phe Tiên giới","ghiChu":""},{"ten":"Hứa Lập Quốc","tag":"ban-be","quanHe":"Thường đi cùng nhau","ghiChu":""},{"ten":"Hải Long","tag":"dong-hanh","quanHe":"Hải Long ẩn dạng rắn nhỏ trên vai hắn","ghiChu":""}],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Dùng ngọc giản phóng khí tức Toái Niết phá tan hộ sơn đại trận Thiên Cương Tông, tống tiền cả tông môn","chuong":"@c1158"},{"text":"Giả dạng Chu Tước đời thứ sáu lừa lão tổ Hỏa Tước tộc, xâm nhập thánh địa trên Hỏa Tước tinh","chuong":"@c1335"},{"text":"Bị Vương Lâm tước tự do, quỳ dập đầu đến trán đầm đìa máu, bắt đầu làm nô bộc ngàn năm","chuong":"@c1474"},{"text":"Chuyển thế tại Tiên Cương, khôi phục ký ức hai đời và thức tỉnh nhận thức mới về đạo lừa gạt — hiểu lừa mình chính là bước thứ hai","chuong":"@c1848"},{"text":"Con rắn nhỏ Hải Long trên vai khôi phục bản thể, gào rít chặn đứng Xích Hồn Tử tại Tiên giới","chuong":"@c1964"}]},"nguon":["@c1963","@c1964","@c1965","@c1968"],"vaiTro":"Kẻ lừa đảo kỳ cựu — nô bộc ngàn năm của Vương Lâm, người ngộ đạo lừa gạt","tinhCach":"Xảo quyệt, chuyên giả mạo khí tức cường giả để tống tiền tông môn; Tham lợi nhưng biết sợ cường giả, quỳ gối cầu sinh không chút do dự; Dai dẳng theo đuổi đạo lừa gạt đến mức tự lừa chính bản thân, ký ức và nguyên thần cũng bị ảnh hưởng; Linh hoạt nương theo Vương Lâm để sinh tồn, dần chuyển từ kẻ b","blurb":"Lưu Kim Bưu, bí danh Kim Bưu Tử, là tu sĩ tu vi thực chỉ ở tầng Âm Hư nhưng nhờ ngọc giản chứa khí tức Toái Niết mà tung hoành lừa gạt các tông môn, từ Thiên Cương Tông tới Quy Nguyên Tông, cho đến khi bị Vương Lâm truy kích, mất bảo vật, rồi bị tước tự do làm nô bộc ngàn năm. Sau khi chuyển thế tại Tiên Cương dưới danh Kim Bưu đại tiên, lão khôi phục ký ức hai đời, thức tỉnh nhận thức mới về đạo lừa gạt — hiểu rằng lừa mình mới là cảnh giới cao nhất — rồi tiếp tục theo Vương Lâm xuyên suốt hành trình từ Đông Lâm Tông qua Tổ Thành đến Tiên giới, với con rắn nhỏ Hải Long trên vai trở thành vật "},{"id":"vuong-binh","name":"Vương Bình","cn":"王平","aliases":["Bình Nhi","A Ngốc"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1963","importance":"normal","mucCt":"gon","tieuDe":"Vương Lâm sắp xếp Mộng Đạo cho Bình nhi gặp mẫu thân","text":"Vương Lâm tuyên bố sẽ dùng Mộng Đạo thuật để Vương Bình được gặp mẫu thân Mộc Băng Mi trong một đời luân hồi trăm năm.","anchor":"Vương Bình cũng muốn có một mẫu thân. Ta sẽ thi triển Mộng Đạo thuật"},{"chuong":"@c1967","importance":"normal","mucCt":"vua","tieuDe":"Trưởng thành và lập nghiệp trong mộng cảnh luân hồi","text":"Trong mộng cảnh, Vương Bình là con trai Vương Lâm và Liễu Mi, thông minh lanh lợi, mười lăm tuổi rời sơn thôn đi thi đỗ đạt lên kinh thành, lập gia đình với Thanh Nghi. Sau khi cha mẹ qua đời, hắn cùng Thanh Nghi từ quan trở về mai táng, ở lại sơn thôn sống đến già.","anchor":"Hắn ngơ ngác nhìn cha mẹ ở trước mắt. rất lâu. rất lâu. trên mặt chảy xuống hai hàng lệ"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Xuất hiện dưới dạng oán anh trong màn sương đen, bị Liễu Mi luyện hóa trăm năm, sau được Vương Lâm nhận làm huyết mạch ruột thịt","chuong":"@c0636"},{"text":"Nhiều lần xin phụ thân cho tu đạo nhưng đều bị từ chối, cuối cùng chấp nhận cầu đạo chí tôn của phàm nhân","chuong":"@c0650"},{"text":"Từ thủ lĩnh Thiên Hành phái trở thành quân chủ lập nên Thiên Hành đế quốc","chuong":"@c0652"},{"text":"Cuối đời bị Lôi Đạo Tử nhìn thấu thân phận oán anh, tự xâu chuỗi chân tướng rồi tan thành hồn tức","chuong":"@c0659"},{"text":"Tiếng khóc lúc còn là oán anh kéo Vương Lâm khỏi nguy cơ, cứu phụ thân trong khoảnh khắc then chốt","chuong":"@c1813"},{"text":"Được Vương Lâm sắp xếp Mộng Đạo thuật để gặp mẫu thân Mộc Băng Mi trong mộng cảnh luân hồi trọn vẹn","chuong":"@c1963"}]},"nguon":["@c1963","@c1967","@c1975"],"vaiTro":"Con trai duy nhất của Vương Lâm — oán anh được ban một đời phàm nhân","tinhCach":"hiếu thuận và quyến luyến phụ thân; kiên trì khẩn cầu tu đạo dù nhiều lần bị cấm; trầm ổn trước hiểm nguy; biết tha thứ và buông bỏ lúc cuối đời","blurb":"Vương Bình vốn là oán anh trong màn sương đen trên Nhiễm Vân Tinh, bị Liễu Mi luyện hóa trăm năm, sau được Vương Lâm nhận làm huyết mạch ruột thịt và nuôi dưỡng như phàm nhân tại thôn Lạc Nguyệt. Hắn sống trọn một đời bên phụ thân — học điêu khắc, du ngoạn sơn xuyên, lập nên Thiên Hành đế quốc — rồi cuối đời bị Lôi Đạo Tử nhìn thấu thân phận oán anh và tan thành hồn tức. Sau đó Vương Bình vẫn tồn tại trong Thiên Nghịch Châu, trở thành nỗi day dứt lâu dài trong tâm thần và nhân quả của Vương Lâm, cho tới khi được phụ thân thu hồi vận mệnh và sắp xếp mộng cảnh luân hồi để gặp lại mẫu thân."},{"id":"hai-long","name":"Hải Long","aliases":["Kim Tôn"],"gioiTinh":"nam","vaiTro":"Tiên thú thủ hộ Đạo Ma Tông — tọa kỵ trung thành của Vương Lâm, tu vi tương đương Kim Tôn","tinhCach":"hung mãnh bản năng khi chưa quy thuận; trung thành tuyệt đối sau khi thần phục; kính sợ uy áp chủ nhân; thân thiết tình cảm với Lưu Kim Bưu","blurb":"Hải Long là tiên thú màu lam vạn trượng do lão tổ Thiên Tôn lưu lại trấn giữ hồ trung tâm Đạo Ma Tông, sở hữu tu vi tương đương Kim Tôn. Sau khi bị Vương Lâm dùng cấm chế phong ấn và hồn khí khuất phục, nó trở thành tọa kỵ trung thành, chở hắn xuyên sa mạc qua Địa Môn, Thiên Châu rồi đồng hành suốt hành trình Sơn Hải Châu, Đông Châu và Trung Châu. Hải Long nhiều lần hộ pháp bảo vệ thân thể Vương Lâm khi hắn bế quan, đỡ tên cứu Lưu Kim Bưu, và khôi phục bản thể vạn trượng phóng uy áp Kim Tôn chặn đứng cường giả bốn phương.","trangThai":"song","tabs":{"diem":[{"text":"Bị Vương Lâm dùng cấm chế phong ấn tại hồ trung tâm Đạo Ma Tông, sau đó giao hồn khí thần phục trở thành tọa kỵ trung thành","chuong":"@c1819"},{"text":"Chở Vương Lâm xuyên sa mạc tới Địa Môn, uy áp Kim Tôn khiến Trịnh Thiên Lâm kinh hãi, rồi tiếp tục qua Thiên Châu phóng uy áp tại Thiên Phong","chuong":"@c1830"},{"text":"Hộ pháp bảo vệ thân thể Vương Lâm trong động phủ Sơn Hải Châu và đối đầu hải thú bạch tuộc ngoài khơi suốt nhiều tháng","chuong":"@c1834"},{"text":"Đỡ mũi tên đen cắm vào bụng phá sinh cơ để cứu Lưu Kim Bưu khi chạy trốn trong Đông Thành, sau được Vương Lâm cứu chữa","chuong":"@c1869"},{"text":"Hộ pháp cho Vương Lâm trong lần cảm ngộ thứ ba tại Đông Lâm Tông, sau đột phá của Vương Lâm càng thêm kính sợ chủ nhân","chuong":"@c1853"},{"text":"Khôi phục bản thể Kim Tôn vạn trượng, rít gào kinh thiên chặn đứng Xích Hồn Tử khi hắn xông tới tấn công","chuong":"@c1964"}],"kinhLich":[{"chuong":"@c1964","importance":"major","mucCt":"vua","tieuDe":"Khôi phục bản thể Kim Tôn Hải Long vạn trượng chặn Xích Hồn Tử","text":"Bình thường ẩn dạng rắn nhỏ bằng ngón tay trên vai Lưu Kim Bưu. Khi Xích Hồn Tử xông tới, rít gào kinh thiên, khôi phục bản thể Hải Long khổng lồ dài vạn trượng lao thẳng tới Xích Hồn Tử. Được Xích Hồn Tử kinh hãi nhận ra là Kim Tôn Hải Long.","anchor":"Một con Hải Long khổng lồ dài vạn trượng ở trong thiên địa này rít gào lao thẳng tới Xích Hồn Tử"}],"nhanMach":[{"ten":"Lưu Kim Bưu","tag":"dong-hanh","quanHe":"Ở trên vai Lưu Kim Bưu","ghiChu":"Thu nhỏ thành rắn nằm trên vai"},{"ten":"Xích Hồn Tử","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Hiện nguyên hình chặn Xích Hồn Tử"}],"tuiDo":{},"tuViMoc":[]},"nguon":["@c1964","@c1968"]},{"id":"dao-nhat","name":"Đạo Nhất","cn":"道一","aliases":["Đạo Nhất Đại Thiên Tôn"],"gioiTinh":"nam","theLuc":[{"ten":"Đạo Nhất Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại Thiên Tôn","trangThai":"song","blurb":"Đạo Nhất (Đạo Khất) là Đại Thiên Tôn của tiên tộc, đứng đầu Đạo Nhất Tông. Bị Vương Lâm kích phát Trớ Thuật khiến huyết nhục bong tróc, hắn buộc phải giao đầu lâu trẻ con để thoát thân rồi về tông môn bế quan triệu tập Dược Tộc cứu chữa. Khi Vương Lâm đột phá Đại Thiên Tôn, Đạo Nhất từ phẫn nộ gầm thét chuyển sang sợ hãi, cuối cùng miễn cưỡng hợp lực thi triển thần thông nghịch chuyển tại chiến trường, rồi run rẩy trước uy áp của Vương Lâm và cung kính gọi Vương tôn.","vaiTro":"Đại Thiên Tôn tiên tộc — tông chủ Đạo Nhất Tông, bí danh Đạo Khất","tinhCach":"Tàn nhẫn, toan tính vì lợi kỷ; kiêu ngạo nhưng biết khuất phục trước thế lực mạnh hơn; hay do dự khi đối mặt biến cố lớn","tabs":{"diem":[{"text":"Bị Trớ Thuật bộc phát toàn diện, huyết nhục bong tróc, phải giao đầu lâu trẻ con cho Vương Lâm để thoát thân","chuong":"@c1896"},{"text":"Mang thân thể tàn tạ về Đạo Nhất Tông bế quan, triệu tập Dược Tộc trị thương","chuong":"@c1898"},{"text":"Phẫn nộ xen sợ hãi khi nhận ra Vương Lâm đã trở thành Đại Thiên Tôn","chuong":"@c1940"},{"text":"Do dự rồi đồng ý hợp lực thi triển thần thông nghịch chuyển tại chiến trường","chuong":"@c1954"},{"text":"Run rẩy trước uy áp Vương Lâm, cảm nhận rõ sự yếu ớt của bản thân","chuong":"@c1966"},{"text":"Cung kính vái Vương Lâm, gọi Vương tôn, không chần chừ khuất phục","chuong":"@c1970"}],"kinhLich":[{"chuong":"@c1966","importance":"normal","mucCt":"gon","tieuDe":"Run rẩy trước uy áp Vương Lâm","text":"Ở bên trong Đạo Nhất Tông tại Tiên Cương đại lục, cảm nhận rõ sự yếu ớt của mình khi dòng xoáy Vương Lâm tạo ra biến mất, run rẩy.","anchor":"Chỉ còn lại Đạo Nhất đang run rẩy bên trong Đạo Nhất Tông tại Tiên Cương đại lục"},{"chuong":"@c1970","importance":"bridge","mucCt":"gon","text":"Tới Thái Cổ Thần Cảnh, không chần chừ cung kính vái Vương Lâm gọi Vương tôn.","anchor":"Đạo Nhất tham kiến Vương tôn."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm khuất phục, cung kính gọi Vương Tôn, cảm giác sinh tử bị nắm trong tay","ghiChu":"@c1965"},{"ten":"Cổ Đế","tag":"khac","quanHe":"Từng coi Cổ Đạo là người mạnh nhất Tiên Cương, nay biết đã bị Vương Lâm vượt qua","ghiChu":"@c1965"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1965","@c1966","@c1970","@c1971"]},{"id":"tuan-son-thanh","name":"Tuần Sơn Thanh","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Thiên Tôn (theo lời Xích Hồn Tử, Đạo Nhất phủ nhận)","trangThai":"khong-ro","blurb":"Tên mà Xích Hồn Tử tự xưng là sư thúc của hắn, nói là Thiên Tôn dưới trướng Đạo Nhất Đại Thiên Tôn. Đạo Nhất phủ nhận có môn hạ này.","vaiTro":"Nhân vật được Xích Hồn Tử nhắc tên, tồn tại không xác thực","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Xích Hồn Tử xưng là sư thúc và Thiên Tôn dưới trướng Đạo Nhất, nhưng Đạo Nhất phủ nhận","chuong":"@c1965"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Xích Hồn Tử","tag":"su-mon","quanHe":"Xích Hồn Tử tự xưng là đệ tử sư huynh của hắn","ghiChu":"@c1965"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1965"]},{"id":"la-minh","name":"La Minh","cn":"罗明","gioiTinh":"nam","trangThai":"khong-ro","vaiTro":"Thị vệ thân tín của Tiên Hoàng, hảo hữu cũ của Xích Hồn Tử","tinhCach":"Trung thành với Tiên Hoàng","blurb":"Thị vệ thân tín của Tiên Hoàng (Liên Đạo Chân), từng được Xích Hồn Tử cứu mạng. Được Xích Hồn Tử viện dẫn quan hệ cũ để cầu sống trước Vương Lâm.","tabs":{"diem":[{"text":"Thị vệ thân tín của Tiên Hoàng, mối quan hệ cũ bị Xích Hồn Tử viện dẫn trong giây phút tuyệt vọng.","chuong":"@c1966"},{"text":"Thị vệ thân tín của Tiên Hoàng, từng là hảo hữu của Xích Hồn Tử","chuong":"@c1966"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Tiên Hoàng","tag":"cap-tren","quanHe":"Chủ nhân, La Minh là thị vệ thân tín","ghiChu":"@c1966"},{"ten":"Xích Hồn Tử","tag":"ban-be","quanHe":"Hảo hữu cũ, từng cứu mạng La Minh","ghiChu":"@c1966"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1966"],"canhGioiCaoNhat":"khong-ro","theLuc":[{"ten":"Tiên Hoàng triều đại","trangThai":"gan-bo"}]},{"id":"that-thai","name":"Thất Thải","cn":"","gioiTinh":"khong-ro","aliases":["Thất Thải Tiên Tôn"],"trangThai":"mat-tich","vaiTro":"Nhân vật thần bí, bí mật cuối cùng của động phủ giới","tinhCach":"Thần bí, bất khả truy vấn","blurb":"Nhân vật thần bí cùng Thiên Vận Tử là hai bí mật còn lại của động phủ giới mà Vương Lâm chưa giải đáp. Dấu vết tồn tại đã hoàn toàn biến mất.","tabs":{"diem":[{"text":"Cùng Thiên Vận Tử là hai bí mật cuối cùng của động phủ giới, dấu vết tồn tại đã biến mất hoàn toàn.","chuong":"@c1966"},{"text":"Nhân vật thần bí mà dấu vết tồn tại đã biến mất, là một trong hai bí ẩn cuối cùng của động phủ giới","chuong":"@c1966"}],"kinhLich":[{"chuong":"@c1966","importance":"normal","mucCt":"gon","tieuDe":"Dấu vết tồn tại biến mất","text":"Vương Lâm xác nhận dấu vết tồn tại của Thất Thải cùng Thiên Vận Tử đã hoàn toàn biến mất khỏi động phủ giới.","anchor":"đó là Thiên Vận Tử thần bí. là Thất Thải thần bí. Chẳng qua dấu vết của sự tồn tại của hai người này đã biến mất"}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Cùng là bí mật cuối cùng của động phủ giới","ghiChu":"@c1966"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người tìm kiếm bí mật về hắn","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1966"],"canhGioiCaoNhat":"khong-ro"},{"id":"tien-hoang","name":"Tiên Hoàng","aliases":["Liên Đạo Chân"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1966","importance":"normal","mucCt":"gon","tieuDe":"Khuôn mặt hiện trong Đại Thiên Tôn Chi Dương","text":"Khuôn mặt thật hiện rõ bên trong mặt trời Đại Thiên Tôn Chi Dương của Vương Lâm, lộ vẻ thống khổ vặn vẹo.","anchor":"ở bên trong Đại Thiên Tôn Chi Dương của Vương Lâm hiện lộ rõ ràng ra khuôn mặt thật của Tiên Hoàng"}],"diem":[{"text":"Bị chí bảo Thiên Nghịch đánh trọng thương, phải bế quan không màng thế sự","chuong":"@c1213"},{"text":"Dùng thánh chỉ và thân ảnh kim sắc buộc Lục Ma Châu cùng Thiên Ngưu Châu đình chiến, thể hiện uy quyền tuyệt đối","chuong":"@c1818"},{"text":"Sắc phong Vương Lâm tại Tiên Đạo Điện trong hoàng cung Trung Châu","chuong":"@c1875"},{"text":"Giải phong ấn Điệu Vong tộc bằng máu thịt hậu nhân Tiên Tổ, lộ mưu đồ đoạt xá đầu lâu Tiên Tổ","chuong":"@c1891"},{"text":"Tự bạo thân thể Đại Thiên Tôn trong mưu đồ đoạt xá thất bại, thực tế tử vong","chuong":"@c1893"},{"text":"Hồn phách bị Vương Lâm dung nhập vào đầu lâu Tiên Tổ, hòa vào Đại Thiên Tôn chi dương","chuong":"@c1926"}]},"nguon":["@c1966"],"vaiTro":"Bát Cực Đại Thiên Tôn — Tiên Hoàng Trung Châu, ca ca Liên Đạo Phi","tinhCach":"kiêu ngạo, trọng uy quyền, được xem là kiêu ngạo nhất trong các Đại Thiên Tôn; quyết đoán, ra tay dứt khoát; thâm trầm, giỏi bố cục mưu kế dài hạn; biết chuyển thái độ trước cục diện bất lợi","blurb":"Tiên Hoàng, tức Liên Đạo Chân, là Bát Cực Đại Thiên Tôn của Tiên Tộc, chủ nhân hoàng cung Trung Châu và truyền thừa Tiên Tổ Bát Cực đạo, được xem là kiêu ngạo nhất trong ngũ đại Đại Thiên Tôn. Từng bị chí bảo Thiên Nghịch đánh trọng thương phải bế quan, sau khi xuất quan hắn dùng thánh chỉ can thiệp chiến cuộc, sắc phong Vương Lâm, đồng thời âm thầm bày bố kế hoạch quanh đầu lâu Tiên Tổ cùng Điệu Vong tộc, lợi dụng huyết mạch hậu nhân để đoạt xá Tiên Tổ. Mưu đồ thất bại, hắn tự bạo thân thể Đại Thiên Tôn; hồn phách suy yếu sau đó bị Vương Lâm thu lấy rồi dung nhập vào đầu lâu Tiên Tổ, hòa vào "},{"id":"lao-to-cam-dia-chu-tuoc","name":"Lão Tổ Cấm Địa Chu Tước","aliases":["lão Chu Tước"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1966","importance":"normal","mucCt":"gon","tieuDe":"Được giải phong ấn vùng đất Điên Lạc","text":"Gặp lại Vương Lâm tại vùng đất Điên Lạc, được giải phong ấn — không còn bị nhốt vĩnh viễn, có thể tùy ý đi ra.","anchor":"Mấy ngày sau Vương Lâm giải khai phong ấn của vùng đất Điên Lạc"}],"diem":[{"text":"Ra lệnh Kiền Phong nuốt Hồng Điệp làm mồi luyện, sai Liễu Mi truy tìm Vương Lâm để đoạt Thiên Nghịch Châu và Tinh La Bàn","chuong":"@c0340"},{"text":"Triệu tám Tiên vệ và Tiên đế nghênh chiến Vương Lâm nhưng Tiên vệ áo đen bị hắn một chỉ Tịch Diệt diệt sát","chuong":"@c0577"},{"text":"Giảng giải bản chất Phá Không Ngũ Chỉ và con đường Niết Không bước thứ ba cho Vương Lâm","chuong":"@c1327"},{"text":"Ngầm lưu hư hỏa trên người Tư Mặc Tử qua ba cái tát, bố cục giúp Vương Lâm lập uy danh khi khiêu chiến","chuong":"@c1330"},{"text":"Truyền thụ Phần Giới Cổ Tán — thuật mạnh nhất Chu Tước tộc — với gần hai trăm vạn ấn ký qua bốn lần ấn quyết","chuong":"@c1336"},{"text":"Được Vương Lâm giải phong ấn tại vùng đất Điên Lạc, không còn bị nhốt vĩnh viễn, có thể tùy ý đi ra","chuong":"@c1966"}]},"nguon":["@c1966"],"vaiTro":"Lão tổ đời thứ hai của Chu Tước tộc — thế lực bí ẩn trong cấm địa Chu Tước Sơn","tinhCach":"Thủ đoạn lạnh lùng, xem sinh linh làm mồi luyện; toan tính thâm sâu, bố cục nhiều tầng từ trong cấm địa; trọng nhân tài, sẵn lòng truyền thụ tuyệt học cho kẻ xứng đáng; hành sự khó lường, khi cười đắc ý khi âm trầm ngưng trọng","blurb":"Lão tổ đời thứ hai của Chu Tước tộc, toàn thân phát hồng quang, ẩn cư trong cấm địa phía sau Chu Tước Sơn. Thuở đầu nuôi Hồng Điệp làm mồi cho Kiền Phong, ra lệnh truy tìm Vương Lâm để đoạt Thiên Nghịch Châu cùng Tinh La Bàn, thậm chí sai Tiên vệ và Tiên đế nghênh chiến hắn; về sau nhận ra tài năng của Vương Lâm nên chuyển sang trợ giúp — giảng giải con đường Niết Không bước thứ ba, trao Cổ Hồn Cấm, truyền thụ Phần Giới Cổ Tán tuyệt học mạnh nhất của Chu Tước tộc, và ngầm bố cục để hắn lập uy danh trước Tư Mặc Tử. Sau này gặp lại Vương Lâm tại Đan Hải, bị kiếm ý chấn thương và được hắn đưa tho"},{"id":"thac-sam","name":"Thác Sâm","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1966","importance":"normal","mucCt":"gon","tieuDe":"Tu luyện thần thông hóa trẻ con","text":"Thân hình hóa thành đứa trẻ, chìm trong trung tâm tinh cầu ngủ say. Vương Lâm suy đoán hắn cùng Đổ Ti đang tu luyện thần thông khiến thân hình hóa trẻ con để trưởng thành lại. Vương Lâm để lại thần niệm cho hắn khi thức tỉnh.","anchor":"Dáng vẻ của hắn rất giống Thác Sâm"},{"importance":"normal","mucCt":"vua","chuong":"@c1969","tieuDe":"Ngủ say trên tu chân tinh hình con mắt","text":"Đã hóa thành đứa trẻ đang ngủ say trên tu chân tinh hình con mắt ở giới ngoại tinh hải, hấp thụ linh lực từ bốn phía. Mí mắt run lên như sắp mở nhưng rồi lại bình tĩnh ngủ tiếp. Vương Lâm để lại ngọc giản do thần thức biến thành trước mặt chờ hắn tỉnh dậy.","anchor":"nhưng rất lâu sau. hắn thủy chung vẫn không mở mắt. mà dần dần lại bình tĩnh trở lại. vẫn ngủ say"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Lộ diện là kẻ đứng đầu huyết hải bị phong ấn mấy vạn năm trong Cổ Thần Chi Địa, thực chất là ma vật do oán niệm Cổ Thần Đồ Ti ngưng tụ","chuong":"@c0163"},{"text":"Trao bảo vật cho Vương Lâm nhờ phá phong ấn, thừa kế lực lượng truyền thừa bát tinh Cổ Thần Đồ Ti","chuong":"@c0430"},{"text":"Phá phong ấn, hóa huyết hải thành huyết long vạn trượng xông vào hư vô, thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ","chuong":"@c1060"},{"text":"Thức tỉnh sau trăm năm, phá trận pháp bay khỏi Chu Tước Tinh, quét ngang Liên Minh tinh vực truy tìm Vương Lâm","chuong":"@c1147"},{"text":"Trong trận chiến định mệnh tại cổ mộ, lần đầu bỏ xưng bổn thần, quỳ gối nhận truyền thừa Đồ Ti từ Vương Lâm và nói hai chữ đa tạ","chuong":"@c1386"},{"text":"Hóa thành đứa trẻ ngủ say trên tu chân tinh ở giới ngoại tinh hải, đang dung hợp ký ức Đồ Ti tu luyện thần thông","chuong":"@c1969"}]},"nguon":["@c1966","@c1969"],"trangThai":"song","cn":"拓森","vaiTro":"Phản diện trọng yếu — Cổ Ma Đồ Ti, ma vật chủ huyết hải bị phong ấn trong Cổ Thần Chi Địa","tinhCach":"Xảo trá, dùng bảo vật làm mồi nhử dụ dỗ Vương Lâm phá phong ấn; tàn nhẫn, khinh miệt chúng sinh như kiến và tàn sát hàng loạt tu sĩ không chớp mắt; cuồng ngạo đỉnh thiên, coi mọi thế lực đều không đáng kể; chấp niệm sâu nặng, liên tục khắc tên Vương Lâm và thề truy sát","blurb":"Thác Sâm là nam tử tóc đỏ như máu, kẻ đứng đầu huyết hải, thực chất là ma vật do oán niệm của Cổ Thần Đồ Ti chết ngưng tụ — tức Cổ Ma Đồ Ti — bị phong ấn mấy vạn năm trên thạch chùy giữa Cổ Thần Chi Địa. Hắn dùng bảo vật dụ dỗ Vương Lâm phá phong ấn, thừa kế lực lượng truyền thừa bát tinh Cổ Thần Đồ Ti, triệu hoán Diệt Thần Mâu và thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ, phá phong ấn bay khỏi Chu Tước Tinh quét ngang Liên Minh tinh vực, truy tìm Vương Lâm xuyên suốt nhiều tinh vực. Cuối cùng trong cổ mộ, sau trận chiến định mệnh với Vương Lâm, Thác Sâm lần đầu bỏ xưng bổn thần, qu"},{"id":"do-ti","name":"Đổ Ti","aliases":["Cổ thần Đồ Ti","Đổ Ti"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1966","importance":"bridge","mucCt":"gon","text":"Được nhắc đang cùng Thác Sâm tu luyện thần thông bí ẩn cần hóa trẻ con rồi trưởng thành lại.","anchor":"có lẽ Thác Sâm và Đổ Ti dường như đang tu luyện một loại thần thông nào đó"}],"diem":[{"text":"Phân thân xuất hiện sau khi Vương Lâm vượt qua thử thách Cấm Sơn, công nhận Vương Lâm là người lĩnh hội truyền thừa","chuong":"@c0160"},{"text":"Ký ức truyền thừa của hắn trở thành kho kiến thức cốt lõi cho Vương Lâm về Cổ Thần, pháp bảo và sinh linh, dù chưa trọn vẹn và còn bị phong ấn","chuong":"@c0927"},{"text":"Được xác nhận đến từ Thái Cổ Tinh Thần — nơi không có Phong giới trận, và năm xưa đơn độc mở ra không gian Cổ Thần Chi Địa","chuong":"@c1148"},{"text":"Thân thể vương tộc bát tinh tồn tại từ vạn cổ bị Thác Sâm chiếm giữ","chuong":"@c1383"},{"text":"Thức tỉnh trong thân xác Thác Sâm với vẻ trầm ổn tỉnh táo, triệu trường mâu đâm Chưởng Tôn","chuong":"@c1678"},{"text":"Thu thân hóa kích thước người thường, ngẩng đầu nắm tay, ở lại chặn Chiến lão quỷ cho Vương Lâm rời đi","chuong":"@c1680"}]},"nguon":["@c1966"],"vaiTro":"Cổ thần vương tộc bát tinh — nguồn truyền thừa Cổ Thần của Vương Lâm","tinhCach":"Thận trọng chọn người kế thừa; kiêu hãnh mang khí phách Cổ Thần; trầm ổn tỉnh táo khi thức tỉnh; sẵn sàng chặn địch cho Vương Lâm","blurb":"Đồ Ti là Cổ thần vương tộc bát tinh, chủ nhân Cấm Sơn trong Cổ Thần Chi Địa, xuất thân từ Thái Cổ Tinh Thần — nơi không có Phong giới trận. Hắn tự mình đơn độc mở ra không gian Cổ Thần Chi Địa, luyện chế ra Cổ Thần đại đỉnh và Tam Xoa Kích, đồng thời để lại truyền thừa ký ức cho Vương Lâm, giúp Vương Lâm nhận biết nhiều pháp bảo, sinh linh và quy luật Cổ Thần, dù phần ký ức ấy không trọn vẹn và còn bị phong ấn. Về sau thân thể Đồ Ti bị Thác Sâm chiếm giữ, song hắn từng thức tỉnh bên trong thân xác ấy, triệu xuất trường mâu đâm Chưởng Tôn và ở lại chặn Chiến lão quỷ cho Vương Lâm."},{"id":"thien-van-tu","name":"Thiên Vận Tử","aliases":["Thất Thải Tiên Tôn","quốc sư Đạo Cổ","khí linh La Bàn Định Giới"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1966","importance":"normal","mucCt":"gon","tieuDe":"Dấu vết tồn tại biến mất","text":"Vương Lâm xác nhận dấu vết tồn tại của Thiên Vận Tử thần bí đã hoàn toàn biến mất khỏi động phủ giới.","anchor":"đó là Thiên Vận Tử thần bí. là Thất Thải thần bí. Chẳng qua dấu vết của sự tồn tại của hai người này đã biến mất"},{"chuong":"@c1974","importance":"normal","mucCt":"ky","tieuDe":"Bị vạch trần là khí linh La Bàn Định Giới","text":"Bị Vương Lâm tuyên bố chân tướng: hắn không phải người bảo vệ mà là khí linh của La Bàn Định Giới, được phóng ra khi la bàn phân ra theo ý chí sát lục phân thân của Vương Lâm trong quá khứ. Thân thể run rẩy kịch liệt, tràn ngập sợ hãi khi phát hiện mọi thứ mình tưởng hiểu đều sai biệt quá lớn. Hắn phản bác bằng những gì tận mắt thấy: Vương Lâm lấy la bàn, chìm mộng đạo, luân hồi chuyển thế từng đời rồi vào la bàn tiêu tán. Nhận ra bày mưu cả đời mà tính sai hết, năm đó từ chỗ vỡ la bàn chui ra hóa ra nằm trong kế hoạch Vương Lâm. Cuối chương phát điên, thân thể hóa thành hắc vụ khổng lồ cao chọc trời lao tới muốn thôn phệ Vương Lâm.","anchor":"Thiên Vận Tử rống lên thể thảm, thân thể hóa thành hắc vụ khổng lồ cao chọc trời"},{"chuong":"@c1975","importance":"major","mucCt":"ky","tieuDe":"Tử vong, lai lịch khí linh La Bàn hé lộ","text":"Hóa sương đen rồi hạc đen lao về Vương Lâm trong nỗ lực phản kháng cuối cùng, bị Vương Lâm bóp nát. Hồi tưởng lai lịch: là khí linh của La Bàn Định Giới, từng tận mắt nhìn Vương Lâm luân hồi nhiều lần rồi tiêu tan, khi được phóng thích muốn đoạt xá Vương Lâm để đạt Cảnh Giới Đạp Thiên và có tự do. Biết La Bàn Định Giới có tác dụng giúp rời Nghịch Trẩn Giới. Trước khi thần thức tiêu tán hoàn toàn, nhớ lại quê hương Đạo Thần Trà. Thân thể hóa hắc khí, trong đó có đạo khí xám không mang khí tức của hắn bay vào Đạp Thiên Kiều.","anchor":"Quê hương của ta Thiên Vận Tử thì thào, toàn bộ thần thức tiêu"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Lần đầu xuất hiện cưỡi tảng đá khổng lồ như sao băng ngang Chu Tước tinh, cứu Vương Lâm khỏi lạc vào cảm ngộ thiên đạo luân hồi, thể hiện tu vi vượt Hóa Thần","chuong":"@c0241"},{"text":"Nhận Vương Lâm làm đệ tử chân chính trong đại thọ vạn năm, mở tâm thần thành thế giới bảy màu chứa 3600 phân thân cho Vương Lâm tự chọn cấm pháp thần thông","chuong":"@c0474"},{"text":"Chủ động hiến phân hồn để đoạt cấm chế bổn nguyên của Vương Lâm, tiết lộ Luân Hồi Toàn Thể Thuật — âm mưu hai ngàn năm bố cục nhằm chiếm cứ thân xác đệ tử","chuong":"@c1624"},{"text":"Bị phơi bày chân tướng: không phải tam hồn thất phách Thất Thải Tiên Tôn mà là thực thể nguyên thủy đã nuốt phách Thất Thải, bổn tôn là nửa nghịch la bàn — một bộ phận của Thiên Đạo","chuong":"@c1628"},{"text":"Hoàn thành thức tỉnh thứ chín mươi chín, thi triển Luân Hồi nhất thể thuật chiếm cứ phân thân Vương Lâm, nhưng bị Vương Lâm đoạt nửa la bàn bổn tôn và đánh bại","chuong":"@c1629"},{"text":"Bị vạch trần là khí linh La Bàn Định Giới, phản kháng lần cuối dưới dạng hạc đen rồi bị Vương Lâm bóp nát tiêu diệt hoàn toàn","chuong":"@c1975"}]},"nguon":["@c1966","@c1968","@c1973","@c1974","@c1975"],"trangThai":"tu-vong","cn":"天运子","vaiTro":"Chưởng môn Thiên Vận Tông — bộ phận Thiên Đạo, bổn tôn là nửa nghịch la bàn / khí linh La Bàn Định Giới","tinhCach":"Giỏi tính toán thiên cơ và bố cục dài hạn qua hàng ngàn năm; điềm tĩnh uy nghi khi chủ trì tông môn, giảng đạo; tự tin quyết liệt trước cường địch; che giấu dã tâm thôn phệ dưới thân phận sư tôn","blurb":"Thiên Vận Tử là chưởng môn Thiên Vận Tông, thành viên Liên Minh Trưởng Lão Đoàn, từng nhận Vương Lâm làm đệ tử chân chính nhưng âm thầm bố cục qua lạc ấn, phân hồn và Luân Hồi Toàn Thể Thuật suốt hai ngàn năm. Chân tướng về sau phơi bày: hắn không phải tàn hồn Thất Thải Tiên Tôn mà là thực thể nguyên thủy đã nuốt phách Thất Thải — bổn tôn là nửa nghịch la bàn, một bộ phận của Thiên Đạo, đồng thời là khí linh La Bàn Định Giới. Sau lần thức tỉnh thứ chín mươi chín và ý đồ chiếm cứ phân thân Vương Lâm, hắn bị Vương Lâm đoạt bổn tôn rồi tiêu diệt hoàn toàn."},{"id":"tan-linh-thuong-nhan","name":"Tán Linh thượng nhân","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1966","importance":"normal","mucCt":"gon","tieuDe":"Gặp lại Vương Lâm ở giới ngoại","text":"Vương Lâm gặp lại Tán Linh thượng nhân cùng bằng hữu ở giới ngoại, cảm động.","anchor":"Vương Lâm thấy Tán Linh thượng nhân, thấy được bằng hữu khiến hắn cảm động"}],"diem":[{"text":"Hiện thân sau khi Vương Lâm rời đi, xin mang thi thể tu sĩ Âm Hư, bộc lộ thân phận dị thường","chuong":"@c1264"},{"text":"Bị Vương Lâm phát hiện và phóng tia chớp hồng sắc xuyên mi tâm kích bản thể, lộ diện xưng danh Tán Linh, tiết lộ chân tướng bảy trăm vạn thiên địa","chuong":"@c1267"},{"text":"Tu vi đạt Thiên Nhân Tứ Suy sau vài ngàn năm điên cuồng tu luyện, lập Tán Linh Tông chiêu mộ tộc nhân phản kháng sấm sét bất diệt","chuong":"@c1268"},{"text":"Mở Tuyệt Thiên trận, dùng thân thể tộc nhân bị phong ấn làm mảng lưới ánh sáng chịu sấm sét bất diệt, trọng thương phun máu","chuong":"@c1271"},{"text":"Dẫn tộc nhân thoát khỏi bảy trăm vạn thiên địa đang sụp đổ vào Thái Cổ Tinh Thần, tuyên thệ trung thành với Vương Lâm","chuong":"@c1273"},{"text":"Gặp lại Vương Lâm cùng bằng hữu ở giới ngoại","chuong":"@c1966"}]},"nguon":["@c1966"],"vaiTro":"Thủ lĩnh Tán Linh Tông — cường giả bí ẩn phản kháng sấm sét bất diệt trong bảy trăm vạn thiên địa","tinhCach":"Hiền lành bề ngoài nhưng tự tin cao độ; bình thản, quan sát sắc bén trước cường giả; kiên định phản kháng, sẵn sàng hy sinh vì tộc nhân","blurb":"Thanh niên đầu trọc láng bóng, vẻ mặt hiền lành, tồn tại hơn vạn năm trong bảy trăm vạn thiên địa, tu vi đạt tới Thiên Nhân Tứ Suy — điều gần như bất khả trong thế giới bị phong tỏa bởi sấm sét bất diệt. Sau khi phá phong hộ tu chân tinh lần đầu nhìn thấy tinh không và phát hiện chân tướng thế giới, y lập Tán Linh Tông chiêu mộ tộc nhân phản kháng, mở Tuyệt Thiên trận đối đầu sấm sét bất diệt, dẫn tộc nhân thoát khỏi thiên địa đang sụp đổ vào Thái Cổ Tinh Thần và thề trung thành với Vương Lâm. Về sau gặp lại Vương Lâm ở giới ngoại."},{"id":"lieu-mi","name":"Liễu Mi","aliases":["Mộc Băng Mi","Mộc Ngung","Côn Hư thánh nữ"],"tabs":{"kinhLich":[{"mucCt":"ky","text":"Trong mộng cảnh luân hồi, nàng là con gái Liễu gia giàu có, thanh mai trúc mã với Vương Lâm, thành thân với hắn. Nàng yêu thương chồng con trọn đời, dành hết tình cảm cho con trai Vương Bình. Hai vợ chồng già đi cùng nhau, tóc bạc trắng. Khi lâm chung, nàng nói chuyện suốt đêm với Vương Lâm, kể về thời ấu thơ, hồi quang phản chiếu nhìn lên bầu trời thấy bản thân và Vương Lâm là tiên nhân — nàng bật khóc vì đau lòng. Nàng dặn Vương Lâm chăm sóc Vương Bình, rồi hai người mỉm cười ra đi cùng nhau. Tỉnh lại trong động phủ bên Vương Lâm, nàng rơi lệ hỏi kết thúc rồi sao, rồi theo lời hắn nhắm mắt mở ra — nàng đã nhìn thấy.","anchor":"Mộc Băng Mi kinh ngạc nhìn Vương Lâm. nàng không biết những lời này của Vương Lâm là có ý gì","bridge":true,"khoang":"@c1967"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Phân thân lặng lẽ ném lệnh bài cho Vương Lâm không nói một lời rồi thở dài nhìn hắn rời đi, thể hiện tình cảm kín đáo từ thuở đầu","chuong":"@c0093"},{"text":"Được xác nhận là đệ tử chân truyền Chu Tước Tử, sư muội Kiền Phong, một trong bốn người được chọn kế thừa danh hiệu","chuong":"@c0374"},{"text":"Được Lão tổ Huyễn gia thu làm nghĩa nữ với danh Huyễn Mi, nhờ Hoán huyết đại pháp đạt Vấn Đỉnh hậu kỳ đại viên mãn","chuong":"@c0633"},{"text":"Bị Huyễn Vô Tình cắn nuốt ý cảnh, trở thành vật hy sinh trong xung đột giữa Huyễn gia và Vương Lâm","chuong":"@c0643"},{"text":"Xác định là Thánh nữ đời thứ bảy của Côn Hư chi cảnh với danh Mộc Băng Mi, gắn với bí mật Thiên Hồn","chuong":"@c0993"},{"text":"Vương Lâm thừa nhận Liễu Mi là người đi vào lòng hắn bằng đau đớn, hình bóng nàng trở thành vết thương không thể xóa trong đạo tâm","chuong":"@c1107"}]},"nguon":["@c1967"],"vaiTro":"Thiên đạo bí ẩn — Thánh nữ Côn Hư, nghĩa nữ Huyễn gia, người khắc sâu trong đạo tâm Vương Lâm","tinhCach":"nặng lòng với Vương Lâm nhưng cam chịu không đòi hỏi, lặng lẽ bảo vệ từ xa; kiên định phụng lệnh sư tôn dù biết bị lợi dụng; hành sự quyết liệt khi cần, sẵn sàng luyện oán ảnh để hoàn thành mục đích; cao ngạo lạnh lùng bề ngoài nhưng nội tâm cô độc hiu quạnh","blurb":"Liễu Mi là một thiên đạo sở hữu hàng nghìn phân thân cảm ngộ thiên đạo khắp các nước, bản thể tu luyện trong Hàn Đàm cấm địa phía sau Chu Tước Sơn; nàng mang nhiều thân phận xuyên suốt truyện — đệ tử chân truyền Chu Tước Tử, sư muội Kiền Phong, Thánh nữ đời thứ bảy của Côn Hư chi cảnh với danh Mộc Băng Mi, và nghĩa nữ Lão tổ Huyễn gia với danh Huyễn Mi. Tình cảm đơn phương với Vương Lâm khiến nàng nhiều lần chủ động cảnh báo và bảo vệ hắn, nhưng cũng đưa nàng vào trung tâm xung đột giữa Huyễn gia và Vương Lâm tại La Thiên tinh vực; về sau hình bóng nàng trở thành vết thương không phai trong đạ"},{"id":"thanh-nghi","name":"Thanh Nghi","tabs":{"kinhLich":[{"chuong":"@c1967","importance":"bridge","mucCt":"gon","text":"Trong mộng cảnh luân hồi, Thanh Nghi là thê tử hiếu thuận của Vương Bình, cùng hắn từ quan trở về sơn thôn sống trọn đời sau khi Vương Lâm và Liễu Mi qua đời.","anchor":"Đây là một nữ tử rất xinh đẹp, là con gái của một gia đình giàu có ở kinh thành"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Che giấu họ Vương Bình trước chi nhánh Tôn gia dù bị uy hiếp, thể hiện lòng trung thành ngay từ đầu","chuong":"@c0650"},{"text":"Bị phong tỏa tu vi và đưa đến phòng Vân Vô Phong sau khi bị đuổi khỏi Tôn gia, được Vương Lâm xuất hiện giải cứu","chuong":"@c0651"},{"text":"Ở bên Vương Bình nhiều năm, chăm sóc và cùng hắn trở lại thôn Lạc Nguyệt viếng mộ Tôn Thái","chuong":"@c0653"},{"text":"Được Vương Lâm nâng tu vi tới Nguyên Anh hậu kỳ đại viên mãn, nhưng chọn ở bên Vương Bình tới cuối đời với tình cảm phàm nhân","chuong":"@c0654"},{"text":"Chắn trước Vương Bình khi bị thần thức Lôi Đạo Tử tấn công, phun máu vì nguyên thần mới hình thành không lâu","chuong":"@c0655"},{"text":"Quỳ xin Vương Lâm dẫn mình theo sau khi chứng kiến Vương Bình tan đi, khẳng định không hối hận","chuong":"@c0659"}]},"nguon":["@c1967"],"vaiTro":"Bạn đời phàm nhân của Vương Bình — người chọn tình yêu thay vì tu tiên","tinhCach":"trọng tình nghĩa, sẵn sàng từ bỏ tiền đồ tu luyện vì tình cảm; kiên định với lựa chọn, không hối hận dù phải chịu thiệt thòi; biết che chở người thân cận, dám chắn thân trước nguy hiểm","blurb":"Thanh Nghi vốn bị cuốn vào biến cố tửu lâu Kỳ Thủy thành và chi nhánh Tôn gia, sau đó bị phong tỏa tu vi và đuổi đi, nhưng được Vương Lâm giải cứu rồi tự nguyện ở bên chăm sóc Vương Bình suốt nhiều năm. Dù từng được Vương Lâm nâng tu vi tới Nguyên Anh hậu kỳ đại viên mãn, nàng vẫn chọn tình yêu phàm nhân bên Vương Bình cho tới cuối đời hắn, rồi quỳ xin Vương Lâm dẫn mình theo khi Vương Bình tan đi. Hồn phách nàng sau đó được xác nhận vẫn còn tồn tại bên trong Thiên Nghịch Châu."},{"id":"chung-dai-hong","name":"Chung Đại Hồng","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1968"]},{"id":"tay-tu-phuong","name":"Tây Tử Phượng","cn":"西子凤","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Đang đứng trên đỉnh núi một tu chân tinh trong La Thiên Tinh Vực, cảm nhận luồng thần thức quen thuộc của Vương Lâm quét tới rồi biến mất, nhận ngọc giản lơ lửng trước mặt. Dùng thần thức nghe thanh âm của Vương Lâm bên trong, mở mắt lộ nụ cười nhu hòa.","anchor":"Khí tức kia giống như là khắc sâu trong linh hôn, cả đời khó quên","bridge":true,"khoang":"@c1969"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Gặp Vương Lâm lần đầu giữa Lôi Tiên Giới sụp đổ, cung kính cảm tạ hắn hai lần cứu mạng","chuong":"@c0750"},{"text":"Đau lòng rơi lệ khi nhận ra Vương Lâm tranh phong tiên vì Lý Mộ Uyển","chuong":"@c0826"},{"text":"Tái xuất sau tám trăm năm với gia tộc bị diệt vong, dung nhan tự hủy thành sẹo để giữ khí tiết","chuong":"@c1395"},{"text":"Được Vương Lâm chữa lành thương thế, khôi phục dung mạo, truyền công bạo tăng tới Tinh Tịnh Niết và chính thức bái sư tôn","chuong":"@c1398"},{"text":"Nhận huyết kiếm bản mệnh từ Vương Lâm, mang theo sứ mệnh rửa nhục tám trăm năm","chuong":"@c1399"},{"text":"Xin Vương Lâm cho ở bên cạnh một năm trong đại chiến giới ngoại, lặng lẽ ấm rượu chờ hắn giữa trận tiền","chuong":"@c1573"}]},"nguon":["@c1969"],"vaiTro":"Nữ tu sĩ trọng tình, từng được Vương Lâm nhiều lần cứu giúp và sau bái hắn làm sư tôn","tinhCach":"biết cảm ân, cung kính tạ ơn và trung thành với ân nhân; trọng tình cảm, nhiều lần rung động trước Vương Lâm nhưng âm thầm chịu đựng; kiên cường chịu nhục, tự hủy dung nhan để giữ khí tiết; dễ tự ti trước khoảng cách thân phận","blurb":"Tây Tử Phượng là nữ tu sĩ lần đầu gặp Vương Lâm trong biến cố Lôi Tiên Giới sụp đổ, được hắn hai lần cứu mạng rồi mang theo tình cảm thầm kín qua cuộc tranh phong tiên tại Lôi Tiên Điện, nơi nàng chứng kiến hắn tranh đoạt vì Lý Mộ Uyển mà đau lòng rơi lệ. Tám trăm năm sau, nàng tái xuất với gia tộc đã bị diệt, dung nhan tự hủy thành vết sẹo, được Vương Lâm chữa lành thương thế, khôi phục dung mạo, truyền công cho tu vi bạo tăng tới Tinh Tịnh Niết, rồi chính thức bái hắn làm sư tôn và nhận huyết kiếm bản mệnh để rửa nhục. Trong đại chiến giới ngoại, nàng xin được ở bên cạnh Vương Lâm một năm, l"},{"id":"lao-gia-buc-tuong-da","name":"Lão già bức tượng đá","gioiTinh":"nam","aliases":["đệ tử Thất Thải Tiên Tôn"],"trangThai":"song","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"blurb":"Vốn là bức tượng đá ở dưới khe sâu trong Phong Tiên Giới, môn nhân đệ tử của Thất Thải Tiên Tôn, đến từ Thất Đạo Tông trên Đại Lục Tiên Cương. Đang tĩnh tọa trong vùng tinh hải của động phủ giới bức sức mạnh hóa thạch ra khỏi cơ thể.","vaiTro":"Đệ tử Thất Thải Tiên Tôn, bức tượng đá khe sâu Phong Tiên Giới năm xưa","tinhCach":"Kiên nhẫn; trung thành với sư môn","tabs":{"diem":[{"text":"Là bức tượng đá từng giúp Vương Lâm trong trận chiến với Thủy Đạo Tử ở Phong Tiên Giới","chuong":"@c1969"},{"text":"Đang tĩnh tọa trong tinh hải bức sức mạnh hóa thạch, cần ba trăm năm khôi phục để về quê hương","chuong":"@c1969"}],"kinhLich":[{"mucCt":"vua","text":"Đang tĩnh tọa trong vùng tinh hải đầy đá vụn của động phủ giới, bức sức mạnh hóa thạch ra khỏi cơ thể, cần thêm ba trăm năm nữa để khôi phục hoàn toàn và trở về quê hương. Nhận viên đan dược đỏ sẫm từ thần thức Vương Lâm gửi tới, sức mạnh hóa thạch trong cơ thể lập tức bị áp chế.","anchor":"Chỉ cần ba trăm năm nữa là lão phu sẽ có thể khôi phục lại","bridge":true,"khoang":"@c1969"}],"tuViMoc":[],"nhanMach":[{"ten":"Thất Thải Tiên Tôn","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Là môn nhân đệ tử của Thất Thải Tiên Tôn"},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân","ghiChu":"Từng giúp Vương Lâm chiến đấu với Thủy Đạo Tử, được Vương Lâm gửi đan dược giúp khôi phục"}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Viên đan dược đỏ sẫm","trangThai":"dang-co","moTa":"Vương Lâm gửi, áp chế sức mạnh hóa thạch trong cơ thể","nguon":"@c1969"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1969"]},{"id":"huyen-la","name":"Huyền La","mucCt":"vua","trangThai":"song","nguon":["@c1970","@c1971","@c1972"],"tabs":{"kinhLich":[{"chuong":"@c1970","importance":"normal","mucCt":"vua","tieuDe":"Được Vương Lâm chủ động vái sư tôn trước sáu Đại Thiên Tôn","text":"Già nua hơn trước, muốn vái chào Vương Lâm nhưng Vương Lâm chủ động vái trước gọi sư tôn, khiến Tống Thiên và Cực Cổ Đại Thiên Tôn chấn động rồi cũng tôn kính Huyền La hơn. Lo lắng khi tiếng ầm vang Thái Cổ Thần Cảnh bất thường, nhận xét lần trước chỉ xuất hiện một lần trong ngày cuối.","anchor":"Ta nhớ rõ lần trước Thái cổ Thần Cảnh mở ra, trong vòng một ngày trước khi mở ra cũng xuất hiện âm thanh mãnh liệt như thế này nhưng chỉ có một lần thôi."},{"chuong":"@c1972","importance":"normal","mucCt":"vua","tieuDe":"Nhận ngọc giản từ Vương Lâm, rời đi trước khi Thái Cổ Thần Cảnh mở","text":"Nhận ngọc giản từ đệ tử Vương Lâm để bảo vệ việc chuyển thế sắp tới, dặn dò Vương Lâm bảo vệ bản thân. Cùng Tống Thiên và Cực Cổ Đại Thiên Tôn hóa cầu vồng bay đi.","anchor":"Bảo vệ bản thân cho tốt"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Triệu hồi Tứ Đại Linh, hoàn thành con đường chuyển thế đầu thai thông tới Tiên Cương","chuong":"@c1696"},{"text":"Nhận Vương Lâm làm đệ tử duy nhất trên con đường mình rồng, dùng máu Cửu Dương bảo hộ và giao phó trọng trách bảo vệ Đạo Cổ nhất mạch","chuong":"@c1699"},{"text":"Âm thầm chuẩn bị ba nơi tạo hóa và pháp bảo cho đệ tử nhiều năm, đích thân dẫn Vương Lâm cầu kiến Cổ Đạo","chuong":"@c1909"},{"text":"Can thiệp trước hoàng quyền Đạo Cổ, bảo vệ địa vị đệ tử duy nhất khi Thường Thị ép Vương Lâm quỳ","chuong":"@c1908"},{"text":"Trả giá lão hóa thân thể, vung quyền xông vào Tổ Miếu cứu Vương Lâm trong lúc phân thần","chuong":"@c1946"},{"text":"Lặng lẽ rời đi sau khi chứng kiến đệ tử vượt tam phân thần Cổ Đạo, ba năm sau đón Vương Lâm và nhận ngọc giản chuẩn bị chuyển thế","chuong":"@c1949"}]},"vaiTro":"Đại Thiên Tôn Cửu Dương — sư tôn duy nhất của Vương Lâm tại Cổ Tộc","tinhCach":"Uy nghiêm nhưng nội tâm trọng nghĩa tình, sẵn sàng trả giá vì đệ tử; kiên nhẫn âm thầm chờ đợi và che chở nhiều năm không cần đệ tử biết; thận trọng biết tiến thoái trước thân phận nhạy cảm giữa các thế lực; cương quyết bảo vệ người mình nhận trước hoàng quyền và cường giả","blurb":"Huyền La là Đại Thiên Tôn cảnh Cửu Dương trấn giữ động phủ giới tại La Thiên tinh vực, người mở con đường chuyển thế đầu thai thông tới Tiên Cương và nhận Vương Lâm làm đệ tử duy nhất, dùng máu Cửu Dương bảo hộ và giao phó trọng trách bảo vệ Đạo Cổ nhất mạch. Suốt nhiều năm ông âm thầm chú ý mọi chuyện của đệ tử, chuẩn bị tạo hóa và pháp bảo, đích thân dẫn Vương Lâm cầu kiến Cổ Đạo, can thiệp trước hoàng quyền để bảo vệ hắn, và thậm chí trả giá lão hóa thân thể để xông vào Tổ Miếu cứu đệ tử. Sau khi chứng kiến Vương Lâm đột phá Đại Thiên Tôn và vượt qua tam phân thần Cổ Đạo, ông lặng lẽ rời đi"},{"id":"tong-thien","name":"Tống Thiên","mucCt":"gon","trangThai":"song","nguon":["@c1970","@c1971","@c1972"],"tabs":{"kinhLich":[{"chuong":"@c1970","importance":"bridge","mucCt":"vua","text":"Cùng Cực Cổ Đại Thiên Tôn cung kính gọi Vương Lâm là Vương tôn tại Thái Cổ Thần Cảnh, chấn động khi thấy Vương Lâm chân thành vái sư tôn Huyền La, sau đó cũng tôn kính Huyền La hơn.","anchor":"Tống Thiên tham kiến Vương tôn."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Đả tọa tại Nguyên Thủy Sơn với tư cách Đại Thiên Tôn Thủy Cổ nhất mạch, nhận Hoàng Man làm đệ tử","chuong":"@c1930"},{"text":"Khai mở Nguyên Thủy Trận trên Nguyên Thủy Sơn để đối phó Vương Lâm khi bị khóa cứng","chuong":"@c1939"},{"text":"Tung Nguyên Thủy Sơn và thi triển Nguyên Thủy trấn áp nhưng bại trận trước Vương Lâm, chấp nhận thua","chuong":"@c1941"},{"text":"Mở Tổ Miếu cho Vương Lâm, giới thiệu pho tượng Cổ Tổ do Cổ Đạo Đại Thiên Tôn điêu khắc","chuong":"@c1942"},{"text":"Khoanh chân trước Tổ Miếu hộ pháp cho Vương Lâm suốt ba năm để bồi thường chuyện năm xưa","chuong":"@c1945"},{"text":"Cùng Cực Cổ Đại Thiên Tôn cung kính gọi Vương Lâm là Vương tôn tại Thái Cổ Thần Cảnh","chuong":"@c1970"}]},"vaiTro":"Đại Thiên Tôn trấn thủ Thủy Cổ nhất mạch — từ đối thủ chuyển thành đồng minh của Vương Lâm","tinhCach":"Lạnh lùng quyết đoán, dám nghênh chiến dù biết bất lợi; biết thời thế, chịu nhận thua trước kẻ mạnh hơn; trọng lời hứa, sẵn sàng bồi thường lỗi lầm năm xưa","blurb":"Tống Thiên là Đại Thiên Tôn đả tọa tại Nguyên Thủy Sơn, trấn thủ Thủy Cổ nhất mạch trong nội bộ Cổ Tộc, từng nhận Đông Man hoàng tử Hoàng Man làm đệ tử và thiên vị hắn trong cuộc tranh đoạt hoàng tôn. Khi Vương Lâm tiến vào lãnh địa Cổ Tộc, Tống Thiên nghênh chiến bằng toàn lực — tung cả Nguyên Thủy Sơn và Nguyên Thủy trấn áp — nhưng bại trận, sau đó chủ động mở Tổ Miếu, hộ pháp ba năm cho Vương Lâm để bồi thường chuyện cũ, và cuối cùng cung kính tôn xưng Vương Lâm là \"Vương tôn\" tại Thái Cổ Thần Cảnh."},{"id":"cuc-co-dai-thien-ton","name":"Cực Cổ Đại Thiên Tôn","mucCt":"gon","trangThai":"song","nguon":["@c1970","@c1971","@c1972"],"tabs":{"kinhLich":[{"chuong":"@c1970","importance":"normal","mucCt":"gon","tieuDe":"Tập kết tại Thái Cổ Thần Cảnh, bái kiến Vương Lâm","text":"Cùng Tống Thiên và Huyền La tới gặp Vương Lâm, trầm mặc ôm quyền. Chấn động khi thấy Vương Lâm chân thành vái sư tôn Huyền La, sau đó cũng tôn kính Huyền La hơn.","anchor":"Tống Thiên tham kiến Vương tôn."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Cường giả đệ nhất Tiên Cương, cung kính gọi Vương tôn"},{"ten":"Huyền La","tag":"khac","quanHe":"Đồng liệt Đại Thiên Tôn Cổ tộc, sư tôn của Vương Lâm, sau tôn kính hơn"},{"ten":"Tống Thiên","tag":"dong-minh","quanHe":"Đồng liệt Đại Thiên Tôn Cổ tộc, cùng tới gặp Vương Lâm"}],"tuiDo":{},"diem":[{"text":"Đại Thiên Tôn thần bí của Cực Cổ Nhất Mạch, trầm mặc ôm quyền hướng Vương Lâm không nói thêm.","chuong":"@c1970"}]},"cn":"極古大天尊","aliases":["Đại Thiên Tôn Cực Cổ"],"canhGioiCaoNhat":"Đại Thiên Tôn","vaiTro":"Đại Thiên Tôn Cổ tộc thuộc Cực Cổ Nhất Mạch, tham gia tập kết tại Thái Cổ Thần Cảnh.","tinhCach":[{"text":"Trầm mặc, ít nói, hành lễ không đa ngôn"}],"blurb":"Đại Thiên Tôn cực kỳ thần bí của Cực Cổ Nhất Mạch trong Cổ tộc, trầm mặc ít nói.","gioiTinh":"nam","theLuc":[{"ten":"Cổ tộc","trangThai":"gan-bo"},{"ten":"Cực Cổ Nhất Mạch","trangThai":"gan-bo"}]},{"id":"vo-phong","name":"Võ Phong","mucCt":"gon","trangThai":"song","nguon":["@c1970","@c1971"],"tabs":{"kinhLich":[{"chuong":"@c1970","importance":"normal","mucCt":"vua","tieuDe":"Tái ngộ Vương Lâm tại Thái Cổ Thần Cảnh","text":"Cung kính vái Vương Lâm gọi Vương tôn, nói chuyện thân mật sau mấy trăm năm không gặp, cảm thán không ngờ tu vi Vương Lâm đạt tới trình độ này.","anchor":"Có mấy trăm năm rồi. không ngờ tu vi của Vương tôn lại đạt tới trình độ như vậy."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Trở về dòng sông băng Bắc Châu, đóng băng toàn thân để xua trừ Trớ Thuật","chuong":"@c1898"},{"text":"Sớm phát hiện Thái Cổ Thần Cảnh trên đất Tiên Tộc, đứng trên băng sơn chờ mong dị tượng","chuong":"@c1928"},{"text":"Ở hàn băng cực bắc, hoảng hốt nhìn bầu trời khi Vương Lâm thành Đại Thiên Tôn","chuong":"@c1940"},{"text":"Bay tới chiến trường, phát lời thề tham gia thần thông nghịch chuyển, chính thức nhập cuộc","chuong":"@c1954"},{"text":"Tái ngộ Vương Lâm tại Thái Cổ Thần Cảnh, cung kính gọi Vương tôn, cảm thán tu vi của Vương Lâm","chuong":"@c1970"}]},"vaiTro":"Đại Thiên Tôn tiên tộc — ẩn tu tại dòng sông băng Bắc Châu, mang Trớ Thuật trong người","tinhCach":"thận trọng, ít ra tay; âm trầm, hay quan sát và suy tư trước biến cố lớn","blurb":"Võ Phong là một Đại Thiên Tôn của tiên tộc, mang trong mình Trớ Thuật nhưng có điều kiện hóa giải nhẹ hơn nhờ ít ra tay, nên chọn cách đóng băng toàn thân trong dòng sông băng tại Bắc Châu để xua trừ. Hắn là người sớm phát hiện Thái Cổ Thần Cảnh xuất hiện trên đất Tiên Tộc, âm thầm theo dõi các biến cố thiên địa từ hàn băng cực bắc. Tới giai đoạn cuối, hắn bay tới chiến trường, phát lời thề tham gia thần thông nghịch chuyển và tái ngộ Vương Lâm tại Thái Cổ Thần Cảnh."},{"id":"cuu-de","name":"Cửu Đế","mucCt":"gon","trangThai":"song","nguon":["@c1970","@c1971","@c1972"],"tabs":{"kinhLich":[{"chuong":"@c1970","importance":"bridge","mucCt":"gon","text":"Tới Thái Cổ Thần Cảnh cùng Võ Phong và Đạo Nhất, do dự rồi ôm quyền hướng Vương Lâm nhưng không nói gì.","anchor":"Có mấy trăm năm rồi. không ngờ tu vi của Vương tôn lại đạt tới trình độ như vậy."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Hóa mặt trời trắng thành bạch lang chặn Vương Lâm, bị đánh bại bởi một cước Đại Thiên Tôn Chi Dương","chuong":"@c1896"},{"text":"Dùng Trớ Thuật trong thân làm lợi thế uy hiếp Vương Lâm, bác bỏ khả năng quy phục","chuong":"@c1897"},{"text":"Phong tỏa tin Tiên Hoàng tử vong, đưa Hài Tử về Đế Sơn bế quan ổn định đại cục","chuong":"@c1898"},{"text":"Đích thân tới Thái Cổ Thần Cảnh thăm dò, phối hợp Hải Tử ước đoán thời hạn gần 500 năm","chuong":"@c1929"},{"text":"Chấn động trước Vương Lâm thành Đại Thiên Tôn, phân tích mặt trời ba màu hắc-bạch-kim chưa có tiền lệ","chuong":"@c1940"},{"text":"Chủ đạo thần thông nghịch chuyển tại chiến trường, hoài nghi người giao chiến với Cổ Đạo là Vương Lâm","chuong":"@c1954"}]},"vaiTro":"Đại Thiên Tôn tiên tộc — cường giả cao nhất phe tiên tộc tại Đế Sơn","tinhCach":"thâm trầm tính toán, biết dùng thế áp người; kiên nhẫn bế quan áp chế nội hoạn; cẩn trọng che giấu tin tức bất lợi cho đại cục; nội tâm dao động trước biến cố vượt ngoài dự liệu nhưng bề ngoài giữ bình thản","blurb":"Cửu Đế là Đại Thiên Tôn mạnh nhất trong nhóm cường giả tiên tộc trú tại Đế Sơn Tổ Thành, thân mang Trớ Thuật khó áp chế, vừa duy trì tu vi bản thân vừa gánh vác đại cục tiên tộc. Từ việc phong tỏa tin Tiên Hoàng tử vong, đưa Hài Tử bế quan, đích thân thăm dò Thái Cổ Thần Cảnh, đến chủ đạo thần thông nghịch chuyển tại chiến trường — ông tính toán từng bước nhằm ổn định cục diện. Khi Vương Lâm đột phá thành Đại Thiên Tôn với mặt trời ba màu hắc-bạch-kim chưa từng có tiền lệ, Cửu Đế chấn động sâu sắc, và cuối cùng tới Thái Cổ Thần Cảnh ôm quyền hướng Vương Lâm mà không nói lời nào."},{"id":"song-tu-dai-thien-ton","name":"Song Tử Đại Thiên Tôn","mucCt":"gon","trangThai":"song","nguon":["@c1970"],"tabs":{"kinhLich":[{"chuong":"@c1970","importance":"bridge","mucCt":"gon","text":"Suy tư rất lâu rồi chọn không tới Thái Cổ Thần Cảnh, ở lại mặt đất tiên tộc để đề phòng.","anchor":"Nàng suy tư rất lâu. cuối cùng lựa chọn bỏ qua. ở lại trên mặt đất tiên tộc để đề phòng."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Được giới thiệu là Đại Thiên Tôn tọa trấn Tử Dương Tông, một trong cửu tông thập bát phái Đông Châu","chuong":"@c1822"},{"text":"Vốn là Thiên Tôn cường đại nhất nhưng sau chuyển thế linh hồn phân liệt thành hai ấu nữ Hàm Hàm và Oa Oa, thực lực suy giảm nghiêm trọng","chuong":"@c1826"},{"text":"Một mình ép lui ba Đại Thiên Tôn — Cửu Đế, Võ Phong, Đạo Nhất — để tuyên bố giữ Vương Lâm","chuong":"@c1865"},{"text":"Trực tiếp giao chiến với Tiên Hoàng trên bầu trời, giữ chân đối phương không cho can dự chiến sự bên dưới","chuong":"@c1883"},{"text":"Sau đại chiến dung hợp thành bản thể, tuyên bố chỉ vì cứu Vương Lâm chứ không can dự kế hoạch của bất kỳ ai","chuong":"@c1892"},{"text":"Hai hồn dung hợp hoàn chỉnh thành một nữ tử, bay tới chiến trường rồi chọn ở lại mặt đất Tiên Tộc đề phòng thay vì vào Thái Cổ Thần Cảnh","chuong":"@c1970"}]},"vaiTro":"Đại Thiên Tôn Tiên Tộc — cường giả bậc nhất Đông Châu, tọa trấn Tử Dương Tông","tinhCach":"uy áp tuyệt đối, một mình ép lui nhiều Đại Thiên Tôn; trọng nghĩa với người mình chọn, chỉ cứu Vương Lâm mà không can dự đại cục; hành sự kín đáo, ẩn thân dưới hình hài hai ấu nữ sau chuyển thế; trầm mặc quả đoán, không để ngoại lực chi phối lập trường","blurb":"Song Tử Đại Thiên Tôn là vị cường đại nhất trong năm Đại Thiên Tôn của Tiên Tộc, tọa trấn Tử Dương Tông thuộc cửu tông thập bát phái Đông Châu. Sau khi chuyển thế gặp biến cố, linh hồn phân liệt thành hai ấu nữ — Hàm Hàm và Oa Oa — khiến thực lực suy giảm nghiêm trọng, nhưng nàng vẫn đủ uy để một mình ép lui ba Đại Thiên Tôn nhằm bảo toàn Vương Lâm, rồi trực tiếp giao chiến với Tiên Hoàng cùng Cửu Đế để giữ chân đối phương. Sau đại chiến, nàng trở về Tử Dương Tông bế quan dung hợp hai hồn, cuối cùng khôi phục bản thể thành một nữ tử hoàn chỉnh và gia nhập chiến trường một lần nữa, nhưng chọn ở"},{"id":"lien-dao-phi","name":"Liên Đạo Phi","mucCt":"gon","trangThai":"song","nguon":["@c1970"],"tabs":{"kinhLich":[{"chuong":"@c1970","importance":"bridge","mucCt":"gon","text":"Vừa trở thành Tiên Hoàng, không tới Thái Cổ Thần Cảnh, ở lại mặt đất tiên tộc.","anchor":"Còn Liên Đạo Phi vừa trở thành Tiên Hoàng thì cũng không tới."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Bị Phàn San Mộng dụ tới Thất Đạo Tông, một mình đánh tứ đại chiến tướng, bị thiên đạo nuốt nhưng nhờ bất diệt thể vẫn sống","chuong":"@c1600"},{"text":"Được Vương Lâm triệu hồi ra trận, chống đỡ lực hủy diệt ba trăm giới sụp đổ khiến suy yếu quá nửa","chuong":"@c1671"},{"text":"Tái xuất trong trạng thái mất ký ức cũ, lúc nhận lúc không nhận ra Vương Lâm","chuong":"@c1874"},{"text":"Bị Tiên Hoàng lợi dụng huyết mạch phản tổ biến thành mắt trái Tiên Tổ, là đường lui để đoạt xá, nhưng cuối cùng thoát khỏi","chuong":"@c1893"},{"text":"Được truyền thừa bí thuật đạt cảnh giới Đại Thiên Tôn","chuong":"@c1897"},{"text":"Trở thành Tiên Hoàng mới, ở lại mặt đất tiên tộc","chuong":"@c1970"}]},"vaiTro":"Cường giả bí ẩn mang bất diệt thể — bằng hữu chí thân và ân nhân của Vương Lâm","tinhCach":"Điên cuồng ngạo mạn, dám một mình chiến quần hùng; dễ bị mỹ nhân dụ dẫn; trọng tình nghĩa, coi Vương Lâm như tri kỷ; ý chí kiên cường, nhờ bất diệt thể mà bất tử","blurb":"Liên Đạo Phi là cường giả bí ẩn sở hữu bất diệt thể và huyết mạch phản tổ của tiên tộc, đồng thời là bằng hữu chí thân và ân nhân lớn của Vương Lâm. Hắn từng bị Phàn San Mộng dụ tới Thất Đạo Tông, một mình giao chiến tứ đại chiến tướng rồi bị thiên đạo nuốt mà không diệt vong, về sau bị Tiên Hoàng lợi dụng huyết mạch phản tổ biến thành mắt trái Tiên Tổ, nhưng cuối cùng thoát khỏi đoạt xá, được truyền thừa bí thuật đạt Đại Thiên Tôn rồi trở thành Tiên Hoàng. Tính tới chương gần nhất, hắn vừa trở thành Tiên Hoàng mới, ở lại mặt đất tiên tộc."},{"id":"co-dao","name":"Cổ Đạo","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Cổ tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại Thiên Tôn","trangThai":"song","blurb":"Cổ Đạo là nhân vật bí ẩn thuộc Cổ tộc, sở hữu thực lực ở tầng Đại Thiên Tôn, sức mạnh thâm sâu khó lường. Hắn từng bước vào Thái Cổ Thần Cảnh với mục đích riêng liên quan đến Cổ Tổ – Tiên Tổ, sau đó trở về Tiên Cương thông qua dòng xoáy do Vương Lâm mở ra.","vaiTro":"Cao nhân bí ẩn bên Cổ tộc, thực lực cấp Đại Thiên Tôn","tinhCach":"Trầm mặc, ít nói; hành động có tính toán sâu xa, xuất hiện đúng thời điểm","tabs":{"diem":[{"text":"Tiết lộ bí mật về Cổ Tổ – Tiên Tổ, bước vào Thái Cổ Thần Cảnh với mục đích làm thê tử sống lại; tuyên bố người dưới Đạp Thiên không thể vào nơi này","chuong":"@c1972"},{"text":"Sau khi Thái Cổ Thần Cảnh bị thu, đứng ở cuối hư vô và trở về Tiên Cương qua dòng xoáy do Vương Lâm mở","chuong":"@c1976"}],"kinhLich":[{"chuong":"@c1972","importance":"major","mucCt":"ky","tieuDe":"Tiết lộ bí ẩn Cổ Tổ – Tiên Tổ, bước vào Thái Cổ Thần Cảnh","text":"Tuyên bố người dưới Đạp Thiên không thể bước vào Thái Cổ Thần Cảnh. Tiết lộ mục đích vào là để làm thê tử sống lại. Giải thích Cổ Tổ và Tiên Tổ phát hiện bí ẩn không thể tin, cuối cùng tử vong để tìm chân tướng, và nếu tìm được đáp án hắn có thể rời khỏi mặt đất Cổ Tộc. Lao vào đại môn Thái Cổ Thần Cảnh trước Vương Lâm.","anchor":"Ta bước vào Thái Cổ Thần Cảnh này là vì làm cho thê tử sống lại"},{"chuong":"@c1976","importance":"normal","mucCt":"vua","tieuDe":"Trở về Tiên Cương qua dòng xoáy","text":"Đứng ở cuối hư vô sau khi Thái Cổ Thần Cảnh bị thu, ngơ ngác hỏi đây có phải đáp án. Vương Lâm mở dòng xoáy tới Tiên Cương đại lục, Cổ Đạo vái một cái rồi đi vào biến mất.","anchor":"Đây là đáp án sao"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đồng hành bên Cổ tộc","ghiChu":"Ngồi bên nhau chờ Thái Cổ Thần Cảnh mở"},{"ten":"Huyền La","tag":"dong-minh","quanHe":"Đại Thiên Tôn Cổ tộc dưới quyền","ghiChu":"Ra lệnh cho ở lại"}],"tuiDo":{}},"nguon":["@c1971","@c1972","@c1976"]},{"id":"dong-mai","name":"Đông Mai","cn":"冬梅","aliases":[],"gioiTinh":"nữ","theLuc":[{"ten":"Thủy cổ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Nữ tử áo trắng ở Hắc Thạch Thành thuộc Thủy Cổ Nhất Mạch, bạn từ nhỏ của Tống Trí. Có cổ mạch, có thể tu hành, mang nỗi buồn giấu kín liên quan tới Vương Lâm.","vaiTro":"Nữ tử nghi là Lý Thiến Mai chuyển thế, có cổ mạch, ở Hắc Thạch Thành","tinhCach":"Buồn bã giấu kín; gắng cười che nỗi đau; hay khóc một mình nhìn bầu trời","tabs":{"diem":[{"text":"Mang nỗi buồn giấu kín, nhiều lần khóc một mình nhìn bầu trời, vẻ mặt ảm đạm khi nghe về Vương Lâm và Lý Mộ Uyển","chuong":"@c1972"},{"text":"Có cổ mạch, có thể tu hành — được Tống Trí dặn chăm sóc bản thân","chuong":"@c1972"},{"text":"Tống Trí thầm nghĩ Đông Mai có thể là Lý Thiến Mai chuyển thế","chuong":"@c1972"},{"text":"Có cổ mạch, có thể tu hành, sống tại Hắc Thạch Thành cùng bà lão Tống Trí","chuong":"@c1972"},{"text":"Bị Tống Trí thầm nghĩ là Lý Thiến Mai chuyển thế — luôn ảm đạm khi nghe về Vương Lâm","chuong":"@c1972"},{"text":"Có cổ mạch, có thể tu hành nhưng chưa bước vào con đường tu luyện","chuong":"@c1972"},{"text":"Có cổ mạch, có thể tu hành, khác với Tống Trí chỉ là phàm nhân.","chuong":"@c1972"},{"text":"Bị Tống Trí nghi ngờ là Lý Thiến Mai chuyển thế vì vẻ buồn bã khi nghe chuyện Vương Lâm.","chuong":"@c1972"}],"kinhLich":[{"chuong":"@c1972","importance":"normal","mucCt":"ky","tieuDe":"Ở bên Tống Trí lúc lâm chung","text":"Đông Mai ở bên cạnh bà lão Tống Trí tại Hắc Thạch Thành khi bà sắp qua đời. Tống Trí nhắc lại nhiều lần thấy Đông Mai khóc một mình nhìn trời, vẻ mặt buồn bã khi nghe chuyện Vương Lâm và Lý Mộ Uyển. Trước khi nhắm mắt, Tống Trí tự hỏi liệu Đông Mai có phải Lý Thiến Mai chuyển thế.","anchor":"Lý Thiến Mai chuyển thế và Đông Mai là một người sao"}],"tuViMoc":[{"chuong":"@c1972","canhGioi":"Phàm nhân","text":"Có cổ mạch nhưng chưa tu hành, là tộc nhân tầm thường ở Hắc Thạch Thành","importance":"minor"}],"nhanMach":[{"ten":"Tống Trí","tag":"ban-be","quanHe":"Bạn từ nhỏ, bà lão dặn dò Đông Mai trước khi qua đời","ghiChu":"Tống Trí sắp đi gặp Thưởng Di"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đông Mai buồn bã khi nghe về Vương Lâm, nghi là mang ký ức kiếp trước","ghiChu":"Có thể là Lý Thiến Mai chuyển thế"},{"ten":"Lý Mộ Uyển","tag":"khac","quanHe":"Đông Mai vẻ mặt ảm đạm khi nghe chuyện Vương Lâm và Lý Mộ Uyển","ghiChu":""},{"ten":"Lý Thiến Mai","tag":"khac","quanHe":"Nghi là kiếp trước","ghiChu":"Tống Trí thầm nghĩ Đông Mai là Lý Thiến Mai chuyển thế"},{"ten":"Thưởng Di","tag":"khac","quanHe":"Người quen qua Tống Trí","ghiChu":"Tống Trí nói sắp đi gặp Thưởng Di"},{"ten":"Tống Trí","tag":"khac","quanHe":"Người chăm sóc, bà lão phàm nhân sống cùng tại Hắc Thạch Thành","ghiChu":"Tống Trí qua đời trước mặt Đông Mai"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1972"]},{"id":"tong-tri","name":"Tống Trí","cn":"宋芷","aliases":[],"gioiTinh":"nữ","theLuc":[{"ten":"Thủy cổ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân","trangThai":"tu-vong","blurb":"Tống Trí là nữ tử xuất thân từ Thủy Cổ nhất mạch, người đầu tiên sau nhiều trăm năm dung hợp thành công tàn hồn — trong đó có tàn hồn Lý Mộ Uyển. Nàng bị Đạo Cổ hoàng tôn sắc phong hoàng hậu nhằm phục vụ mục đích chính trị, sau đó được Vương Lâm cứu khỏi hoàng cung và đưa đi suốt gần hai năm đường trường về Hắc Thạch Thành, trong quá trình đó tàn hồn Lý Mộ Uyển bên trong nàng dần được tách ra. Nàng sống yên ổn tại Hắc Thạch Thành hơn trăm năm dưới sự bảo vệ ngầm của các cường giả mà bản thân không hề hay biết, cuối cùng qua đời tại đây khi tuổi thọ phàm nhân năm trăm năm đã tới cực hạn.","vaiTro":"Nữ tử Thủy Cổ nhất mạch dung hợp tàn hồn, bị lập làm hoàng hậu Đạo Cổ","tinhCach":"tĩnh tại, cam chịu; mê man giữa bản ngã và ký ức tàn hồn; không hay biết thế sự xung quanh","tabs":{"diem":[{"text":"Là nữ tử Thủy Cổ nhất mạch đầu tiên sau nhiều trăm năm dung hợp thành công tàn hồn, bao gồm tàn hồn Lý Mộ Uyển","chuong":"@c1910"},{"text":"Tỉnh dậy trong hoàng cung Đạo Cổ sau chuỗi mộng ký ức hỗn loạn từ tàn hồn, bị sắc phong hoàng hậu và đưa ra trước đại yến","chuong":"@c1911"},{"text":"Được Vương Lâm mang đi khỏi hoàng cung Đạo Cổ trong trạng thái đang dung nhập tàn hồn Lý Mộ Uyển","chuong":"@c1922"},{"text":"Theo Vương Lâm đi suốt gần hai năm về Hắc Thạch Thành, tàn hồn Lý Mộ Uyển trong người dần được tách ra","chuong":"@c1929"},{"text":"Sống yên ổn hơn trăm năm tại Hắc Thạch Thành dưới sự bảo vệ ngầm của nhiều cường giả ẩn thế mà bản thân không hề hay biết","chuong":"@c1942"},{"text":"Qua đời tại Hắc Thạch Thành khi tuổi thọ phàm nhân năm trăm năm đã tới cực hạn, dặn dò Đông Mai trước lúc lâm chung","chuong":"@c1972"}],"kinhLich":[{"chuong":"@c1972","importance":"major","mucCt":"ky","tieuDe":"Qua đời tại Hắc Thạch Thành, nghi Đông Mai là Lý Thiến Mai chuyển thế","text":"Bà lão phàm nhân tại Hắc Thạch Thành, tuổi thọ 500 năm đã tới cực hạn, nằm trên giường sắp chết. Dặn dò Đông Mai chăm sóc bản thân, nhớ lại chuyện Vương Lâm kể về Lý Mộ Uyển và Lý Thiến Mai 500 năm trước. Tự hỏi Đông Mai có phải Lý Thiến Mai chuyển thế không, rồi nhắm mắt qua đời.","anchor":"Lý Thiến Mai chuyển thế và Đông Mai là một người sao"}],"tuViMoc":[],"nhanMach":[{"ten":"Đông Mai","tag":"ban-be","quanHe":"Bạn từ nhỏ, dặn dò trước khi qua đời","ghiChu":""},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Vương Lâm tiễn Tống Trí về năm trăm năm trước, kể chuyện Lý Mộ Uyển và nhắc tới Lý Thiến Mai","ghiChu":""},{"ten":"Thưởng Di","tag":"khac","quanHe":"Người mà Tống Trí nói sắp đi gặp (đã chết trước đó)","ghiChu":""},{"ten":"Lý Mộ Uyển","tag":"khac","quanHe":"Được Vương Lâm kể về","ghiChu":"Vương Lâm kể chuyện Lý Mộ Uyển cho Tống Trí nghe"},{"ten":"Lý Thiến Mai","tag":"khac","quanHe":"Nghi là kiếp trước của Đông Mai","ghiChu":"Thầm nghĩ Đông Mai là Lý Thiến Mai chuyển thế"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người quen","ghiChu":"Năm trăm năm trước được Vương Lâm tiễn về, nghe hắn kể chuyện Lý Mộ Uyển và nhắc tới Lý Thiến Mai"},{"ten":"Đông Mai","tag":"khac","quanHe":"Nữ tử sống cùng, được Tống Trí chăm sóc và dặn dò trước lúc chết"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1972"]},{"id":"luc-mac","name":"Lục Mặc","tabs":{"kinhLich":[{"chuong":"@c1975","importance":"normal","mucCt":"gon","tieuDe":"Mộng đạo khiến Thiên Vận Tử sụp đổ","text":"Được nhắc đến: mọi chuyện không phải giấc mộng của Vương Lâm mà là mộng đạo của Lục Mặc, khiến toàn bộ kế hoạch đoạt xá của Thiên Vận Tử sụp đổ.","anchor":"mà là mộng đạo của Lục Mặc kia"},{"chuong":"@c1976","importance":"major","mucCt":"ky","tieuDe":"Xóa linh trí, dung hợp trở lại thân Vương Lâm","text":"Xuất hiện bên ngoài Tiên Cương đại lục, tràn đầy khí tức sát lục và hủy diệt, hình dạng giống hệt Vương Lâm. Nhìn Lý Mộ Uyển ánh mắt nhu hòa. Chặt một sợi tóc đen — tóc hóa trắng. Chủ động xóa linh trí bản thân, hóa hắc khí dung nhập thân Vương Lâm. Vương Lâm cảm ngộ hắn đã trải vô số lần luân hồi nên chọn dung hợp.","anchor":"nhắm mắt lại, hóa thành một vùng hắc khí, xóa đi linh trí của bản thân đung nhập vào trong thân thể Vương Lâm"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Ngưng thành từ hắc khí, hiện thân trong không gian trận pháp trước mặt Đạo Cổ quốc sư","chuong":"@c1926"},{"text":"Chất vấn Đạo Cổ quốc sư, nhận ra đối phương ở không gian khác với trận pháp","chuong":"@c1927"},{"text":"Dung hợp với bản thể Vương Lâm, từ hình chiếu hư ảo trở thành tồn tại chân thật","chuong":"@c1928"},{"text":"Năm chân thân dung hợp, Hình Phạt Lục Mặc ra đời, phát ra khí tức hủy diệt","chuong":"@c1934"},{"text":"Mộng đạo của Lục Mặc khiến Thiên Vận Tử sụp đổ, mọi chuyện không phải giấc mộng của Vương Lâm","chuong":"@c1975"},{"text":"Bị xóa linh trí, dung hợp trở lại thân Vương Lâm bên ngoài Tiên Cương đại lục","chuong":"@c1976"}]},"nguon":["@c1975","@c1976"],"trangThai":"tu-vong","gioiTinh":"nam","aliases":["Lục Mặc"],"vaiTro":"Sát lục chân thân tóc đen của Vương Lâm — phân thân mang khí tức hủy diệt","tinhCach":"Lạnh lùng, quyết đoán; sắc bén trong quan sát và phán đoán; mang bản chất hủy diệt thuần túy","blurb":"Lục Mặc là sát lục chân thân tóc đen do Vương Lâm tạo ra, ngưng tụ từ hắc khí sau khi bản thể phá lỗ hổng trên tấm lưới không gian rồi xâm nhập trận pháp. Hắn trực tiếp chất vấn Đạo Cổ quốc sư, dung hợp với bản thể từ hình chiếu hư ảo trở thành tồn tại chân thật, và sau khi năm chân thân dung hợp, tái xuất dưới danh xưng Hình Phạt Lục Mặc với khí tức hủy diệt. Cuối cùng hắn bị xóa linh trí và dung hợp trở lại thân Vương Lâm bên ngoài Tiên Cương đại lục."},{"id":"thien-van-tu-ao-xam","name":"Thiên Vận Tử áo xám","gioiTinh":"nam","trangThai":"song","canhGioiCaoNhat":"Đạp Thiên Cảnh (người thứ nhất trong Nghịch Trần Giới)","tabs":{"kinhLich":[{"chuong":"@c1976","importance":"major","mucCt":"ky","tieuDe":"Hé lộ thân phận, đánh nốt ván cờ với Vương Lâm","text":"Thực chất là đạo thần niệm người bảo vệ la bàn chân chính lưu lại trên khí linh Thiên Vận Tử. Tự xưng là người đầu tiên đạt Đạp Thiên Cảnh trong Nghịch Trần Giới, xác nhận Vương Lâm là người thứ hai. Giải thích Thất Thải Giới do phân thân Vương Lâm sáng tạo, khí linh mượn lợi dụng. Giải thích hàm nghĩa Phụng Chí Tu Chân — chữ chân là chân ngã trong luân hồi. Tiết lộ đạp thiên bước thứ tư là đỉnh phong Nghịch Trần Giới, vũ trụ còn bước năm bước sáu, bàn cờ có trước khi hắn tới. Vương Lâm đặt Thiên Nghịch châu làm quân trắng, bàn cờ hiện khuôn mặt nửa đen nửa trắng, hắn xác nhận hiểu rõ.","anchor":"Ta không có tên. Nếu như ta là người đầu tiên của Nghịch Trần Giới này đạt tới Đạp Thiên Cảnh thì ngươi chính là người thứ hai."}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Cùng là người bảo vệ, đánh ván cờ tàn cuộc","ghiChu":"Vương Lâm là người thứ hai đạt Đạp Thiên Cảnh"},{"ten":"Lăng Thiên Hậu","tag":"khac","quanHe":"Đứng phía sau như người hầu trong đào viên"}],"diem":[{"text":"Lần đầu tiếp cận Vương Lâm tại Thiên Vận Tông, tiết lộ được đưa tới vì Sát Lục Tiên quyết và mời truyền pháp","chuong":"@c0474"},{"text":"Bị Tàn Dạ dồn tới chỉ còn tàn niệm, liều mạng hóa huyết kiếm từ căn nguyên khí Sát Lục rồi liên tiếp mở phong ấn chiến đấu","chuong":"@c1004"},{"text":"Đoạt máu thiên đạo từ Thanh Long Thánh Hoàng bằng cách nương lực tự bạo của ba phân thân rồi tẩu thoát","chuong":"@c1044"},{"text":"Bổn tôn Thiên Vận Tử tự sát để nuôi phân hồn áo xám, cho gần ba nghìn phân thân tự hủy hội tụ hồn phách nhằm chiếm cứ phân thân Vương Lâm","chuong":"@c1624"},{"text":"Hoàn thành lần thức tỉnh thứ chín mươi chín, thi triển Thiên đạo nhất thể nhưng bị U Minh Thú nuốt sạch","chuong":"@c1629"},{"text":"Hé lộ thực chất là đạo thần niệm của người bảo vệ la bàn chân chính lưu lại trên khí linh Thiên Vận Tử, đánh nốt ván cờ với Vương Lâm tại Cổ Đạo Sơn","chuong":"@c1976"}]},"nguon":["@c1976"],"vaiTro":"Phân thân áo xám của Thiên Vận Tử — nắm giữ Sát Lục Tiên quyết, thực chất mang thần niệm người bảo vệ la bàn","tinhCach":"Bí ẩn và tự chủ cao, hành xử tách biệt khỏi bổn tôn đến mức liếc lạnh khi bị triệu hồi; hiếu chiến nhưng tính toán, chỉ mở phong ấn khi bị dồn tới tuyệt cảnh; quyết liệt liều mạng, sẵn sàng hóa tàn niệm để tấn công; lạnh lùng chủ động, nhiều lần thăm dò và truy kích Vương Lâm xuyên suốt tứ đại tinh ","blurb":"Thiên Vận Tử áo xám là phân thân đặc biệt của Thiên Vận Tử, sở hữu Sát Lục Tiên quyết và sát khí cực mạnh, hoạt động với mức độ tự chủ cao — thậm chí từng liếc lạnh bổn tôn khi bị triệu hồi dung nhập. Hắn nhiều lần truy kích Vương Lâm xuyên suốt các biến cố tại Tiên Phủ Đông Hải và tứ đại tinh vực, bị thần thông Tàn Dạ dồn tới mức chỉ còn tàn niệm nhưng vẫn kiên cường mở liên tiếp các tầng phong ấn chiến đấu; sau đó đoạt máu thiên đạo từ Thanh Long Thánh Hoàng rồi tẩu thoát. Về sau bổn tôn Thiên Vận Tử tự sát để nuôi phân hồn áo xám, phân thân này hoàn thành lần thức tỉnh thứ chín mươi chín tr"},{"id":"lang-thien-hau","name":"Lăng Thiên Hậu","gioiTinh":"nam","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1976","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện trong đào viên bên Thiên Vận Tử áo xám","text":"Đứng phía sau Thiên Vận Tử áo xám trong đào viên, dáng vẻ hơi già nua. Vương Lâm nhận ra nhưng người áo xám nói đúng mà cũng không phải. Lão lắc đầu không nói gì.","anchor":"Dáng vẻ đối phương hơi già nua đi nhưng hắn liếc mắt một cái liền nhận ra người này"}],"diem":[{"text":"Cưỡi Kỳ Lân tiên thú xông vào mảnh vỡ tiên giới tranh kiếm tiên, bị Tiên chỉ đánh vỡ nửa người trên, trọng thương nghiêm trọng","chuong":"@c0299"},{"text":"Dàn mưu mượn hiện tượng thủy triều năm nghìn năm một lần để hút đạo kiếm hồn của nữ quân tiên giới","chuong":"@c0487"},{"text":"Dẫn Đại La Kiếm Tông vây ép Thiên Vận Tông đòi lệnh bài, giao chiến cùng Vương Lâm rồi phong hắn làm trưởng lão khách khanh","chuong":"@c0899"},{"text":"Trong Tiên phủ bị Cổ Ma truy sát, trước ngực mang chưởng ấn đen, phải cầu Vương Lâm liên thủ và tự nhận chưa chắc thắng nếu giao chiến với hắn","chuong":"@c0994"},{"text":"Bị sát khí nữ tử mờ ảo áp chế vượt cả Thiên Vận Tử, thân rơi gần biển máu, được bổn tôn Thiên Vận Tử cứu thoát","chuong":"@c0965"},{"text":"Xuất hiện trong đào viên phía sau Thiên Vận Tử áo xám, dáng vẻ già nua hơn xưa","chuong":"@c1976"}]},"nguon":["@c1976"],"vaiTro":"Phụ — Kiếm Tôn Đại La Kiếm Tông, đại năng Anh Biến kỳ trên Thiên Vận tinh","tinhCach":"Ngạo mạn, không nể mặt ngay cả Thiên Vận Tử; quyết đoán liều lĩnh khi tranh đoạt bảo vật tiên giới; nhiều mưu tính, ấp ủ kế hoạch dài hạn nhắm tới kiếm hồn nữ quân tiên giới; hộ đoản, nổi tiếng bao che đệ tử và dễ nổi giận khi môn nhân bị tổn hại","blurb":"Lăng Thiên Hậu là Kiếm Tôn của Đại La Kiếm Tông, tu vi Anh Biến kỳ, được xem là nhân vật số một số hai trên Thiên Vận tinh, luyện thành kiếm nguyên thần từ tứ tiểu thiên địa và cưỡi Hỏa Hồng Kỳ Lân ra trận. Lão từng xông vào mảnh vỡ tiên giới tranh Vũ Chi Tiên Kiếm và bị Tiên chỉ trọng thương, sau đó dàn mưu mượn thủy triều năm nghìn năm để thu phục kiếm hồn, vây ép Thiên Vận Tông đòi lệnh bài, phong Vương Lâm làm trưởng lão khách khanh rồi cùng liên quân thâm nhập Tiên phủ. Trong cuộc khám phá Tiên phủ, lão nhiều lần rơi vào cảnh nguy nan — bị Cổ Ma truy sát, bị sát khí nữ tử mờ ảo áp chế, ph"},{"id":"nu-tu-bach-y-hac-thach-thanh","name":"Nữ tử bạch y (Hắc Thạch Thành)","gioiTinh":"nu","trangThai":"song","blurb":"Nữ tử bạch y bí ẩn xuất hiện cuối chương tại Hắc Thạch Thành, đưa lưng về phía ánh đèn vạn nhà, ngẩng đầu nhìn cầu vồng Vương Lâm bay xa với khóe mắt ngấn lệ, thì thầm về tiền kiếp cá và chim. Bỗng nhiên quay đầu thấy thân ảnh mỉm cười.","vaiTro":"Nhân vật bí ẩn xuất hiện ở đoạn kết","tinhCach":"Đa cảm, sâu lắng","tabs":{"diem":[{"text":"Thì thầm về tiền kiếp cá và chim, khóe mắt ngấn lệ khi nhìn cầu vồng bay xa, rồi bỗng nhiên quay đầu thấy thân ảnh mỉm cười trong ánh đèn.","chuong":"@c1976"},{"text":"Đưa lưng về phía ánh đèn vạn nhà, khóe mắt ngấn lệ nhìn cầu vồng bay xa, thì thầm về tiền kiếp cá và chim.","chuong":"@c1976"},{"text":"Xuất hiện ở cảnh cuối cùng của toàn bộ truyện, bỗng nhiên quay đầu thấy thân ảnh mỉm cười trong ánh đèn — tạo dư vị kết thúc mở.","chuong":"@c1976"}],"kinhLich":[{"chuong":"@c1976","importance":"normal","mucCt":"ky","tieuDe":"Bỗng nhiên quay đầu trong ánh đèn Hắc Thạch Thành","text":"Tại Hắc Thạch Thành dưới chân núi, nàng đưa lưng về phía ánh đèn vạn nhà, ngẩng đầu nhìn cầu vồng Vương Lâm bay xa dần, khóe mắt ngấn lệ, thì thầm về tiền kiếp cá và chim. Phía sau nàng bỗng vang lên giọng nói nhu hòa nói đời này không phải cá và chim. Nàng chấn động, bỗng nhiên quay đầu thấy trong ánh đèn có một thân ảnh mỉm cười nhìn mình.","anchor":"Đời trước là một con cá. ở trong nước nhìn cánh chim đang bay xa dần."}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1976"],"canhGioiCaoNhat":"Không rõ"},{"id":"thanh-nien-hong-bao-xich-hon-giao","name":"Thanh niên hồng bào (Xích Hồn Giáo)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Xích Hồn Giáo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Đệ tử Xích Hồn Giáo, ra tối hậu thư ép tân Tiên giới quy thuận trong năm ngày, đồng thời ép Mộc Băng Mi làm đạo lữ cho “bốn thiếu gia”.","vaiTro":"Đệ tử Xích Hồn Giáo, kẻ truyền lệnh uy hiếp tân Tiên giới","tinhCach":[{"text":"Ngạo mạn, coi thường truyền thuyết Vương Lâm"}],"tabs":{"diem":[{"text":"Ra tối hậu thư ép tân Tiên giới quy thuận, đe dọa phá Chu Tước Tinh và pho tượng Vương Lâm","chuong":"@c1961"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Mộc Băng Mi","tag":"doi-thu","quanHe":"Mục tiêu uy hiếp","ghiChu":"Ép làm đạo lữ cho bốn thiếu gia"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1961"]},{"id":"hong-diep","tabs":{"kinhLich":[],"nhanMach":[],"tuViMoc":[],"tuiDo":{}},"nguon":["@c1961","@c1968"]},{"id":"co-dao-dai-thien-ton","nguon":["@c1970"],"tabs":{"kinhLich":[{"chuong":"@c1970","importance":"bridge","mucCt":"gon","text":"Được nhắc là trước đây bị coi là cường giả đệ nhất nhưng thực tế Vương Lâm mới là, ba năm trước Tống Thiên và Cực Cổ Đại Thiên Tôn đã tới Cổ Đạo Sơn xác nhận.","anchor":"Ba năm trước bọn họ đã biết cường giả đệ nhất trên Tiên Cương đại lục không phải là cổ Đạo Đại Thiên Tôn mà là người tên Vương Lâm trước mắt này."}],"diem":[{"text":"Được công nhận là đệ nhất nhân Cửu Dương Tiên Cương, từng giết Đại Thiên Tôn trong đại chiến, khiến Tiên Tộc kiêng dè không dám tùy tiện tiến công Cổ Tộc","chuong":"@c1866"},{"text":"Là chỗ dựa then chốt giúp hoàng quyền Đạo Cổ áp chế các Đại Thiên Tôn khác trong tộc, từng truyền khẩu dụ thừa nhận quyền kế vị hoàng hậu Diệp Vi","chuong":"@c1922"},{"text":"Dùng ý chí đặt thử thách một ngàn một trăm mười bậc trên Cổ Đạo Sơn để thử Vương Lâm, đồng thời giữ lời hóa bàn tay đen như Ngũ Chỉ Sơn xuống núi trấn áp lực lượng Tiên Tộc","chuong":"@c1914"},{"text":"Lộ danh tính chính là Cổ Tổ khi sương mù tan hoàn toàn: thân gầy, thanh bào, tay phải cụt, tóc xám, tướng mạo giống hệt Cổ Tổ; thi triển Cổ Hóa Thiên Địa trong trận chiến đỉnh cao với Vương Lâm","chuong":"@c1952"},{"text":"Thi triển thức Đạp Thiên độc sáng nhưng bại trước Cửu Khúc Tam Tướng của Vương Lâm, bị đánh phun máu lảo đảo lui hơn trăm trượng","chuong":"@c1953"},{"text":"Thừa nhận bại trận, Đạp Thiên Thuật bị Vương Lâm một chỉ phá sụp hoàn toàn; chủ động đặt ước định ba trăm năm với Vương Lâm","chuong":"@c1954"}]},"vaiTro":"Đệ nhất cường giả Cổ Tộc — lão tổ trấn giữ hoàng quyền Đạo Cổ, chính thể Cổ Tổ","tinhCach":"Uy nghiêm áp đảo, lấy sức mạnh tuyệt đối làm lẽ trị tộc; thận trọng quan sát, không vội hành động khi chưa thấu triệt đối phương; trọng lời hứa, nói xuống núi thì xuống núi; biết tiến thoái, thừa nhận bại trận và chủ động đặt ước định","blurb":"Cổ Đạo Đại Thiên Tôn là đệ nhất nhân trong Cửu Dương Tiên Cương, cư ngụ trên đỉnh Cổ Đạo Sơn, được xưng là lão tổ Cổ Tộc và bậc tiền bối cùng thời Cổ Tổ — thực chất chính là Cổ Tổ bản thân. Uy thế lịch sử từng giết Đại Thiên Tôn trong đại chiến khiến Tiên Tộc dù chiếm ưu thế số lượng vẫn không dám tùy tiện tiến công Cổ Tộc; hắn là chỗ dựa then chốt giúp hoàng quyền Đạo Cổ nhất mạch áp chế các thế lực trong tộc, từng truyền khẩu dụ thừa nhận quyền kế vị hoàng hậu Diệp Vi. Sau khi trực tiếp giao phong với Vương Lâm, hắn lộ dung mạo thật và danh tính Cổ Tổ, thi triển Cổ Hóa Thiên Địa cùng thức Đạ"},{"id":"thien-van-tu-kia","nguon":["@c1973"],"tabs":{"kinhLich":[{"chuong":"@c1973","importance":"major","mucCt":"ky","tieuDe":"Phát động La Bàn Định Giới — bị Vương Lâm phủ nhận","text":"Ngồi đợi Vương Lâm trên đỉnh núi trung tâm La Bàn Định Giới, toàn thân ánh sáng bảy màu. Vung tay triệu hắc khí từ khe nứt ngưng tụ thành thân ảnh khổng lồ chống đỡ thiên địa. Tự xưng là người bảo vệ La Bàn Định Giới năm xưa bị Vương Lâm cướp, xác nhận Mặc Trí là đệ tử. Tiết lộ Tiên Cương Đại Lục chỉ là giấc mộng của Vương Lâm, vũ trụ có tứ đại Giới, Thái Cổ Thần Cảnh chính là La Bàn Định Giới — Không Diệt Bảo duy nhất của Nghịch Trần Giới. Tuyên bố đây là nơi duy nhất có thể nuốt dung hợp Vương Lâm, nhưng bất an khi ý thức Vương Lâm hoàn toàn bình tĩnh không vặn vẹo. Bị câu nói về người còn thiếu khiến chấn động mạnh.","anchor":"Lão phu là người bảo vệ La Bàn Định Giới, năm đó ngươi đã cướp vật này từ trong tay ta"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Được Thiên Vận Tử áo xám nhắc tới trong đối thoại với Lăng Thiên Hậu về chuyện không xen vào","chuong":"@c0914"},{"text":"Hiện thân bằng ánh sáng bảy màu để đối chất với Lăng Thiên Hậu, khẳng định chuyện thuộc phạm vi Thiên Vận Tử","chuong":"@c0915"},{"text":"Phát động La Bàn Định Giới trên đỉnh núi trung tâm, toàn thân ánh sáng bảy màu, nhưng bị Vương Lâm phủ nhận","chuong":"@c1973"}]},"vaiTro":"Thực thể bí ẩn mang ánh sáng bảy màu, liên quan đến La Bàn Định Giới","tinhCach":"Chủ động đối chất, không né tránh xung đột; tự tin vào quyền hạn của mình","blurb":"Thiên Vận Tử bảy màu là một thực thể được phân biệt với Thiên Vận Tử áo xám, hiện thân bằng ánh sáng bảy màu để đối chất với Lăng Thiên Hậu về chuyện thuộc phạm vi của Thiên Vận Tử. Về sau ngồi đợi Vương Lâm trên đỉnh núi trung tâm La Bàn Định Giới và phát động cơ chế này, nhưng bị Vương Lâm phủ nhận."},{"id":"moc-ngung","tabs":{"kinhLich":[{"chuong":"@c1961","importance":"normal","mucCt":"vua","tieuDe":"Bị Xích Hồn Giáo uy hiếp ép làm đạo lữ","text":"Năm xưa chọn ở lại tân Tiên giới chờ Vương Lâm trở về. Hiện bị thanh niên hồng bào Xích Hồn Giáo ra tối hậu thư: hai ngày nữa phải trở thành đạo lữ của “bốn thiếu gia”, nếu không sẽ phá hủy Chu Tước Tinh và pho tượng Vương Lâm.","anchor":"Mộc Băng Mi. lựa chọn của ngươi cũng chỉ còn hai ngày"},{"chuong":"@c1966","importance":"normal","mucCt":"vua","tieuDe":"Theo Vương Lâm rời Tiên giới","text":"Ngày chiến đấu thứ hai, được Vương Lâm mang theo cùng Thập Tam và Hứa Lập Quốc rời khỏi Tiên giới.","anchor":"Vương Lâm mang theo Mộc Băng Mi và đám người Thập Tam"}],"diem":[{"text":"Tu luyện hấp thụ Lam Viêm Ma hỏa trong huyệt động cột đá; tiếp đón Vương Lâm khi y đến Thi Âm tông","chuong":"@c0080"},{"text":"Chứng kiến Vương Lâm được Dạ Tự Tại chính thức nhận làm đại đệ tử thứ hai","chuong":"@c0081"},{"text":"Dẫn Vương Lâm xuống Địa Âm chi địa để tu luyện Hoàng Tuyền Thăng Khiếu","chuong":"@c0084"},{"text":"Năm xưa chọn ở lại tân Tiên giới chờ Vương Lâm; bị thanh niên hồng bào Xích Hồn Giáo ra tối hậu thư uy hiếp ép làm đạo lữ","chuong":"@c1961"},{"text":"Được Vương Lâm mang theo cùng Thập Tam và Hứa Lập Quốc rời khỏi Tiên giới","chuong":"@c1966"}]},"nguon":["@c1961","@c1966"],"cn":"木凝","aliases":["Mộc Băng Mi"],"vaiTro":"Chấp sự trưởng lão Thi Âm tông Triệu quốc, tu vi Trúc Cơ trung kỳ","tinhCach":"Thực dụng, biết nhìn thực lực; cung kính với bề trên, tận tụy phụng sự cấp trên trong tông; trung thành, chọn ở lại chờ Vương Lâm dù trải qua thời gian dài","blurb":"Mộc Ngung là chấp sự trưởng lão của Thi Âm tông tại Triệu quốc, tu vi Trúc Cơ trung kỳ, thường ngày tu luyện bằng cách hấp thụ khí xanh biếc từ Lam Viêm Ma hỏa trong huyệt động cột đá. Bà là người tiếp đón Vương Lâm khi y lần đầu đến tông, sau đó liên lạc Dạ Tự Tại lão tổ, dẫn Vương Lâm xuống Địa Âm chi địa tu luyện, và chứng kiến Vương Lâm được nhận làm đại đệ tử thứ hai. Về sau, tại tân Tiên giới, Mộc Ngung chọn ở lại chờ Vương Lâm trở về, từng bị Xích Hồn Giáo uy hiếp ép làm đạo lữ, và cuối cùng được Vương Lâm mang theo rời khỏi Tiên giới."},{"id":"nu-tu-trong-buc-tranh","nguon":["@c1966"],"tabs":{"kinhLich":[{"chuong":"@c1966","importance":"normal","mucCt":"gon","tieuDe":"Được giải phong ấn, đưa vào luân hồi","text":"Vương Lâm tìm lại bức tranh phong ấn trong vực sâu Yêu Linh Chỉ Địa, đưa nữ tử ra, giải phong ấn rồi đưa nàng chìm vào luân hồi.","anchor":"tìm được bức tranh mà hẳn phong ấn ở trong vực sâu. đưa nữ từ kia ra. giải phong ấn, đua nàng chìm vào luân hồi"}]}}]};
